  'ATOM_LIST_QUERY':              { min_state: 2, actors: ACTOR_TYPES.PUBLIC,         dispatcher: DISPATCHERS.LOGIC   },

  // ── INTELIGENCIA Y LÓGICA ──
  'INTELLIGENCE_CHAT':            { min_state: 2, actors: ACTOR_TYPES.PUBLIC,         dispatcher: DISPATCHERS.LOGIC   },
