// =============================================================================
// ARTEFACTO: 0_gateway/pulse_router.gs
// CAPA: 0 — Gateway Layer (Interceptor de Pulsos)
// RESPONSABILIDAD: Interceptar side-channels (Boomerang y Webhooks) antes
//         de la autenticación del Gateway.
// =============================================================================

/**
 * Procesa la ignición de pulsos (The Boomerang | ADR-018).
 * @param {GoogleAppsScript.Events.DoPost} e
 * @returns {GoogleAppsScript.Content.TextOutput|null} Response o null si no es un pulso.
 */
function pulse_router_intercept(e) {
  // 1. Detección de Ignición de Pulsos (Boomerang)
  const igniteHeader = e && e.parameter && e.parameter.ignite === 'true' || 
                       e && e.headers && e.headers['X-Indra-Ignite'] === 'true';

  if (igniteHeader) {
    logInfo('[pulse_router] Boomerang detectado. Iniciando Red de Pulsos.');
    try {
      const pulseResult = pulse_service_process_next(); // → pulse_service.gs
      return _buildResponse_(200, { 
        items: [], 
        metadata: { status: 'OK', message: 'Ignición completada.', pulse_executed: !!pulseResult } 
      });
    } catch (err) {
      logError('[pulse_router] Error en ignición del Boomerang.', err);
      return _buildResponse_(500, { items: [], metadata: { status: 'ERROR', error: err.message } });
    }
  }

  // 2. Detección de Webhooks de Soberanía (ADR-018)
  const webhookId = e && e.parameter && e.parameter.webhook_id;
  if (webhookId) {
    logInfo('[pulse_router] Webhook de Soberanía detectado.', { webhookId });
    try {
      const pulseId = trigger_hub_activate(webhookId); // → trigger_hub.gs
      return _buildResponse_(202, { 
        items: [], 
        metadata: { status: 'OK', message: 'Trigger aceptado. Pulso encolado.', pulse_id: pulseId } 
      });
    } catch (err) {
      logError('[pulse_router] Error en activación de Webhook de Soberanía.', err);
      return _buildResponse_(404, { items: [], metadata: { status: 'ERROR', error: err.message } });
    }
  }

  return null; // No es un side-channel, continuar al Gateway normal
}

0_gateway.system_state_manager.gs:
/**
 * =============================================================================
 * ARTEFACTO: 0_gateway/system_state_manager.gs
 * CAPA: 0 — Gateway Layer (Cerebro de Estado)
 * RESPONSABILIDAD: Cálculo determinista del nivel de consciencia/madurez del Core.
 * AXIOMA AX-052-4: El estado es monótonico (solo avanza). 
 * AXIOMA AX-052-5: Función pura — cálculo sin efectos secundarios.
 * =============================================================================
 */

const SYSTEM_STATE = Object.freeze({
  UNINITIALIZED: 0, // El Core no ha detectado a su dueño (Soberanía latente)
  PROVISIONING:  1, // Dueño identificado pero sin infraestructura Ledger
  ACTIVE:        2, // Sistema operativo pleno (Ledger montado)
  FEDERATED:     3  // (Futuro) Multi-core activo con malla relacional
});

const SystemStateManager = (function() {

  /**
   * Determina el estado actual consultando la persistencia de forma aislada.
   * @returns {number} Una de las constantes SYSTEM_STATE.*
   */
  function getState() {
    const store = PropertiesService.getScriptProperties();

    // ── NIVEL 0: SOBERANÍA LATENTE ──
    const ownerUid = store.getProperty('SYS_CORE_OWNER_UID');
    if (!ownerUid) {
      console.warn('[state_manager] Estado SISTÉMICO: 0 (UNINITIALIZED). El Core es huérfano.');
      return SYSTEM_STATE.UNINITIALIZED;
    }

    // ── NIVEL 1: PROVISIÓN PENDIENTE ──
    // El dueño existe pero no ha "firmado el pacto" o el Ledger no ha cristalizado.
    const isBootstrapped = store.getProperty('SYS_IS_BOOTSTRAPPED') === 'true';
    const rootMountId = store.getProperty('SYS_MOUNT_ROOT_ID');

    if (!isBootstrapped || !rootMountId) {
      console.warn('[state_manager] Estado SISTÉMICO: 1 (PROVISIONING). Dueño detectado pero núcleo inactivo.');
      return SYSTEM_STATE.PROVISIONING;
    }

    // ── NIVEL 2: CONSCIENCIA ACTIVA ──
    return SYSTEM_STATE.ACTIVE;
  }

  /**
   * Traduce el código de estado a un string legible para respuestas.
   * @param {number} stateCode 
   * @returns {string}
   */
  function getLabel(stateCode) {
    const labels = {
      0: 'UNINITIALIZED_IDENTITY',
      1: 'PROVISIONING_REQUIRED',
      2: 'CORE_ACTIVE',
      3: 'FEDERATED_MESH'
    };
    return labels[stateCode] || 'UNKNOWN_STATE';
  }

  return {
    getState,
    getLabel,
    STATES: SYSTEM_STATE
  };

})();

0_utils.indra_utils.gs:
/**
 * =============================================================================
 * ARTEFACTO: 0_utils/indra_utils.gs
 * RESPONSABILIDAD: Utilidades compartidas para todo el Core Indra.
 * AXIOMA: Las utilidades no tienen estado y son puras.
 * =============================================================================
 */

/**
 * Convierte un texto en un alias (slug) canónico: minúsculas, sin espacios ni especiales.
 * @param {string} text - Texto a procesar.
 * @returns {string} Slug limpio.
 */
function _system_slugify_(text) {
    if (!text) return '';
    return text
        .toString()
        .toLowerCase()
        .normalize('NFD') // Quitar acentos
        .replace(/[\u0300-\u036f]/g, '')
        .trim()
        .replace(/[^\w\s-]/g, '')
        .replace(/[\s_-]+/g, '_')
        .replace(/^-+|-+$/g, '');
}

/**
 * REALIZA UNA FUSIÓN PROFUNDA DE OBJETOS (ADR-004).
 * @param {Object} target - El objeto base que recibirá los cambios.
 * @param {Object} source - El objeto que trae las actualizaciones.
 * @returns {Object} El objeto target modificado.
 */
function _indra_deepMerge_(target, source) {
  if (!source) return target;
  Object.keys(source).forEach(key => {
    if (source[key] instanceof Object && !Array.isArray(source[key])) {
      if (!target[key]) Object.assign(target, { [key]: {} });
      _indra_deepMerge_(target[key], source[key]);
    } else {
      Object.assign(target, { [key]: source[key] });
    }
  });
  return target;
}

/**
 * Indica si un ítem es una Señal de Prospección (Probe), no un Átomo.
 * @param {Object} item
 * @returns {boolean}
 */
function _isProbeSignal_(item) {
    return item && item.type === 'PROBE';
}

0_utils.indra_watchdog.gs:
/**
 * =============================================================================
 * ARTEFACTO: 0_utils/indra_watchdog.js
 * RESPONSABILIDAD: Vigilancia del tiempo de ejecución y prevención de timeouts.
 * AXIOMA: Fatiga de Proceso (Checkpoint-based).
 * =============================================================================
 */

const Watchdog = (function() {
  let startTime = null;
  const EXECUTION_LIMIT_MS = 25000; // 25s (Límite razonable para una petición web de 30s)

  /**
   * Inicia el cronómetro de la petición actual.
   */
  function start() {
    startTime = Date.now();
    logDebug('[watchdog] Cronómetro de ejecución iniciado.');
  }

  /**
   * Verifica si el proceso está cerca de su límite de fatiga.
   * Un proveedor debería llamar a esto en bucles largos.
   * @returns {boolean} true si el tiempo está por agotarse.
   */
  function isFatigued() {
    if (!startTime) return false;
    const elapsed = Date.now() - startTime;
    return elapsed > EXECUTION_LIMIT_MS;
  }

  /**
   * Obtiene el tiempo restante antes de la interrupción controlada.
   */
  function getRemainingTime() {
    if (!startTime) return 0;
    return Math.max(0, EXECUTION_LIMIT_MS - (Date.now() - startTime));
  }

  /**
   * Obtiene el tiempo transcurrido desde el inicio.
   */
  function getElapsedMs() {
    if (!startTime) return 0;
    return Date.now() - startTime;
  }

  return {
    start: start,
    isFatigued: isFatigued,
    getRemainingTime: getRemainingTime,
    getElapsedMs: getElapsedMs
  };

})();

