// =============================================================================
// ARTEFACTO: 0_utils/infra_oauth2_client.gs
// CAPA: 0 — Utility Layer (Infraestructura Pura)
// RESPONSABILIDAD: Cliente genérico para protocolos OAuth2.
// AXIOMA: No conoce nombres de servicios, solo URLs y parámetros.
// =============================================================================

/**
 * Realiza un Refresh Token Flow genérico.
 * @param {Object} config - Configuración { token_url, client_id, client_secret, refresh_token }
 * @returns {string} El nuevo Access Token.
 */
function OAUTH2_RefreshAccess(config) {
  const { token_url, client_id, client_secret, refresh_token } = config;

  if (!token_url || !client_id || !client_secret || !refresh_token) {
    throw new Error("OAUTH2_HANDLER_ERROR: Parámetros de refresco incompletos.");
  }

  const payload = {
    client_id: client_id,
    client_secret: client_secret,
    refresh_token: refresh_token,
    grant_type: 'refresh_token'
  };

  const options = {
    method: 'post',
    contentType: 'application/x-www-form-urlencoded',
    payload: payload,
    muteHttpExceptions: true
  };

  try {
    const response = UrlFetchApp.fetch(token_url, options);
    const result = JSON.parse(response.getContentText());

    if (response.getResponseCode() !== 200) {
      console.error(`[OAuth2:Fatal] Fallo en refresco: ${response.getContentText()}`);
      throw new Error(`OAUTH2_REFRESH_FAILED: ${result.error_description || result.error || 'Unknown error'}`);
    }

    return result.access_token;
  } catch (e) {
    console.error(`[OAuth2:Exception] Error crítico en transporte OAuth: ${e.message}`);
    throw e;
  }
}

1_logic.document_engine.gs:
/**
 * NATIVE DOCUMENT ENGINE v1.0
 * ----------------------------
 * Misión: Renderizar documentos nativos de Indra (basados en bloques JSON) a PDF.
 * Axioma: Independencia total de Google Docs.
 * Soberanía: Los bloques del DocumentDesigner son la única fuente de la verdad.
 */

const NativeDocumentEngine = {
  
  /**
   * Procesa un átomo de tipo DOCUMENT y devuelve un Blob PDF de Google Apps Script.
   * @param {Object} docAtom - Átomo cargado desde el silo (con payload.blocks).
   * @param {Object} data - Variables de inyección {{key}} (opcional).
   * @returns {Blob} PDF Blob.
   */
  renderToPdf(docAtom, data = {}) {
    const blocks = (docAtom.payload && docAtom.payload.blocks) || [];
    if (blocks.length === 0) {
      throw new Error("[NativeDocumentEngine] El documento no contiene bloques o está vacío.");
    }

    logInfo(`[NativeDocumentEngine] Iniciando renderizado PDF de "${docAtom.handle?.label || docAtom.id}"...`);

    // 1. Ensamble de HTML (Axioma de Visualización)
    const htmlBody = this._renderBlocks(blocks, data);
    
    // 2. Wrap de HTML con estilos base del sistema
    const htmlFull = this._wrapInDocumentTemplate(htmlBody, docAtom);

    // 3. Conversión nativa vía GAS (HtmlService)
    try {
      const htmlOutput = HtmlService.createHtmlOutput(htmlFull);
      const pdfBlob = htmlOutput.getAs(MimeType.PDF);
      
      const fileName = `${docAtom.handle?.label || 'Indra_Doc'}.pdf`;
      pdfBlob.setName(fileName);
      
      logInfo(`[NativeDocumentEngine] PDF generado con éxito: ${fileName} (${pdfBlob.getSize()} bytes)`);
      return pdfBlob;
    } catch (e) {
      logError("[NativeDocumentEngine] Error en generación de PDF:", e);
      throw e;
    }
  },

  /**
   * Recorre recursivamente los bloques del DocumentDesigner y genera HTML.
   * @private
   */
  _renderBlocks(blocks, data) {
    if (!Array.isArray(blocks)) return "";
    
    return blocks.map(block => {
      let childrenContent = "";
      
      // Procesar hijos primero (recursión)
      if (block.children && block.children.length > 0) {
        childrenContent = this._renderBlocks(block.children, data);
      }

      const props = block.props || {};
      const tag = this._mapBlockToTag(block.type);
      const styles = this._mapPropsToCss(props);
      
      // Manejo de Texto
      let blockText = props.text || props.content || "";
      if (typeof blockText === 'string') {
        blockText = this._injectVariables(blockText, data);
      } else if (childrenContent === "" && (!block.children || block.children.length === 0)) {
        // Bloque vacío o tipo especial (Media)
        if (block.type === 'IMAGE' || block.type === 'MEDIA') {
          const media = this._resolveMediaInfo(props, data);
          if (media) {
            return `<img src="${media.url}" alt="${media.alt}" style="${styles}; max-width: 100%; height: auto;">`;
          }
        }
      }

      // Atributos adicionales (clase de salto de página, etc)
      const extraClass = props.pageBreakAfter ? 'class="page-break"' : '';

      return `<${tag} ${extraClass} style="${styles}">${blockText}${childrenContent}</${tag}>`;
    }).join("");
  },

  /**
   * Inyecta variables del payload en el texto: {{nombre}} -> "Juan".
   * Soporta dot notation: {{cliente.nombre}}.
   * @private
   */
  _injectVariables(text, data) {
    if (!text) return "";
    return text.replace(/\{\{([a-zA-Z0-9_\.]+)\}\}/g, (match, key) => {
      // Resolvemos por punto (ej. cliente.nombre)
      const value = key.split('.').reduce((obj, k) => (obj && obj[k] !== undefined) ? obj[k] : undefined, data);
      
      if (value === undefined || value === null) return match; // Dejar el token si no existe el dato

      // Formateo de INDRA_MEDIA como texto (alt o placeholder)
      if (typeof value === 'object' && value.type === 'INDRA_MEDIA') {
        return value.alt || "[RESOURCE:MEDIA]";
      }
      
      return String(value);
    });
  },

  /**
   * Resuelve información de media para inyección visual en el HTML.
   * @private
   */
  _resolveMediaInfo(props, data) {
    let url = props.src || props.url || "";
    let alt = props.alt || "Resource";

    // Si la imagen está linkeada a una variable: {{foto_perfil}}
    if (url.startsWith('{{') && url.endsWith('}}')) {
      const key = url.substring(2, url.length - 2).trim();
      const val = key.split('.').reduce((obj, k) => (obj && obj[k] !== undefined) ? obj[k] : undefined, data);
      
      if (val && typeof val === 'object' && val.type === 'INDRA_MEDIA') {
        url = val.canonical_url;
        alt = val.alt || alt;
      } else if (typeof val === 'string') {
        url = val;
      } else {
        return null; // Variable no resuelta
      }
    }
    
    // Ignorar si no hay URL resultante
    if (!url || url === "" || url.startsWith('{{')) return null;

    return { url, alt };
  },

  /**
   * Mapeo de tipos de bloque Indra -> Tags HTML semánticos.
   * @private
   */
  _mapBlockToTag(type) {
    const map = {
      'PAGE': 'div',
      'SECTION': 'section',
      'COLUMN': 'div',
      'HEADING_1': 'h1',
      'HEADING_2': 'h2',
      'HEADING_3': 'h3',
      'PARAGRAPH': 'p',
      'TEXT': 'span',
      'IMAGE': 'div',
      'MEDIA': 'div',
      'BOX': 'div',
      'SPACER': 'div'
    };
    return map[type] || 'div';
  },

  /**
   * Convierte props de estilo Indra a CSS inline para el motor de PDF.
   * Optimizado para renderizado @media print de GAS.
   * @private
   */
  _mapPropsToCss(props) {
    const styles = [];
    
    // Tipografía
    if (props.fontSize) styles.push(`font-size: ${props.fontSize}px`);
    if (props.color) styles.push(`color: ${props.color}`);
    if (props.textAlign) styles.push(`text-align: ${props.textAlign}`);
    if (props.fontWeight) styles.push(`font-weight: ${props.fontWeight}`);
    if (props.lineHeight) styles.push(`line-height: ${props.lineHeight}`);
    if (props.fontFamily) styles.push(`font-family: ${props.fontFamily}, sans-serif`);
    
    // Box Model
    if (props.padding) styles.push(`padding: ${props.padding}px`);
    if (props.margin) styles.push(`margin: ${props.margin}px`);
    if (props.background) styles.push(`background: ${props.background}`);
    if (props.backgroundColor) styles.push(`background-color: ${props.backgroundColor}`);
    if (props.borderRadius) styles.push(`border-radius: ${props.borderRadius}px`);
    if (props.border) styles.push(`border: ${props.border}`);
    if (props.width) styles.push(`width: ${props.width}${typeof props.width === 'number' ? 'px' : ''}`);
    if (props.height) styles.push(`height: ${props.height}${typeof props.height === 'number' ? 'px' : ''}`);
    
    // Layout (Flex soporte básico en PDF renderer de GAS)
    if (props.display === 'flex') {
      styles.push('display: flex');
      if (props.flexDirection) styles.push(`flex-direction: ${props.flexDirection}`);
      if (props.justifyContent) styles.push(`justify-content: ${props.justifyContent}`);
      if (props.alignItems) styles.push(`align-items: ${props.alignItems}`);
      if (props.gap) styles.push(`gap: ${props.gap}px`);
    }

    return styles.join("; ");
  },

  /**
   * Envuelve el contenido en un esqueleto HTML con fuentes y resets globales.
   * @private
   */
  _wrapInDocumentTemplate(body, docAtom) {
    return `
      <!DOCTYPE html>
      <html>
      <head>
        <meta charset="UTF-8">
        <style>
          @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;700&family=Roboto+Mono&display=swap');
          body { 
            font-family: 'Inter', -apple-system, sans-serif; 
            margin: 0; padding: 40px; 
            color: #333; line-height: 1.5;
            background: white;
          }
          * { box-sizing: border-box; }
          h1, h2, h3 { margin-top: 0; margin-bottom: 0.5em; color: #000; }
          p { margin-top: 0; margin-bottom: 1em; }
          img { display: block; max-width: 100%; height: auto; border: none; }
          .page-break { page-break-after: always; }
          
          /* Estilos para que el PDF se vea más profesional */
          .indra-document-footer { font-size: 8px; color: #999; margin-top: 50px; border-top: 1px solid #eee; padding-top: 10px; }
        </style>
      </head>
      <body>
        ${body}
        <div class="indra-document-footer">
          Generado automáticamente por Indra OS — Identidad: ${docAtom.id} — Fecha: ${new Date().toLocaleString()}
        </div>
      </body>
      </html>
    `;
  }
};

1_logic.indra_parser.gs:
/**
 * INDRA PARSER v4.0 (Isomorfismo Axiomático)
 * -------------------------------------------
 * Misión: Proveer una única verdad de cálculo para el Frontend y el Backend.
 * Axioma: Cero dependencias de plataforma (isomórfico).
 * Restricción: No usa eval() ni new Function().
 * Soporta: Aritmética, Lógica (&&, ||, !), Comparación (==, !=, >, <), Funciones (IF, ROUND, SUM).
 */

const IndraParser = {
  
  /**
   * Evalúa una expresión básica o fórmula contra un contexto.
   */
  evaluate(expr, context = {}) {
    if (!expr || typeof expr !== 'string') return 0;
    
    try {
      const tokens = this._tokenize(expr);
      return this._evaluateTokens(tokens, context);
    } catch (e) {
      if (typeof console !== 'undefined') {
        console.error("[IndraParser v4] Eval Error:", e.message, "| Expr:", expr);
      }
      return 0;
    }
  },

  /**
   * Tokenización avanzada.
   */
  _tokenize(expr) {
    // Regex para: Funciones, Identificadores de ruta, Números, Operadores (compuestos), Paréntesis y Comas
    // Detectamos &&, ||, ==, !=, >=, <= como unidades.
    const regex = /([0-9\.]+|[a-zA-Z_][a-zA-Z0-9_\.]*|&&|\|\||==|!=|>=|<=|[+\-*/()!,><=])/g;
    return expr.match(regex) || [];
  },

  /**
   * Precedencia de operadores canónica (C-style).
   */
  _precedence: {
    '!': 6,
    '*': 5, '/': 5,
    '+': 4, '-': 4,
    '>': 3, '<': 3, '>=': 3, '<=': 3,
    '==': 2, '!=': 2,
    '&&': 1,
    '||': 0
  },

  /**
   * Evaluador con soporte para funciones y lógica extendida.
   */
  _evaluateTokens(tokens, context) {
    const values = [];
    const ops = [];

    const applyOp = () => {
      const op = ops.pop();
      if (op === '!') {
          const v = values.pop();
          values.push(!v);
          return;
      }
      const b = values.pop();
      const a = values.pop();
      
      switch (op) {
        case '+': values.push(a + b); break;
        case '-': values.push(a - b); break;
        case '*': values.push(a * b); break;
        case '/': values.push(b !== 0 ? a / b : 0); break;
        case '&&': values.push(a && b); break;
        case '||': values.push(a || b); break;
        case '==': values.push(a == b); break;
        case '!=': values.push(a != b); break;
        case '>':  values.push(a > b); break;
        case '<':  values.push(a < b); break;
        case '>=': values.push(a >= b); break;
        case '<=': values.push(a <= b); break;
      }
    };

    for (let i = 0; i < tokens.length; i++) {
        let token = tokens[i];
        
        // 1. Manejo de Funciones de Sistema (v4.0)
        if (['IF', 'ROUND', 'SUM'].includes(token.toUpperCase())) {
            const func = token.toUpperCase();
            // Avanzar hasta el '(' de la función
            i += 2; // Token -> '(' -> Primer argumento
            let depth = 1;
            let subTokens = [];
            let args = [[]];
            
            // Recolectar tokens hasta cerrar la función, separando por comas
            while (i < tokens.length && depth > 0) {
                const sub = tokens[i];
                if (sub === '(') depth++;
                if (sub === ')') depth--;
                
                if (depth === 0) break;
                
                if (sub === ',' && depth === 1) {
                    args.push([]);
                } else {
                    args[args.length - 1].push(sub);
                }
                i++;
            }
            
            // Evaluar argumentos recursivamente
            const evaluatedArgs = args.map(aTokens => this._evaluateTokens(aTokens, context));
            
            // Ejecutar lógica de función
            if (func === 'IF') {
                values.push(evaluatedArgs[0] ? evaluatedArgs[1] : (evaluatedArgs[2] || 0));
            } else if (func === 'ROUND') {
                values.push(Math.round(evaluatedArgs[0]));
            } else if (func === 'SUM') {
                // AXIOMA DE COLAPSO: Aplanar argumentos para permitir SUM(op.items.subtotal) o SUM(1,2,3)
                const flatArgs = evaluatedArgs.flat(Infinity);
                values.push(flatArgs.reduce((s, v) => s + (Number(v) || 0), 0));
            } else if (func === 'MONEY_ROUND') {
                // AXIOMA DE SINCERIDAD: Redondeo bancario a 2 decimales para evitar errores de coma flotante.
                const val = Number(evaluatedArgs[0]) || 0;
                values.push(Math.round((val + Number.EPSILON) * 100) / 100);
            }
            continue;
        }

        if (token === '(') {
            ops.push(token);
        } else if (token === ')') {
            while (ops.length && ops[ops.length - 1] !== '(') applyOp();
            ops.pop();
        } else if (this._precedence[token] !== undefined) {
            while (ops.length && this._precedence[ops[ops.length - 1]] >= this._precedence[token]) applyOp();
            ops.push(token);
        } else {
            // Resolver variable o número
            if (!isNaN(token)) {
                values.push(parseFloat(token));
            } else {
                let val = token.split('.').reduce((obj, key) => (obj && obj[key] !== undefined) ? obj[key] : undefined, context);
                // Si el valor es boolean, lo dejamos, si es numérico lo parseamos
                if (typeof val === 'boolean') {
                    values.push(val);
                } else {
                    values.push((val === undefined || val === null) ? 0 : parseFloat(val) || 0);
                }
            }
        }
    }
    
    while (ops.length) applyOp();
    return values[0] !== undefined ? values[0] : 0;
  }
};

if (typeof module !== 'undefined' && module.exports) {
  module.exports = { IndraParser };
}

1_logic.induction_orchestrator.gs:
/**
 * =============================================================================
 * ARTEFACTO: 1_logic/induction_orchestrator.gs
 * RESPONSABILIDAD: Orquestación Universal de Cristalización (Motor de Ignición v2.0)
 * AXIOMA: Big Bang Único + Soberanía de la Materia + Relacionalidad Micelar.
 * =============================================================================
 */

const INDUCTION_TICKET_TTL_SECONDS_ = 60 * 60 * 12; // 12 horas de vida para el ticket de génesis

// --- UTILIDADES DE TICKETS (MEMORIA DE GÉNESIS) ---

function _system_induction_cache_() {
  return CacheService.getScriptCache();
}

function _system_induction_ticketKey_(ticketId) {
  return `indra_induction_ticket_${ticketId}`;
}

function _system_induction_generateTicketId_() {
  const nonce = Math.random().toString(36).slice(2, 10);
  return `ind_${Date.now()}_${nonce}`;
}

function _system_induction_readTicket_(ticketId) {
  if (!ticketId) return null;
  const raw = _system_induction_cache_().get(_system_induction_ticketKey_(ticketId));
  if (!raw) return null;
  try {
    return JSON.parse(raw);
  } catch (e) {
    return null;
  }
}

function _system_induction_writeTicket_(ticket) {
  if (!ticket || !ticket.ticket_id) return;
  ticket.updated_at = new Date().toISOString();
  _system_induction_cache_().put(
    _system_induction_ticketKey_(ticket.ticket_id),
    JSON.stringify(ticket),
    INDUCTION_TICKET_TTL_SECONDS_
  );
}

// --- MOTOR DE CRISTALIZACIÓN UNIVERSAL ---

/**
 * ALIAS: Entrada de compatibilidad para el Router Global.
 */
function _system_induction_start(uqo) {
  return induction_orchestrateCrystallization_(uqo);
}

/**
 * MOTOR DE CRISTALIZACIÓN UNIVERSAL (The Big Bang)
 * Toma un ADN (Blueprint) y lo expande en un mini-universo autocontenido.
 */
function induction_orchestrateCrystallization_(uqo) {
  const data = uqo.data || {};
  const dna = data.source_artifact || data.blueprint; // ADN / Blueprint
  const workspaceId = uqo.workspace_id || data.workspace_id;
  const targetProvider = data.target_provider || 'drive';
  const publishImmediately = !!data.publish_immediately;

  // --- AXIOMA DE PERISTALSIS: Modo Ingesta Irreversible ---
  if (data.mode === 'PERISTALTIC' || data.peristaltic) {
      logInfo(`[induction:engine] 🌊 Modo PERISTÁLTICO detectado. Generando Ticket Persistente.`);
      const ticket = _peristaltic_createPersistentTicket(uqo);
      return { 
          items: [ticket], 
          metadata: { 
              status: 'OK', 
              mode: 'PERISTALTIC', 
              ticket_id: ticket.id 
          } 
      };
  }

  const ticket = {
    ticket_id: _system_induction_generateTicketId_(),
    status: 'IN_PROGRESS',
    step: 'GÉNESIS',
    created_at: new Date().toISOString(),
    updated_at: new Date().toISOString(),
    workspace_id: workspaceId,
    dna_id: dna?.id || 'unknown',
    errors: []
  };
  _system_induction_writeTicket_(ticket);

  try {
    logInfo(`[induction:engine] ✨ Iniciando Cristalización Universal. DNA: ${dna?.id || 'protoplasm'}`);

    // --- FASE 1: INDUCCIÓN DE ESQUEMA (El Código Genético) ---
    ticket.step = 'INDUCING_SCHEMA';
    _system_induction_writeTicket_(ticket);

    let schemaFields = [];
    let schemaAtom = null;

    if (data.mode === 'IN_PLACE_IGNITION' && uqo.context_id) {
      // MODO: IN-PLACE. Usamos el esquema existente.
      logInfo(`[induction:engine] 💉 Modo IN_PLACE detectado. Usando esquema: ${uqo.context_id}`);
      const schemaRead = route({ provider: 'system', protocol: 'ATOM_READ', context_id: uqo.context_id });
      schemaAtom = schemaRead.items?.[0];
      if (!schemaAtom) throw createError('NOT_FOUND', 'Esquema original no encontrado para ignición in-situ.');
      schemaFields = schemaAtom.payload?.fields || [];
    } else if (dna?.class === 'DATA_SCHEMA') {
      schemaFields = dna.payload?.fields || [];
    } else {
      const stream = _system_induction_collectStream_(uqo, dna);
      _system_induction_validateInput_(dna, stream);
      schemaFields = _system_induction_buildSchemaFields_(dna, stream, data.muted_fields || []);
    }

    if (schemaFields.length === 0) throw createError('CONTRACT_VIOLATION', 'ADN estéril: No se encontraron campos para materializar.');

    if (!schemaAtom) {
      // Solo creamos si no estamos en modo IN_PLACE
      const schemaCreate = route({
        provider: 'system',
        protocol: 'ATOM_CREATE',
        data: {
          class: 'DATA_SCHEMA',
          handle: { label: `Schema for ${dna?.handle?.label || dna?.id || 'Materialization'}` },
          payload: { fields: schemaFields }
        }
      });
      schemaAtom = schemaCreate.items?.[0];
    }

    if (!schemaAtom) throw createError('SYSTEM_FAILURE', 'Error al cristalizar el ADN (Schema).');

    // --- FASE 2: MATERIALIZACIÓN FÍSICA (La Materia) ---
    ticket.step = `MATERIALIZING_IN_${targetProvider.toUpperCase()}`;
    _system_induction_writeTicket_(ticket);

    logInfo(`[induction:engine] 🧱 Solicitando materia física a ${targetProvider}...`);
    const physicalCreate = route({
      provider: targetProvider,
      protocol: 'ATOM_CREATE',
      context_id: data.parent_id,
      data: {
        class: 'TABULAR',
        handle: { label: dna?.handle?.label || dna?.id || 'Indra Silo' },
        fields: schemaFields,
        parent_id: data.parent_id,
        intent: 'MATERIALIZE_SOVEREIGN'
      }
    });

    const physicalSilo = physicalCreate.items?.[0];
    if (!physicalSilo) throw createError('MATERIALIZATION_FAILED', `El provider ${targetProvider} denegó la materialización.`);

    // --- FASE 3: GENERACIÓN DE PUENTE (El Entrelazamiento Relacional) ---
    ticket.step = 'GENERATING_BRIDGE';
    _system_induction_writeTicket_(ticket);

    const uiPurpose = dna.payload?.ui_purpose || 'GENERIC_BOARD';
    const cognitiveClass = dna.payload?.cognitive_class || 'DATA_METER';
    logInfo(`[induction:engine] 🧬 Puente heredando semántica: ${cognitiveClass} (UI: ${uiPurpose})`);

    const bridgeCreate = route({
      provider: 'system',
      protocol: 'ATOM_CREATE',
      data: {
        class: 'BRIDGE',
        handle: { label: `Bridge for ${dna?.id || 'Induction'}` },
        payload: {
          dna_id: dna?.id,
          ui_purpose: uiPurpose,
          cognitive_class: cognitiveClass,
          targets: [physicalSilo.id],
          target_provider: targetProvider,
          mappings: {
            [physicalSilo.id]: schemaFields.reduce((acc, f) => {
              acc[f.id] = `source.${f.handle?.alias || f.id}`;
              return acc;
            }, {})
          }
        }
      }
    });

    const bridgeAtom = bridgeCreate.items?.[0];
    if (!bridgeAtom) throw createError('SYSTEM_FAILURE', 'Error al crear el Puente Relacional.');

    // --- FASE 4: ACOPLAMIENTO AL WORKSPACE (Anclaje Cuántico) ---
    if (workspaceId) {
      ticket.step = 'QUANTUM_PINNING';
      _system_induction_writeTicket_(ticket);
      logInfo(`[induction:engine] 🔗 Anclando mini-universo a Workspace: ${workspaceId}`);

      [schemaAtom, bridgeAtom, physicalSilo].forEach(atom => {
        if (atom && atom.id) {
          route({
            provider: 'system',
            protocol: 'SYSTEM_PIN',
            workspace_id: workspaceId,
            data: { atom }
          });
        }
      });
    }

    // --- FINALIZACIÓN Y ACTUALIZACIÓN DE METADATOS ---
    schemaAtom.payload = { 
      ...schemaAtom.payload, 
      bridge_id: bridgeAtom.id, 
      silo_id: physicalSilo.id,
      publish_immediately: publishImmediately 
    };
    route({ 
      provider: 'system', 
      protocol: 'ATOM_UPDATE', 
      context_id: schemaAtom.id, 
      data: { payload: schemaAtom.payload } 
    });

    ticket.status = 'COMPLETED';
    ticket.step = 'CRISTALIZADO';
    _system_induction_writeTicket_(ticket);

    logInfo(`[induction:engine] ✅ Cristalización completada con éxito. Universo listo.`);

    return {
      items: [schemaAtom],
      metadata: {
        status: 'OK',
        ticket_id: ticket.ticket_id,
        universe: {
          schema_id: schemaAtom.id,
          bridge_id: bridgeAtom.id,
          silo_id: physicalSilo.id
        }
      }
    };

  } catch (err) {
    logError(`[induction:engine] ❌ Colapso en cristalización.`, err);
    ticket.status = 'ERROR';
    ticket.errors.push(err.message);
    _system_induction_writeTicket_(ticket);
    return { 
      items: [], 
      metadata: { 
        status: 'ERROR', 
        error: err.message, 
        code: err.code || 'CRYSTALLIZATION_FAILED',
        ticket_id: ticket.ticket_id 
      } 
    };
  }
}

// --- FUNCIONES DE APOYO DEL MOTOR ---

function _system_induction_validateInput_(sourceArtifact, streamResult) {
  if (!sourceArtifact || typeof sourceArtifact !== 'object') throw createError('INPUT_CONTRACT_VIOLATION', 'INDUCTION requiere data.source_artifact.');
  if (!streamResult || streamResult.metadata?.status !== 'OK') throw createError('CONTRACT_VIOLATION', 'TABULAR_STREAM inválido para inducción.');
}

function _system_induction_collectStream_(uqo, sourceArtifact) {
  const providedStream = uqo.data?.tabular_stream;
  if (providedStream && providedStream.metadata?.schema?.fields) return providedStream;

  return route({
    provider: sourceArtifact.provider,
    protocol: 'TABULAR_STREAM',
    context_id: sourceArtifact.id,
    query: { limit: 5 }
  });
}

function _system_induction_buildSchemaFields_(sourceArtifact, streamResult, mutedFields) {
  const streamFields = streamResult.metadata?.schema?.fields || [];
  const mutedSet = {};
  (mutedFields || []).forEach(id => { mutedSet[id] = true; });

  return streamFields
    .filter(field => !mutedSet[field.id])
    .map(field => {
      const fieldAlias = _system_slugify_(field.handle?.label || field.label || field.id);
      return {
        id: fieldAlias,
        handle: {
          ns: 'com.indra.system.schema.field',
          alias: fieldAlias,
          label: field.handle?.label || field.label || field.id
        },
        type: _system_induction_mapType_(field.type),
        source_id: field.id,
        source_provider: sourceArtifact.provider,
        source_context_id: sourceArtifact.id
      };
    });
}

function _system_induction_mapType_(canonicalType) {
  const t = String(canonicalType || '').toUpperCase();
  if (['NUMBER', 'INTEGER', 'FLOAT', 'DECIMAL'].includes(t)) return 'NUMBER';
  if (['BOOLEAN', 'BOOL', 'CHECKBOX'].includes(t)) return 'BOOLEAN';
  if (['DATE', 'DATETIME', 'TIME'].includes(t)) return 'DATE';
  return 'STRING';
}

// --- PROTOCOLOS ADICIONALES (CONTROL DE GÉNESIS) ---

function _system_induction_status(uqo) {
  const ticketId = uqo.query?.ticket_id || uqo.data?.ticket_id || uqo.context_id;
  const ticket = _system_induction_readTicket_(ticketId);
  if (!ticket) return { items: [], metadata: { status: 'ERROR', error: 'Ticket no encontrado.' } };

  return {
    items: [],
    metadata: { status: 'OK', ticket: ticket, induction_status: ticket.status }
  };
}

function _system_induction_cancel(uqo) {
  const ticketId = uqo.data?.ticket_id || uqo.context_id;
  const ticket = _system_induction_readTicket_(ticketId);
  if (!ticket) return { items: [], metadata: { status: 'ERROR', error: 'Ticket no encontrado.' } };

  ticket.status = 'CANCELLED';
  _system_induction_writeTicket_(ticket);
  return { items: [], metadata: { status: 'OK', ticket: ticket } };
}

/**
 * _system_induction_drift_check: Sensor de Entropía Estructural.
 * Compara el Silo Físico contra el DNA (Schema) para detectar divergencias.
 */
function _system_induction_drift_check(uqo) {
  const bridgeId = uqo.context_id || uqo.data?.bridge_id;
  if (!bridgeId) throw createError('INVALID_INPUT', 'INDUCTION_DRIFT_CHECK requiere bridge_id.');

  const bridgeAtom = route({ provider: 'system', protocol: 'ATOM_READ', context_id: bridgeId }).items?.[0];
  if (!bridgeAtom || bridgeAtom.class !== 'BRIDGE') throw createError('NOT_FOUND', 'Puente no encontrado para chequeo de drift.');

  const dnaId = bridgeAtom.payload?.dna_id;
  const targetSiloId = bridgeAtom.payload?.targets?.[0];

  // 1. Leer el ADN (Esquema Ideal)
  const schemaAtom = route({ provider: 'system', protocol: 'ATOM_READ', context_id: dnaId }).items?.[0];

  // 2. Leer la Materia (Silo Físico)
  const siloStream = route({ 
    provider: bridgeAtom.payload?.target_provider || 'drive', 
    protocol: 'TABULAR_STREAM', 
    context_id: targetSiloId,
    query: { limit: 1 } 
  });

  const idealFields = schemaAtom?.payload?.fields || [];
  const physicalFields = siloStream.metadata?.schema?.fields || [];

  // 3. Comparación de Resonancia
  const missingInPhysical = idealFields.filter(f => !physicalFields.find(pf => pf.id === f.id));
  const driftDetected = missingInPhysical.length > 0;

  return {
    items: [],
    metadata: {
      status: 'OK',
      drift_detected: driftDetected,
      entropy_report: {
        missing_fields: missingInPhysical.map(f => f.id),
        ideal_count: idealFields.length,
        physical_count: physicalFields.length
      }
    }
  };
}

1_logic.logic_engine.gs:
/**
 * INDRA LOGIC ENGINE v4.0
 * Responsibility: Execute transformation chains independently from providers.
 * Engine: Google Apps Script V8 + IndraParser (Isomorphic).
 */

var LogicEngine = {
  
  /**
   * Executes a Logic Bridge transformation.
   * @param {Object} uqo The Universal Query Object containing payload and bridge config.
   */
  executeLogicBridge: function(uqo) {
    const dataObj = uqo.data || uqo.query || {};
    const { payload, trigger_data, bridge } = dataObj;
    const config = bridge || {};
    const operators = config.operators || [];
    const targetMappings = config.targetMappings || {};
    
    // Axioma de Dualidad: Si no hay payload (Batch), buscamos trigger_data (AEE)
    const activeData = payload || (trigger_data ? [trigger_data] : null);
    
    if (!activeData || !Array.isArray(activeData)) {
      return { items: [], metadata: { status: "ERROR", error: "LogicEngine: No valid data pool found." } };
    }

    try {
      const results = activeData.map(item => {
        // Clonamos el estado inicial para calcular el diferencial (Delta)
        const before = JSON.parse(JSON.stringify(item));
        let context = JSON.parse(JSON.stringify(item)); 
        
        // AXIOMA DE NOMBRE ESPACIAL: El payload original reside en 'source' para el parser.
        context.source = JSON.parse(JSON.stringify(item));
        context.op = {}; // Asegurar inicialización de namespace de operadores
        
        // 1. Ejecución Secuencial de Operadores (Resonancia de Cálculo)
        operators.forEach(op => {
          this.executeOperator(op, context);
        });
        
        // 2. Aplicación de Mapeo Final (Mapeo a slots destino)
        // ADR-014: Los mappings vienen agrupados por targetId
        const mappings = config.mappings || config.targetMappings || {};
        const targetConfigs = config.targetConfigs || {};
        const sourceConfigs = config.sourceConfigs || {};

        Object.keys(mappings).forEach(targetId => {
          const fieldMappings = mappings[targetId];
          if (typeof fieldMappings !== 'object') return;

          // Buscar el alias del targetId para saber dónde escribir en el context
          const tConfig = targetConfigs[targetId] || {};
          const sConfig = sourceConfigs[targetId] || {};
          const alias = tConfig.alias || sConfig.alias || targetId;

          Object.keys(fieldMappings).forEach(fieldId => {
             if (fieldId.endsWith('_label')) return; // Saltar metadatos de UI
             
             const sourcePath = fieldMappings[fieldId];
             const val = this._get_(context, sourcePath);
             
             // Escribir en context.ALIAS.FIELD_ID (Ley de Aduana: Respetar estructura del trigger_data)
             this._set_(context, `${alias}.${fieldId}`, val);
          });
        });
        
        // 3. Calculadora de Deltas (Sinceridad de Resonancia)
        const delta = this._calculateDelta_(before, context);
        
        // AXIOMA DE TRANSPARENCIA: En simulaciones, adjuntamos resultados de operadores
        if (bridge) delta.__debug_op__ = JSON.parse(JSON.stringify(context.op || {}));
        
        return delta;
      });

      // Si es una ejecución unitaria (AEE / Cotizador), notificamos modo DELTA
      const isSingle = trigger_data || activeData.length === 1;
      
      return { 
        items: results, 
        metadata: { 
          status: "OK", 
          update_type: isSingle ? "DELTA" : "SNAPSHOT",
          result: isSingle ? results[0] : null,
          // AXIOMA DE TRANSPARENCIA: Si enviaron un bridge efímero, devolvemos los resultados de los operadores
          debug: bridge ? results.map((_, idx) => results[idx].__debug_op__) : null
        } 
      };

    } catch (e) {
      logError("[LogicEngine v4] Runtime Error:", e.message);
      return { items: [], metadata: { status: "ERROR", error: "LogicEngine V4 Error: " + e.message } };
    }
  },

  /**
   * Executes an operator, delegation logic to the isomorphic IndraParser or performing internal actions like RESOLVER.
   */
  /**
   * Executes an operator, delegation logic to the isomorphic IndraParser or performing internal actions like RESOLVER.
   */
  executeOperator: function(op, context) {
    const { config, alias, id, type } = op;
    const { input_a, input_b, operation, silo } = config; 
    
    // --- NODO RESOLVER (Data Extractor) ---
    if (type === 'RESOLVER') {
      const ptrInput = this._get_(context, input_a);
      
      const resolveSingle = (idStr) => {
         if (!idStr) return null;
         try {
            const providerId = silo.provider || 'system';
            const resp = route({
                provider: providerId, protocol: 'ATOM_READ', context_id: idStr
            });
            if (resp && resp.items && resp.items.length > 0) {
                // SINCERIDAD TOTAL: Simplemente retornamos el átomo tal cual.
                // El provider se encargó de poner los datos en la raíz.
                return resp.items[0];
            }
         } catch(e) {
            logWarn("[LogicEngine] RESOLVER Node error al hidratar " + idStr + ": " + e.message);
         }
         return null;
      };

      let extracted = null;
      // Compatibilidad Vectorial: Si es una lista de IDs (Repeater), retorna lista de propiedades
      if (Array.isArray(ptrInput)) {
          extracted = ptrInput.map(itemId => resolveSingle(itemId));
      } else {
          extracted = resolveSingle(ptrInput);
      }

      this._set_(context, "op." + id, extracted);
      if (alias) this._set_(context, "op." + alias, extracted);
      return;
    }

    // --- NODO HYDRATE_DOC (Document Generation Engine) ---
    // AXIOMA: Independence & Information. Inyecta DataRow en el AST sin persistir.
    if (type === 'HYDRATE_DOC') {
      const sourceData = this._get_(context, input_a) || context.source || {};
      const templateDoc = this._get_(context, input_b);
      
      if (!templateDoc || templateDoc.class !== 'DOCUMENT') {
         logError("[LogicEngine] HYDRATE_DOC requiere un átomo DOCUMENT en input_b.");
         return;
      }

      // Clonar AST para no mutar plantilla
      const hydratedAst = JSON.parse(JSON.stringify(templateDoc.payload?.blocks || []));
      
      const hydrateNode = (node) => {
         if (node.type === 'TEXT' && typeof node.content === 'string') {
             node.content = node.content.replace(/\{\{\s*([a-zA-Z0-9_.-]+)\s*\}\}/g, (match, path) => {
                 const val = this._get_(sourceData, path);
                 return val !== undefined && val !== null ? String(val) : match;
             });
         }
         if (node.children && Array.isArray(node.children)) {
             node.children.forEach(hydrateNode);
         }
      };

      hydratedAst.forEach(hydrateNode);
      
      const resultDoc = JSON.parse(JSON.stringify(templateDoc));
      resultDoc.payload.blocks = hydratedAst;
      resultDoc._hydrated = true;

      this._set_(context, "op." + id, resultDoc);
      if (alias) this._set_(context, "op." + alias, resultDoc);
      return;
    }

    // --- NODO FILTER (Sinceridad de Colección) ---
    // Axioma: Reducir ruido filtrando vectores por propiedad o valor.
    if (type === 'FILTER') {
      const list = this._get_(context, input_a);
      const { property, criteria, value } = config; 
      
      const filtered = Array.isArray(list) ? list.filter(item => {
          const val = property ? (item && item[property]) : item;
          switch (criteria) {
            case '==': return val == value;
            case '!=': return val != value;
            case '>':  return val > value;
            case '<':  return val < value;
            case 'CONTAINS': return String(val).includes(String(value));
            default: return true;
          }
      }) : [];
      
      this._set_(context, "op." + id, filtered);
      if (alias) this._set_(context, "op." + alias, filtered);
      return;
    }

    // --- NODO LOOKUP (Referencia de Resonancia) ---
    // Axioma: Localizar un átomo en una tabla por una clave de búsqueda.
    if (type === 'LOOKUP') {
      const searchKey = this._get_(context, input_a);
      const table = this._get_(context, input_b);
      const { search_field, return_field } = config;
      
      const matched = Array.isArray(table) ? table.find(item => item && item[search_field] == searchKey) : null;
      const result = (matched && return_field) ? (matched[return_field] !== undefined ? matched[return_field] : matched) : matched;
      
      this._set_(context, "op." + id, result || 0);
      if (alias) this._set_(context, "op." + alias, result || 0);
      return;
    }

    // --- OPERADORES MATH & TEXT ---
    const isStandard = ["ADD", "SUBTRACT", "MULTIPLY", "DIVIDE", "SUMMATION"].includes(operation);
    
    if (isStandard) {
        if (operation === 'SUMMATION') {
          // AXIOMA DE COLAPSO: Reducir vector a escalar para Totales.
          const valA = this._get_(context, input_a);
          const result = Array.isArray(valA) ? valA.reduce((s, v) => s + (Number(v) || 0), 0) : (Number(valA) || 0);
          this._set_(context, "op." + id, result);
          if (alias) this._set_(context, "op." + alias, result);
        } else {
          const valA = this._get_(context, input_a);
          const valB = this._get_(context, input_b);
          const result = this._computeStandard_(operation, valA, valB);
          this._set_(context, "op." + id, result);
          if (alias) this._set_(context, "op." + alias, result);
        }
    } else {
        // MODO AXIOMÁTICO: Evaluación de expresión (parser compartido FE/BE)
        const result = IndraParser.evaluate(operation, context);
        this._set_(context, "op." + id, result);
        if (alias) this._set_(context, "op." + alias, result);
    }
  },

  /**
   * Operaciones aritméticas vectoriales. 
   * Si las entradas son arrays (ej. cantidad y precios de un Repeater), realiza operaciones Par-a-Par.
   */
  _computeStandard_: function(operation, a, b) {
    const isArrA = Array.isArray(a);
    const isArrB = Array.isArray(b);

    const doMath = (vA, vB) => {
      const numA = Number(vA) || 0;
      const numB = Number(vB) || 0;
      switch (operation) {
        case "ADD":      return numA + numB;
        case "SUBTRACT": return numA - numB;
        case "MULTIPLY": return numA * numB;
        case "DIVIDE":   return numB !== 0 ? numA / numB : 0;
        default:         return numA;
      }
    };

    if (isArrA && isArrB) return a.map((val, idx) => doMath(val, b[idx]));
    if (isArrA && !isArrB) return a.map(val => doMath(val, b));
    if (!isArrA && isArrB) return b.map(val => doMath(a, val));
    return doMath(a, b);
  },

  /**
   * Calcula el diferencial puro entre dos estados.
   */
  _calculateDelta_: function(before, after) {
    const delta = { id: after.id }; 
    Object.keys(after).forEach(key => {
        if (key === 'source' || key === 'op' || key === 'id') return;
        if (JSON.stringify(before[key]) !== JSON.stringify(after[key])) {
            delta[key] = after[key];
        }
    });
    return delta;
  },

  /**
   * Helper: Get value by dot path con soporte vectorial.
   * Si en la ruta hay un 'Array', recolecta el mapeo de sus hijos.
   */
  _get_: function(obj, path) {
    if (!path) return undefined;
    return path.split('.').reduce((prev, curr) => {
      if (prev === undefined || prev === null) return undefined;
      if (Array.isArray(prev)) {
          if (!isNaN(curr)) return prev[Number(curr)]; // Índice exacto
          return prev.map(item => item && item[curr]); // Array map
      }
      return prev[curr];
    }, obj);
  },

  /**
   * Helper: Set value by dot path con soporte vectorial mutativo.
   */
  _set_: function(obj, path, value) {
    if (!path) return;
    const parts = path.split('.');
    let last = parts.pop();

    let target = obj;
    for (let i = 0; i < parts.length; i++) {
        let curr = parts[i];
        if (target === undefined || target === null) return;
        
        if (Array.isArray(target)) {
            let subPath = [...parts.slice(i), last].join('.');
            target.forEach((item, index) => {
                this._set_(item, subPath, Array.isArray(value) ? value[index] : value);
            });
            return;
        } else {
            if (target[curr] === undefined) target[curr] = {};
            target = target[curr];
        }
    }

    if (Array.isArray(target)) {
        target.forEach((item, index) => {
            item[last] = Array.isArray(value) ? value[index] : value;
        });
    } else {
        target[last] = value;
    }
  }
};

