2_providers.provider_drive.gs:
// =============================================================================
// ARTEFACTO: 2_providers/provider_drive.gs
// CAPA: 2 — Providers
// RESPONSABILIDAD: Traductor del sistema de archivos de Google Drive al protocolo
//         universal del Core. Opera con las credenciales del propietario del
//         script (executeAs: USER_DEPLOYING) — no requiere API Key externa.
//         Es el único artefacto del sistema que invoca DriveApp para exploración.
//
// PROTOCOLO DE REGISTRO (auto-descubrimiento):
//   PROVIDER_CONF_DRIVE es detectado por _scanProviders_() en provider_registry.gs.
//
// AXIOMS:
//   - Classification logic resides here. Frontend receives standardized atoms.
//   - `class` determines the projected view (DATA_CONTRACTS §2.3).
//   - Google Sheets → class: TABULAR. Todo lo demás → class: DOCUMENT | FOLDER.
//   - `raw` contiene el dato crudo de Drive para depuración. Solo para eso.
//   - La paginación es real: `has_more` y `next_cursor` viajan en metadata.
//
// RESTRICCIONES:
//   - NO puede hardcodear nombres de archivos ni IDs de carpetas del usuario.
//   - NO puede leer ni escribir PropertiesService.
//   - NO puede invocar UrlFetchApp (Drive es nativo, no una REST API externa).
//   - NO puede inferir `class` por regex o heurísticas de nombre de archivo.
//     La clasificación es por mimeType — determinista y sin adivinar.
// =============================================================================

/**
 * Configuración de auto-descubrimiento del provider drive.
 * Los campos `implements` mapean protocolo → nombre de función global.
 * @const {Object}
 */
/**
 * Manifestación del Silo Drive. Sigue el Protocolo ADR-002.
 * Esta función es detectada automáticamente por el ProviderRegistry.
 * @returns {Object} Contrato de configuración.
 */
function CONF_DRIVE() {
  return Object.freeze({
    id: 'drive',
    handle: {
      ns: 'com.indra.system.silo',
      alias: 'drive',
      label: 'Google Drive',
      icon: 'FOLDER',
      entry_point: 'ROOT' // LEY SUH: Punto de entrada canónico
    },
    class: 'FOLDER',
    version: '1.2 (Sovereign Synthesis)',
    capabilities: {
      ATOM_READ: { sync: 'BLOCKING', purge: 'NONE' },
      ATOM_CREATE: { sync: 'BLOCKING', purge: 'ALL' },
      ATOM_UPDATE: { sync: 'BLOCKING', purge: 'ID' },
      ATOM_DELETE: { sync: 'BLOCKING', purge: 'ALL' },
      BATCH_UPDATE: { sync: 'BLOCKING', purge: 'ALL' },
      HIERARCHY_TREE: { sync: 'BLOCKING', purge: 'NONE' },
      SEARCH_DEEP: { sync: 'BLOCKING', purge: 'NONE' },
      TABULAR_STREAM: { sync: 'BLOCKING', purge: 'NONE' },
      TABULAR_UPDATE: { sync: 'BLOCKING', purge: 'ALL' }, // Nueva Ley Canónica
      MEDIA_RESOLVE: { sync: 'BLOCKING', purge: 'NONE' },
      MEDIA_UPLOAD: { sync: 'BLOCKING', purge: 'NONE' },
      TRANSFER_HANDSHAKE: { sync: 'BLOCKING', purge: 'NONE' }
    },
    protocol_meta: {
      TRANSFER_HANDSHAKE: {
        desc: "Inicia una sesión de transferencia resumible para archivos grandes.",
        inputs: { 
          filename: { type: 'string', required: true },
          mimeType: { type: 'string', required: true },
          parent_id: { type: 'string', required: false }
        }
      },
      ATOM_CREATE: {
        desc: "Crea una nueva FOLDER o un DOCUMENT (vía handshake si es pesado).",
        inputs: {
          name: { type: 'string', required: true },
          class: { type: 'string', required: true },
          context_id: { type: 'string', required: false },
          intent: { type: 'string', required: false, desc: 'TRANSFER | DIRECT' }
        }
      }
    }
  });
}

// ─── MAPA DE MIME TYPES → CLASS CANÓNICO ─────────────────────────────────────

/**
 * Mapa determinista: mimeType de Google Drive → class canónico del átomo universal.
 * Decisión: El backend clasifica. El front no pregunta qué es el ítem, solo qué vista usar.
 * Cualquier mimeType ausente en el mapa → class: DOCUMENT (safe default).
 * @const {Object}
 */
const MIME_TO_CLASS_ = Object.freeze({
  'application/vnd.google-apps.folder': 'FOLDER',
  'application/vnd.google-apps.spreadsheet': 'TABULAR',
  'application/vnd.google-apps.document': 'DOCUMENT',
  'application/vnd.google-apps.presentation': 'DOCUMENT',
  'application/vnd.google-apps.form': 'DOCUMENT',
  'application/vnd.google-apps.drawing': 'DOCUMENT',
  'application/pdf': 'DOCUMENT',
  'image/jpeg': 'DOCUMENT',
  'image/png': 'DOCUMENT',
  'text/plain': 'DOCUMENT',
  'application/json': 'DOCUMENT',
});

/**
 * Mapa determinista: mimeType → protocolos que soporta ese ítem específico.
 * Decisión: Los protocolos del átomo reflejan lo que ESE ítem puede hacer,
 * no lo que el provider soporta globalmente (DATA_CONTRACTS §2.3).
 * @const {Object}
 */
const MIME_TO_PROTOCOLS_ = Object.freeze({
  'application/vnd.google-apps.folder': ['HIERARCHY_TREE', 'ATOM_CREATE'],
  'application/vnd.google-apps.spreadsheet': ['TABULAR_STREAM', 'ATOM_READ', 'ATOM_CREATE'],
  'application/vnd.google-apps.document': ['ATOM_READ'],
});

/** Máximo de ítems por página para evitar timeouts en GAS (límite: 6 min). */
const DRIVE_PAGE_SIZE_ = 50;

// ─── MANEJADOR PRINCIPAL ──────────────────────────────────────────────────────

/**
 * Punto de entrada del provider drive. Invocado por protocol_router.gs.
 * Despacha el UQO al sub-handler correcto según el protocolo.
 *
 * @param {Object} uqo - Universal Query Object validado por protocol_router.
 * @returns {{ items: Array, metadata: Object }}
 */
function handleDrive(uqo) {
  const protocol = (uqo.protocol || '').toUpperCase();

  const providerStr = uqo.provider || 'drive';
  const baseId = providerStr.split(':')[0];
  if (baseId !== 'drive') {
    const err = createError('SYSTEM_FAILURE', `El handler de Drive recibió un provider inesperado: ${uqo.provider}`);
    return { items: [], metadata: { status: 'ERROR', error: err.message, code: err.code } };
  }

  logInfo(`[provider_drive] Dispatching: ${protocol}`, { context_id: uqo.context_id });

  if (protocol === 'HIERARCHY_TREE') return _drive_handleHierarchyTree(uqo);
  if (protocol === 'ATOM_READ')      return _drive_handleAtomRead(uqo);
  if (protocol === 'ATOM_CREATE')    return _drive_handleAtomCreate(uqo);
  if (protocol === 'ATOM_UPDATE')    return _drive_handleAtomUpdate(uqo);
  if (protocol === 'TABULAR_UPDATE') return _drive_handleTabularUpdate(uqo); // Sintonía Axial v17.6
  if (protocol === 'SEARCH_DEEP')    return _drive_handleSearchDeep(uqo);
  if (protocol === 'TRANSFER_HANDSHAKE') return _drive_handleTransferHandshake(uqo);
  if (protocol === 'MEDIA_RESOLVE')   return _drive_handleMediaResolve(uqo);
  if (protocol === 'MEDIA_UPLOAD')    return _drive_handleMediaUpload(uqo);

  const err = createError('PROTOCOL_NOT_FOUND',
    `El Silo "Drive" no soporta el protocolo: "${protocol}".`
  );
  return { items: [], metadata: { status: 'ERROR', error: err.message, code: err.code } };
}

// ─── HANDLERS POR PROTOCOLO ───────────────────────────────────────────────────

/**
 * HIERARCHY_TREE: Lista los contenidos de una carpeta de Drive.
 * context_id = "ROOT"   → carpeta raíz del usuario.
 * context_id = folderId → subcarpeta específica.
 *
 * @private
 */
function _drive_handleHierarchyTree(uqo) {
  try {
    const contextId = uqo.context_id || 'ROOT';
    const folder = _drive_resolveFolder(contextId);

    if (!folder) {
      const err = createError('NOT_FOUND', `Carpeta "${contextId}" no encontrada.`);
      return { items: [], metadata: { status: 'ERROR', error: err.message } };
    }

    const items = [];
    const cursor = uqo.query && uqo.query.cursor ? uqo.query.cursor : null;
    const providerId = uqo.provider;

    // ── Listar subcarpetas primero (convención de explorador de archivos)
    const foldersIter = folder.getFolders();
    if (cursor) {
      // Si hay cursor, usar continuación de paginación
      try { foldersIter.setPageToken(cursor); } catch (e) { /* GAS no siempre soporta esto */ }
    }

    let count = 0;
    while (foldersIter.hasNext() && count < DRIVE_PAGE_SIZE_) {
      const subFolder = foldersIter.next();
      items.push(_drive_folderToAtom(subFolder, providerId));
      count++;
    }

    // ── Listar archivos
    const filesIter = folder.getFiles();
    while (filesIter.hasNext() && count < DRIVE_PAGE_SIZE_) {
      const file = filesIter.next();
      const atom = _drive_fileToAtom(file, providerId, false);
      if (atom) {
        items.push(atom);
        count++;
      }
    }

    const hasMore = foldersIter.hasNext() || filesIter.hasNext();
    const nextCursor = hasMore ? _drive_extractCursor(foldersIter, filesIter) : null;

    // ── Calculate Hood Categorization
    const hoodCounts = {
      ROUTES: items.filter(i => i.system_hood === 'ROUTES').length,
      STRUCTURE: items.filter(i => i.system_hood === 'STRUCTURE').length,
      PHENOTYPE: items.filter(i => i.system_hood === 'PHENOTYPE').length
    };

    return {
      items,
      metadata: {
        status: 'OK',
        has_more: hasMore,
        next_cursor: nextCursor,
        sync_status: hasMore ? 'RESONATING' : 'COMPLETE',
        hood_counts: hoodCounts,
        context: { folder_id: contextId, folder_name: folder.getName() },
      },
    };

  } catch (err) {
    logError('[provider_drive] Error en hierarchy_tree.', err);
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }
}

/**
 * ATOM_READ: Lee metadatos de un archivo específico de Drive.
 * context_id = fileId de Drive.
 *
 * @private
 */
function _drive_handleAtomRead(uqo) {
  const contextId = uqo.context_id;
  const query = uqo.query || {};

  // AXIOMA DE RESOLUCIÓN SOBERANA: Si no tenemos ID, intentamos resolver por nombre y padre (Navegación Relativa)
  if (!contextId) {
    if (query.name && query.parentId) {
      logInfo(`[provider_drive] Resolviendo átomo por nombre: "${query.name}" en padre: ${query.parentId}`);
      try {
        const parent = _drive_resolveFolder(query.parentId);
        if (!parent) throw new Error("Carpeta padre no existe.");
        
        const files = parent.getFilesByName(query.name);
        if (files.hasNext()) {
          const file = files.next();
          return { items: [_drive_fileToAtom(file, uqo.provider, true)], metadata: { status: 'OK', resolution: 'BY_NAME' } };
        }
        
        const folders = parent.getFoldersByName(query.name);
        if (folders.hasNext()) {
          const folder = folders.next();
          return { items: [_drive_folderToAtom(folder, uqo.provider)], metadata: { status: 'OK', resolution: 'BY_NAME' } };
        }

        return { items: [], metadata: { status: 'OK', message: 'No se encontró el elemento por nombre.', items: [] } };
      } catch (e) {
        logWarn(`[provider_drive] Fallo en resolución relativa: ${e.message}`);
      }
    }
    
    const err = createError('INVALID_INPUT', 'ATOM_READ requiere context_id o (query.name + query.parentId).');
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }
  try {
    // Intentar como archivo primero, luego como carpeta
    let atom = null;
    try {
      const file = DriveApp.getFileById(contextId);
      if (file.isTrashed()) throw new Error("TRASHED"); 

      // AXIOMA DE SINCERIDAD (v10.9): Si es un manifiesto de Indra, escalar a la carpeta padre
      const fileName = file.getName();
      if (fileName === 'manifest.json' || fileName === 'manifest.indra') {
        logInfo(`[IDENTITY_SOVEREIGNTY] Manifest detectado. Escalando a carpeta padre.`);
        const parent = file.getParents().next();
        return { items: [_drive_folderToAtom(parent, uqo.provider)], metadata: { status: 'OK', role: 'WORKSPACE_FOLDER' } };
      }

      atom = _drive_fileToAtom(file, uqo.provider, true);
    } catch (e) {
      // No es un archivo o está en papelera — intentar como carpeta
      try {
        const folder = DriveApp.getFolderById(contextId);
        if (folder.isTrashed()) throw new Error("TRASHED");
        atom = _drive_folderToAtom(folder, uqo.provider);
      } catch (e2) {
        const err = createError('NOT_FOUND', `Elemento "${contextId}" no encontrado.`);
        return { items: [], metadata: { status: 'ERROR', error: err.message, code: 'NOT_FOUND' } };
      }
    }

    return { items: atom ? [atom] : [], metadata: { status: 'OK' } };

  } catch (err) {
    logError('[provider_drive] Error en atom_read.', err);
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }
}

/**
 * ATOM_CREATE: Crea una carpeta o un archivo en Drive.
 * data.name           → nombre del elemento (requerido).
 * context_id          → ID de la carpeta padre (opcional, default: ROOT).
 * data.file_base64    → contenido del archivo en base64 (opcional, si existe crea archivo, si no carpeta)
 * data.mime_type      → tipo mime (opcional, requerido si hay file_base64)
 *
 * @private
 */
function _drive_handleAtomCreate(uqo) {
  const data = uqo.data || {};
  
  // AXIOMA DE FLUJO: Si venimos de un paso anterior en el workflow, resolvemos del array de items.
  const source = (data.items && data.items.length > 0) ? data.items[0] : data;

  const label = source.handle?.label || source.name || source.file_name || '';
  if (!label || typeof label !== 'string' || label.trim() === '') {
    const err = createError('INVALID_INPUT', 'ATOM_CREATE requiere data.name o datos del paso anterior.');
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }

  try {
    const parentFolder = _drive_resolveFolder(uqo.context_id || 'ROOT');
    if (!parentFolder) {
      const err = createError('NOT_FOUND', `Carpeta padre "${uqo.context_id}" no encontrada.`);
      return { items: [], metadata: { status: 'ERROR', error: err.message } };
    }

    let atom;
    if (source.file_base64) {
      // ── MODO ARCHIVO: Crear archivo a partir de Base64 (Axioma de Transporte)
      const mimeType = source.mime_type || 'application/octet-stream';
      const decoded = Utilities.base64Decode(source.file_base64);
      const blob = Utilities.newBlob(decoded, mimeType, label.trim());
      const newFile = parentFolder.createFile(blob);
      atom = _drive_fileToAtom(newFile, uqo.provider, false);
      logInfo(`[provider_drive] Archivo generado: "${label}" (${mimeType}) en "${parentFolder.getName()}"`);
    } else if (source.class === 'TABULAR') {
      // ── DELEGACIÓN: El motor de Sheets ahora es el responsable de esto.
      throw createError('SOVEREIGN_VIOLATION', 'Para crear tablas use el provider "sheets". Drive ya no gestiona materia prima tabular nativa.');
    } else if (source.class === 'DATA_SCHEMA') {
      // ── MODO SEMILLA: Crear archivo JSON de esquema puro (Axioma de Sinceridad)
      const fileName = `${label.trim()}.json`;
      const content = JSON.stringify(source, null, 2);
      const newFile = parentFolder.createFile(fileName, content, 'application/json');
      atom = _drive_fileToAtom(newFile, uqo.provider, false);
      logInfo(`[provider_drive] Semilla de ADN materializada: "${fileName}" en artifacts.`);
    } else if (source.class === 'DOCUMENT' && source.intent === 'TRANSFER') {
      // ── MODO TRANSFERENCIA: Emitir Handshake para el Cliente
      return _drive_handleTransferHandshake({ 
        ...uqo, 
        data: { 
          filename: label, 
          mimeType: source.mime_type || 'application/octet-stream',
          parent_id: uqo.context_id 
        } 
      });
    } else {
      // ── MODO CARPETA: Comportamiento original
      const newFolder = parentFolder.createFolder(label.trim());
      atom = _drive_folderToAtom(newFolder, uqo.provider);
      logInfo(`[provider_drive] Carpeta creada: "${label}" en "${parentFolder.getName()}"`);
    }

    return { 
      items: [atom], 
      metadata: { 
        status: 'OK',
        silo_url: atom.raw?.url || file.getUrl(),
        physical_id: file.getId()
      } 
    };

  } catch (err) {
    logError('[provider_drive] Error en atom_create.', err);
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }
}

/**
 * ATOM_UPDATE: Actualiza metadatos de un archivo o carpeta en Drive.
 * context_id → ID del elemento (file o folder).
 * data.name  → Nuevo nombre (opcional).
 * data.description → Nueva descripción (opcional).
 *
 * @private
 */
function _drive_handleAtomUpdate(uqo) {
  if (!uqo.context_id) {
    const err = createError('INVALID_INPUT', 'ATOM_UPDATE requiere context_id.');
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }

  const data = uqo.data || {};

  try {
    let element = null;
    try {
      element = DriveApp.getFileById(uqo.context_id);
    } catch (e) {
      element = DriveApp.getFolderById(uqo.context_id);
    }

    const label = data.handle?.label || data.name;
    if (label) {
      logInfo(`[provider_drive] Renombrando ${uqo.context_id} a "${label}"`);
      element.setName(label);
    }

    if (data.description !== undefined) {
      element.setDescription(data.description);
    }

    // Retornar el átomo actualizado
    const updatedAtom = (element.getMimeType && element.getMimeType() === 'application/vnd.google-apps.folder')
      ? _drive_folderToAtom(element, uqo.provider)
      : _drive_fileToAtom(element, uqo.provider);

    return { items: [updatedAtom], metadata: { status: 'OK' } };

  } catch (err) {
    logError('[provider_drive] Error en ATOM_UPDATE.', err);
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }
}

/**
 * ATOM_DELETE: Mueve un archivo/carpeta a la papelera.
 * context_id → fileId o folderId de Drive.
 *
 * @private
 */
function _drive_handleAtomDelete(uqo) {
  if (!uqo.context_id) {
    const err = createError('INVALID_INPUT', 'ATOM_DELETE requiere context_id.');
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }

  try {
    try {
      DriveApp.getFileById(uqo.context_id).setTrashed(true);
    } catch (e) {
      DriveApp.getFolderById(uqo.context_id).setTrashed(true);
    }
    logInfo(`[provider_drive] Elemento movido a papelera: ${uqo.context_id}`);
    return { items: [], metadata: { status: 'OK' } };

  } catch (err) {
    logError('[provider_drive] Error en ATOM_DELETE.', err);
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }
}

/**
 * SEARCH_DEEP: Búsqueda global en todo el Drive del usuario.
 * Usa DriveApp.searchFiles con el término de búsqueda.
 *
 * @private
 */
function _drive_handleSearchDeep(uqo) {
  try {
    const searchTerm = uqo.query && uqo.query.search_term;
    const providerId = uqo.provider;

    if (!searchTerm) {
      return { items: [], metadata: { status: 'ERROR', error: 'SEARCH_DEEP requiere uqo.query.search_term.' } };
    }

    // Google Drive search query syntax: title contains 'term'
    const driveQuery = `title contains '${searchTerm.replace(/'/g, "\\'")}' and trashed = false`;
    const filesIter = DriveApp.searchFiles(driveQuery);

    const items = [];
    let count = 0;
    while (filesIter.hasNext() && count < 50) {
      const file = filesIter.next();
      const atom = _drive_fileToAtom(file, providerId, false);
      if (atom) {
        items.push(atom);
        count++;
      }
    }

    return {
      items,
      metadata: {
        status: 'OK',
        has_more: filesIter.hasNext(),
        sync_status: filesIter.hasNext() ? 'RESONATING' : 'COMPLETE',
        total_objects: items.length // DriveApp no da total count fácilmente sin iterar todo
      },
    };

  } catch (err) {
    logError('[provider_drive] Error en SEARCH_DEEP.', err);
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }
}

// ─── CONVERSIÓN A ÁTOMO UNIVERSAL ────────────────────────────────────────────

/**
 * Convierte una carpeta de Drive a Átomo Universal canónico.
 * Las carpetas siempre tienen class: FOLDER y permiten drill-down.
 *
 * @param {DriveApp.Folder} folder
 * @returns {Object} Átomo Universal.
 * @private
 */
function _drive_folderToAtom(folder, providerId) {
  const name = folder.getName();
  return {
    id: folder.getId(),
    handle: {
      ns: 'com.drive.folder',
      alias: _system_slugify_(name) || 'folder_unnamed',
      label: name
    },
    class: 'FOLDER',
    provider: providerId,
    protocols: ['HIERARCHY_TREE', 'ATOM_READ', 'ATOM_CREATE', 'ATOM_UPDATE', 'ATOM_DELETE'],
    system_hood: 'ROUTES',
    modified_at: folder.getLastUpdated().toISOString(),
    description: folder.getDescription() || '',
    mime_type: 'application/vnd.google-apps.folder',
    payload: {},
    raw: {
      folder_id: folder.getId(),
    },
  };
}

/**
 * Convierte un archivo de Drive a Átomo Universal canónico.
 * @param {DriveApp.File} file
 * @param {string} providerId
 * @param {boolean} [includeFields=false] - Si es true, abre el archivo para extraer esquema (Lento).
 * @returns {Object|null}
 * @private
 */
function _drive_fileToAtom(file, providerId, includeFields) {
  const mimeType = file.getMimeType();

  // Excluir archivos de sistema que no son útiles para el usuario
  const EXCLUDED_MIMES = [
    'application/vnd.google-apps.script',     
    'application/vnd.google-apps.site',       
    'application/vnd.google-apps.fusiontable',
    'application/vnd.google-apps.map',        
  ];
  if (EXCLUDED_MIMES.includes(mimeType)) return null;

  const atomClass = MIME_TO_CLASS_[mimeType] || 'DOCUMENT';
  const atomProtos = MIME_TO_PROTOCOLS_[mimeType] || ['ATOM_READ'];
  const name = file.getName();

  const payload = {};
  // ADR-008: Solo extraemos esquema si se solicita (ATOM_READ) para evitar lentitud en listados.
  if (includeFields && atomClass === 'TABULAR' && mimeType === 'application/vnd.google-apps.spreadsheet') {
    try {
      payload.fields = _drive_spreadsheetToFields(file);
    } catch (e) {
      logWarn(`[provider_drive] Error extrayendo esquema de Sheet ${file.getId()}: ${e.message}`);
      payload.fields = [];
    }
  }
  
  // ADR-0XX: Extracción de ADN Puro para Esquemas JSON
  if (includeFields && mimeType === 'application/json') {
      try {
          payload.content = file.getBlob().getDataAsString();
      } catch (e) {
          logWarn(`[provider_drive] Error leyendo contenido JSON: ${e.message}`);
      }
  }

  // ADR-023: Si el archivo es una imagen, construir el tipo INDRA_MEDIA canónico.
  if (mimeType && mimeType.startsWith('image/')) {
    const fileId = file.getId();
    payload.media = {
      type: 'INDRA_MEDIA',
      storage: 'drive',
      // URL de thumbnail/visualización: funciona para archivos compartidos (ver ADR-023 §Riesgos)
      canonical_url: `https://lh3.googleusercontent.com/d/${fileId}`,
      file_id: fileId,
      mime_type: mimeType,
      expires_at: null // Drive no tiene URLs temporales — es permanente si el archivo está compartido
    };
  }

  return {
    id: file.getId(),
    handle: {
      ns: `com.drive.${atomClass.toLowerCase()}`,
      alias: _system_slugify_(name) || 'file_unnamed',
      label: name
    },
    class: atomClass,
    provider: providerId,
    protocols: atomProtos,
    system_hood: mimeType === 'application/vnd.google-apps.spreadsheet' ? 'STRUCTURE' : 'PHENOTYPE',
    modified_at: file.getLastUpdated().toISOString(),
    size: mimeType.startsWith('application/vnd.google-apps') ? 0 : file.getSize(),
    mime_type: mimeType,
    description: file.getDescription() || '',
    payload: payload,
    raw: {
      url: file.getUrl(),
    },
  };
}

// ─── UTILIDADES INTERNAS ──────────────────────────────────────────────────────

/**
 * Resuelve un contextId a una carpeta de Drive.
 * "ROOT" → carpeta raíz del usuario.
 * Cualquier otro string → intenta como folderId.
 *
 * @param {string} contextId
 * @returns {DriveApp.Folder|null}
 * @private
 */
function _drive_resolveFolder(contextId) {
  try {
    if (!contextId || contextId === 'ROOT') {
      return DriveApp.getRootFolder();
    }
    return DriveApp.getFolderById(contextId);
  } catch (err) {
    logWarn(`[provider_drive] Carpeta no encontrada: ${contextId}. Error: ${err.message}`);
    return null;
  }
}

/**
 * Intenta extraer un cursor de paginación de los iteradores de Drive.
 * GAS no expone el cursor directamente — este es un placeholder para
 * cuando GAS mejore su API de paginación.
 *
 * @param {FolderIterator} foldersIter
 * @param {FileIterator}   filesIter
 * @returns {null} Siempre null en GAS (paginación manual no soportada nativamente)
 * @private
 */
function _drive_extractCursor(foldersIter, filesIter) {
  // GAS no soporta cursores nombrados en DriveApp.
  // La paginación en HIERARCHY_TREE está limitada a DRIVE_PAGE_SIZE_ por request.
  // Implementar paginación manual requeriría almacenar offset en UQO.query.
  return null;
}

/**
 * TABULAR_STREAM: [ELIMINADO] Delegado al motor de Sheets soberano.
 */

// =============================================================================
// ADR-024: UNIVERSAL MEDIA RESOLVER
// =============================================================================

/**
 * MEDIA_RESOLVE: Handler universal agnóstico a provider.
 * Soporta tres estrategias: BY_ID, BY_NAME_IN_CONTAINER, DIRECT_URL.
 * Retorna siempre INDRA_MEDIA canónico.
 *
 * @private
 */
function _drive_handleMediaResolve(uqo) {
  const strategy = uqo.data?.strategy || 'BY_ID';
  const data = uqo.data || {};

  try {
    switch (strategy) {
      case 'BY_ID':
        return _drive_mediaResolveByID(data.asset_id, uqo.provider);
      
      case 'BY_NAME_IN_CONTAINER':
        return _drive_mediaResolveByNameInContainer(data.container_ref, data.asset_name, uqo.provider);
      
      case 'DIRECT_URL':
        return _drive_mediaResolveDirectUrl(data.asset_id, uqo.provider);
      
      default:
        return {
          items: [],
          metadata: { status: 'ERROR', error: `Estrategia desconocida: ${strategy}`, code: 'INVALID_STRATEGY' }
        };
    }
  } catch (err) {
    logError('[provider_drive] Error en MEDIA_RESOLVE.', err);
    return { items: [], metadata: { status: 'ERROR', error: err.message, code: 'MEDIA_RESOLVE_ERROR' } };
  }
}

/**
 * MEDIA_RESOLVE - BY_ID: Resuelve un archivo por su File ID.
 * @private
 */
function _drive_mediaResolveByID(fileId, providerId) {
  if (!fileId) {
    return {
      items: [],
      metadata: { status: 'ERROR', error: 'BY_ID requiere asset_id', code: 'MISSING_ASSET_ID' }
    };
  }

  try {
    const file = DriveApp.getFileById(fileId);
    const mimeType = file.getMimeType();
    const atom = _drive_buildMediaAtom(file, providerId);
    return { items: [atom], metadata: { status: 'OK', strategy_used: 'BY_ID' } };
  } catch (err) {
    return {
      items: [],
      metadata: { status: 'ERROR', error: `Archivo no encontrado: ${fileId}`, code: 'NOT_FOUND' }
    };
  }
}

/**
 * MEDIA_RESOLVE - BY_NAME_IN_CONTAINER: Resuelve archivo por nombre en una carpeta.
 * Política de Determinismo: último modificado (modified_at DESC).
 * Falla Transparente: si cero matches, retorna error claro sin fallback.
 *
 * @private
 */
function _drive_mediaResolveByNameInContainer(folderId, fileName, providerId) {
  if (!folderId || !fileName) {
    return {
      items: [],
      metadata: { status: 'ERROR', error: 'BY_NAME_IN_CONTAINER requiere container_ref y asset_name', code: 'MISSING_PARAMS' }
    };
  }

  try {
    const folder = DriveApp.getFolderById(folderId);
    const files = folder.getFilesByName(fileName);
    const candidates = [];

    while (files.hasNext()) {
      const file = files.next();
      const mimeType = file.getMimeType();
      // Solo filtrar imágenes (o dejar pasar cualquier mime_type si el cliente especificó hint)
      if (mimeType.startsWith('image/')) {
        candidates.push(file);
      }
    }

    if (candidates.length === 0) {
      return {
        items: [],
        metadata: { status: 'ERROR', error: `No se encontró imagen con nombre: ${fileName}`, code: 'NO_MATCH', strategy: 'BY_NAME_IN_CONTAINER' }
      };
    }

    // Determinar el "último modificado" 
    candidates.sort((a, b) => b.getLastUpdated().getTime() - a.getLastUpdated().getTime());
    const selected = candidates[0];

    const atom = _drive_buildMediaAtom(selected, providerId);
    logInfo(`[provider_drive] MEDIA_RESOLVE BY_NAME: "${fileName}" en folder "${folder.getName()}" → ${selected.getId()}`);

    return { items: [atom], metadata: { status: 'OK', strategy_used: 'BY_NAME_IN_CONTAINER' } };

  } catch (err) {
    return {
      items: [],
      metadata: { status: 'ERROR', error: `Error resolviendo en carpeta: ${err.message}`, code: 'CONTAINER_ERROR' }
    };
  }
}

/**
 * MEDIA_RESOLVE - DIRECT_URL: Valida que asset_id sea una URL válida.
 * Retorna como INDRA_MEDIA con storage="url".
 *
 * @private
 */
function _drive_mediaResolveDirectUrl(url, providerId) {
  if (!url) {
    return {
      items: [],
      metadata: { status: 'ERROR', error: 'DIRECT_URL requiere asset_id (HTTP URL)', code: 'MISSING_URL' }
    };
  }

  // Validar formato URL básico
  if (!/^https?:\/\/.+/i.test(url.trim())) {
    return {
      items: [],
      metadata: { status: 'ERROR', error: `URL inválida: ${url}`, code: 'INVALID_URL_FORMAT' }
    };
  }

  // Construir átomo para URL externa
  const mediaAtom = {
    id: url,  // Usar URL como ID único
    handle: {
      ns: 'com.indra.media',
      alias: _system_slugify_('external_url') || 'external_media',
      label: 'External URL'
    },
    class: 'MEDIA',
    provider: providerId || 'system',
    protocols: ['ATOM_READ'],
    payload: {
      media: {
        type: 'INDRA_MEDIA',
        storage: 'url',
        canonical_url: url,
        file_id: null,
        mime_type: 'image/*',  // Sin verificación MIME para URLs externas
        expires_at: null  // URLs externas asumidas permanentes
      }
    }
  };

  logInfo(`[provider_drive] MEDIA_RESOLVE DIRECT_URL: ${url}`);
  return { items: [mediaAtom], metadata: { status: 'OK', strategy_used: 'DIRECT_URL' } };
}

/**
 * Helper privado: Construir INDRA_MEDIA atom a partir de un Google Drive File object.
 * @private
 */
function _drive_buildMediaAtom(file, providerId) {
  const fileId = file.getId();
  const mimeType = file.getMimeType();
  const name = file.getName();

  // Construir URL canónica según mime type
  let canonicalUrl;
  if (mimeType.startsWith('image/')) {
    canonicalUrl = `https://lh3.googleusercontent.com/d/${fileId}`;
  } else if (mimeType === 'application/pdf') {
    canonicalUrl = `https://drive.google.com/file/d/${fileId}/view`;
  } else {
    canonicalUrl = file.getDownloadUrl();
  }

  const mediaAtom = {
    id: fileId,
    handle: {
      ns: 'com.indra.media',
      alias: _system_slugify_(name) || 'drive_media_file',
      label: name
    },
    class: 'MEDIA',
    provider: providerId || 'drive',
    protocols: ['ATOM_READ'],
    mime_type: mimeType,
    payload: {
      media: {
        type: 'INDRA_MEDIA',
        storage: 'drive',
        canonical_url: canonicalUrl,
        file_id: fileId,
        mime_type: mimeType,
        expires_at: null  // Drive URLs son permanentes si archivo compartido
      }
    }
  };

  return mediaAtom;
}

/**
 * TRANSFER_HANDSHAKE: Genera una sesión de subida resumible en Google Drive.
 * ADR-025: Inteligencia Multimodal Adaptativa.
 * @private
 */
function _drive_handleTransferHandshake(uqo) {
  const data = uqo.data || {};
  const filename = data.filename || data.name || 'Untitled';
  const mimeType = data.mimeType || 'application/octet-stream';
  
  // AXIOMA DE UBICACIÓN: Prioridad al context_id del UQO (Aduana) sobre el campo de datos.
  let parentId = uqo.context_id || data.parent_id || 'root';
  if (parentId === 'ROOT') parentId = 'root'; // Normalización para API v3

  logInfo(`[provider_drive] Negociando Handshake para: ${filename} en padre: ${parentId}`);

  try {
    const url = "https://www.googleapis.com/upload/drive/v3/files?uploadType=resumable";
    const options = {
      method: "post",
      contentType: "application/json",
      headers: { Authorization: "Bearer " + ScriptApp.getOAuthToken() },
      payload: JSON.stringify({
        name: filename,
        parents: [parentId],
        mimeType: mimeType
      }),
      muteHttpExceptions: true
    };
    
    const response = UrlFetchApp.fetch(url, options);
    const uploadUrl = response.getHeaders()["Location"];

    if (!uploadUrl) throw new Error("Google Drive denegó la creación de sesión resumible.");

    return { 
      metadata: { 
        status: 'HANDSHAKE_READY', 
        transfer_protocol: 'GOOGLE_RESUMABLE',
        upload_url: uploadUrl,
        intent: 'TRANSFER'
      } 
    };
  } catch (err) {
    logError('[provider_drive] Fallo en Transfer Handshake.', err);
    return { metadata: { status: 'ERROR', error: err.message } };
  }
}

/**
 * TABULAR_UPDATE (DRIVE): Procesa múltiples acciones de escritura en el Silo de Archivos.
 * @private
 */
function _drive_handleTabularUpdate(uqo) {
  const { silo_id, actions } = uqo.data || {};
  if (!silo_id || !Array.isArray(actions)) {
    throw createError('INVALID_INPUT', 'TABULAR_UPDATE requiere silo_id y un array de acciones.');
  }

  logInfo(`[provider_drive] Iniciando TABULAR_UPDATE en Silo: ${silo_id}. Acciones: ${actions.length}`);

  try {
    const file = DriveApp.getFileById(silo_id);
    if (file.getMimeType() !== MimeType.GOOGLE_SHEETS) {
       logInfo(`[provider_drive] El silo ${silo_id} no es una hoja de cálculo. Ignorando actualización tabular.`);
       return { items: [], metadata: { status: 'OK', message: 'Silo is not a spreadsheet' } };
    }

    const ss = SpreadsheetApp.openById(silo_id);
    const sheet = ss.getSheets()[0]; 
    const headers = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
    const results = [];

    actions.forEach(action => {
      if (action.type === 'CREATE' || action.type === 'UPDATE') {
        const rowData = headers.map(h => action.data[h] !== undefined ? action.data[h] : '');

        if (action.type === 'CREATE') {
          sheet.appendRow(rowData);
          results.push({ id: action.id, status: 'CREATED' });
        } else {
          const ids = sheet.getRange(1, 1, Math.max(1, sheet.getLastRow()), 1).getValues();
          let rowIndex = -1;
          for(let i=0; i<ids.length; i++) {
            if (String(ids[i][0]) === String(action.id)) { rowIndex = i + 1; break; }
          }
          
          if (rowIndex > 0) {
            sheet.getRange(rowIndex, 1, 1, rowData.length).setValues([rowData]);
            results.push({ id: action.id, status: 'UPDATED' });
          } else {
            sheet.appendRow(rowData);
            results.push({ id: action.id, status: 'CREATED_ON_UPDATE' });
          }
        }
      }
    });

    return {
      items: results,
      metadata: {
        status: 'OK',
        silo_id: silo_id,
        actions_executed: actions.length,
        trace: uqo.trace_id
      }
    };
  } catch (err) {
    logError('[provider_drive] Fallo en TABULAR_UPDATE.', err);
    return { items: [], metadata: { status: 'ERROR', error: err.message, code: 'TABULAR_EXECUTION_FAILED' } };
  }
}

2_providers.provider_google_calendar.gs:
// =============================================================================
// ARTEFACTO: 2_providers/provider_google_calendar.gs
// CAPA: 2 — Provider Layer (Silo Nativo)
// RESPONSABILIDAD: Gestión de Google Calendar vía Protocolos Canónicos ATOM.
// =============================================================================

/**
 * @dharma MANIFIESTO DEL SILO (CANÓNICO v16.2)
 */
function CONF_GOOGLE_CALENDAR() {
  return {
    id: 'google_calendar',
    class: 'SILO',
    handle: {
      label: 'Google Calendar',
      icon: 'CALENDAR',
      entry_point: 'primary'
    },
    capabilities: {
      'ATOM_READ': { handler: 'handleGoogleCalendar' },
      'ATOM_CREATE': { handler: 'handleGoogleCalendar' },
      'ATOM_UPDATE': { handler: 'handleGoogleCalendar' },
      'ATOM_DELETE': { handler: 'handleGoogleCalendar' },
      'ATOM_DISCOVER': { handler: 'handleGoogleCalendar' }
    },
    config_schema: [], 
    protocol_meta: {
      is_temporal: true,
      supported_classes: ['CALENDAR_EVENT', 'CALENDAR_MANIFEST']
    }
  };
}

/**
 * Orquestador Canónico de Calendario.
 */
function handleGoogleCalendar(uqo) {
  const { protocol, context_id, data } = uqo;

  logInfo(`📅 [GCal:Native] Axioma Protocolar: ${protocol}`);

  // Normalización del contexto (Entry Point)
  const calendarId = context_id || 'primary';

  switch (protocol) {
    case 'ATOM_DISCOVER':
      return _googleCalendar_Discover();

    case 'ATOM_READ':
      return _googleCalendar_Read(calendarId, data);

    case 'ATOM_CREATE':
      return _googleCalendar_Create(calendarId, data);

    case 'ATOM_UPDATE':
      return _googleCalendar_Update(calendarId, data);

    case 'ATOM_DELETE':
      return _googleCalendar_Delete(calendarId, data);

    default:
      throw new Error(`PROTOCOL_NOT_SUPPORTED_BY_PROVIDER: ${protocol}`);
  }
}

// --- IMPLEMENTACIÓN CANÓNICA (FÍSICA) ---

function _googleCalendar_Discover() {
  const calendars = CalendarApp.getAllCalendars();
  return {
    items: calendars.map(cal => ({
      id: cal.getId(),
      class: 'CALENDAR_MANIFEST',
      handle: {
        alias: cal.getName().toLowerCase().replace(/\s/g, '_'),
        label: cal.getName(),
        is_primary: cal.isMyPrimaryCalendar()
      },
      payload: { 
        description: cal.getDescription(),
        color: cal.getColor()
      }
    })),
    metadata: { status: 'OK' }
  };
}

function _googleCalendar_Read(calendarId, data) {
  const cal = CalendarApp.getCalendarById(calendarId);
  const start = data.start ? new Date(data.start) : new Date();
  const end = data.end ? new Date(data.end) : new Date(Date.now() + 86400000);

  const events = cal.getEvents(start, end);

  return {
    items: events.map(ev => ({
      id: ev.getId(),
      class: 'CALENDAR_EVENT',
      handle: { label: ev.getTitle() },
      payload: {
        description: ev.getDescription(),
        location: ev.getLocation(),
        start: ev.getStartTime().toISOString(),
        end: ev.getEndTime().toISOString(),
        colorId: ev.getColor(),
        attendees: ev.getGuestList().map(g => g.getEmail())
      }
    })),
    metadata: { status: 'OK', count: events.length }
  };
}

function _googleCalendar_Create(calendarId, data) {
  const cal = CalendarApp.getCalendarById(calendarId);

  const options = {
    description: data.description || '',
    location: data.location || '',
    guests: (data.attendees || []).join(','),
    sendInvites: data.sendInvites || false
  };

  const event = cal.createEvent(
    data.title || 'Nuevo Evento Indra', 
    new Date(data.start), 
    new Date(data.end), 
    options
  );

  if (data.colorId) event.setColor(data.colorId);

  return {
    items: [{ id: event.getId(), class: 'CALENDAR_EVENT', handle: { label: event.getTitle() } }],
    metadata: { status: 'OK' }
  };
}

function _googleCalendar_Update(calendarId, data) {
  const eventId = data.id || data.event_id;
  const cal = CalendarApp.getCalendarById(calendarId);
  const event = cal.getEventById(eventId);

  if (!event) throw new Error(`EVENT_NOT_FOUND: ${eventId}`);

  if (data.title) event.setTitle(data.title);
  if (data.description) event.setDescription(data.description);
  if (data.start && data.end) event.setTime(new Date(data.start), new Date(data.end));
  if (data.colorId) event.setColor(data.colorId);

  return {
    items: [{ id: event.getId(), class: 'CALENDAR_EVENT', handle: { label: event.getTitle() } }],
    metadata: { status: 'OK' }
  };
}

function _googleCalendar_Delete(calendarId, data) {
  const eventId = data.id || data.event_id;
  const cal = CalendarApp.getCalendarById(calendarId);
  const event = cal.getEventById(eventId);
  if (event) event.deleteEvent();

  return {
    items: [{ id: eventId, status: 'DELETED' }],
    metadata: { status: 'OK' }
  };
}

2_providers.provider_intelligence.gs:
/**
 * =============================================================================
 * ARTEFACTO: 2_providers/provider_intelligence.gs
 * RESPONSABILIDAD: El Oráculo del Core. Bridge hacia modelos de lenguaje (LLMs).
 * DHARMA: 
 *   - Universalidad: Soporta cualquier API compatible con OpenAI.
 *   - Sinceridad: Traduce el lenguaje natural a directivas MCEP sinceras.
 * =============================================================================
 */

/**
 * Manifestación del Silo de Inteligencia.
 */
function CONF_INTELLIGENCE() {
  return Object.freeze({
    id: 'intelligence',
    handle: { ns: 'com.indra.system.ai', alias: 'oracle', label: 'Indra Intelligence', icon: 'COGNITIVE' },
    class: 'COGNITIVE_ENGINE',
    version: '1.1 (Synthesis)',
    capabilities: {
      INTELLIGENCE_CHAT: { sync: 'BLOCKING', exposure: 'public', handler: 'handleIntelligence' },
      INTELLIGENCE_DISCOVERY: { sync: 'BLOCKING', exposure: 'public', handler: 'handleIntelligence' }
    },
    config_schema: [
      { id: 'default_provider', label: 'Proveedor por Defecto', type: 'TEXT', default: 'gemini' },
      { id: 'custom_base_url', label: 'URL Base (OpenAI Compatible)', type: 'TEXT' }
    ]
  });
}

/**
 * Router de Segundo Nivel para Inteligencia.
 */
function handleIntelligence(uqo) {
  const protocol = (uqo.protocol || '').toUpperCase();

  if (protocol === 'INTELLIGENCE_CHAT') return _ai_handleChat(uqo);
  if (protocol === 'INTELLIGENCE_DISCOVERY') return _ai_handleDiscovery(uqo);
  if (protocol === 'GETMCEPMANIFEST') return _ai_handleDiscovery(uqo); // Alias para el frontend

  throw createError('PROTOCOL_NOT_FOUND', `Intelligence no soporta: ${protocol}`);
}

/**
 * INTELLIGENCE_CHAT: Bridge hacia LLMs.
 */
function _ai_handleChat(uqo) {
  const data = uqo.data || {};
  const { prompt, history = [], systemInstruction, model, provider, credentials, baseUrl, tools = [] } = data;

  if (!prompt) throw createError('INVALID_INPUT', 'Falta el prompt para la IA.');

  const targetProvider = provider || 'gemini';
  const apiKey = credentials || readProviderApiKey('intelligence', 'default');

  try {
    let resultPayload;

    if (targetProvider === 'gemini') {
        resultPayload = _chatGemini(prompt, history, systemInstruction, apiKey, model, tools);
    } else if (targetProvider === 'groq' || targetProvider === 'grok' || targetProvider === 'openai' || targetProvider === 'custom') {
        const effectiveBaseUrl = baseUrl || (targetProvider === 'groq' ? 'https://api.groq.com/openai/v1' : 
                                            targetProvider === 'grok' ? 'https://api.x.ai/v1' : 
                                            targetProvider === 'openai' ? 'https://api.openai.com/v1' : null);
        resultPayload = _chatOpenAICompatible(prompt, history, systemInstruction, apiKey, model, effectiveBaseUrl, tools);
    } else {
        throw createError('PROVIDER_NOT_SUPPORTED', `Proveedor de IA no soportado: ${targetProvider}`);
    }

    return {
      items: [{
        id: `ai_${Date.now()}`,
        handle: { ns: 'com.indra.ai.response', alias: 'chat_response', label: 'Respuesta de IA' },
        class: 'AI_MESSAGE',
        protocols: ['ATOM_READ'],
        response: resultPayload.text || '', // legacy fallback
        payload: resultPayload
      }],
      metadata: { status: 'OK', response: resultPayload }
    };

  } catch (e) {
    logError(`[intelligence] Fallo en chat (${targetProvider}):`, e);
    throw e;
  }
}

/**
 * INTELLIGENCE_DISCOVERY: Genera el mapa de capacidades para el Agente.
 */
function _ai_handleDiscovery(uqo) {
  const mode = uqo.data?.mode || 'RAW_MAP';
  const registry = buildManifest(); // Obtiene todos los providers registrados
  const capabilities = {};

  registry.items.forEach(item => {
    const providerId = item.provider_base;
    if (capabilities[providerId]) return;

    const conf = getProviderConf(providerId);
    if (!conf) return;

    capabilities[providerId] = {
      label: conf.handle?.label || providerId,
      description: conf.description || `Módulo de ${providerId}`,
      tools: {}
    };

    // Mapear protocolos a herramientas para el LLM
    Object.keys(conf.implements || {}).forEach(proto => {
        const cap = conf.capabilities && conf.capabilities[proto];
        if (cap && cap.exposure === 'internal') return; // No exponer herramientas internas

        capabilities[providerId].tools[proto] = {
            desc: (conf.protocol_meta && conf.protocol_meta[proto]?.desc) || `Ejecuta el protocolo ${proto} en el motor ${providerId}.`,
            inputs: (conf.protocol_meta && conf.protocol_meta[proto]?.inputs) || {}
        };
    });
  });

  return {
    items: [],
    metadata: { 
        status: 'OK', 
        capabilities: capabilities 
    }
  };
}

/**
 * Connector: Google Gemini
 */
function _chatGemini(prompt, history, systemInstruction, apiKey, model, tools) {
  const url = `https://generativelanguage.googleapis.com/v1beta/models/${model || 'gemini-1.5-flash'}:generateContent?key=${apiKey}`;

  // Normalizar historial al formato Gemini: { role: 'user'|'model', parts: [{text}] }
  const historyContents = (history || []).map(msg => {
    if (msg.role === 'tool') {
       return { role: 'user', parts: [{ text: `[SYSTEM_RESULT_FOR_${msg.name}]: ${msg.content}` }] }; // Mocking tool responses for Gemini simplicity
    }
    const text = msg.content || msg.text || (msg.parts && msg.parts[0]?.text) || '';
    const role = (msg.role === 'assistant' || msg.role === 'model') ? 'model' : 'user';
    return { role, parts: [{ text }] };
  }).filter(m => m.parts && m.parts[0] && m.parts[0].text && m.parts[0].text.trim() !== '');

  const contents = [
    ...historyContents,
    { role: 'user', parts: [{ text: prompt }] }
  ];

  const body = {
    contents,
    generationConfig: { maxOutputTokens: 2048, temperature: 0.7 }
  };

  if (systemInstruction) {
    body.systemInstruction = { parts: [{ text: systemInstruction }] };
  }

  // Inject Native Tools if provided
  if (tools && tools.length > 0) {
    body.tools = [{
      functionDeclarations: tools.map(t => ({
        name: t.function.name,
        description: t.function.description,
        parameters: {
          type: "OBJECT",
          properties: t.function.parameters.properties || {},
          required: t.function.parameters.required || []
        }
      }))
    }];
  }

  const options = {
    method: 'post',
    contentType: 'application/json',
    payload: JSON.stringify(body),
    muteHttpExceptions: true
  };

  const response = UrlFetchApp.fetch(url, options);
  const json = JSON.parse(response.getContentText());

  if (json.error) {
    throw new Error(`Gemini API Error: ${json.error.message}`);
  }

  const part = json.candidates[0].content.parts[0];

  if (part.functionCall) {
     return {
         type: 'tool_calls',
         calls: [{
             name: part.functionCall.name,
             arguments: part.functionCall.args || {}
         }]
     };
  }

  return { type: 'message', text: part.text || '' };
}

/**
 * Connector: OpenAI Compatible (Groq, Grok, etc)
 */
function _chatOpenAICompatible(prompt, history, systemInstruction, apiKey, model, baseUrl, tools) {
  if (!baseUrl) throw new Error('Missing baseUrl for OpenAI compatible provider.');

  const url = `${baseUrl}/chat/completions`;
  const messages = [];

  if (systemInstruction) {
    messages.push({ role: 'system', content: systemInstruction });
  }

  // Normalizar historial al formato OpenAI: { role: 'user'|'assistant'|'tool', content: string }
  (history || []).forEach(msg => {
    if (msg.role === 'tool') {
        messages.push({ role: 'user', content: `[SYSTEM_RESULT_FOR_${msg.name}]: ${msg.content}` }); // Simplified tool response tracking
        return;
    }
    const text = msg.content || msg.text || (msg.parts && msg.parts[0]?.text) || '';
    if (!text.trim()) return;
    const role = (msg.role === 'model' || msg.role === 'assistant') ? 'assistant' : 'user';
    messages.push({ role, content: text });
  });

  messages.push({ role: 'user', content: prompt });

  const payload = {
    model: model || 'llama-3.3-70b-versatile',
    messages,
    temperature: 0.7
  };

  if (tools && tools.length > 0) {
      payload.tools = tools;
      payload.tool_choice = "auto";
  }

  const options = {
    method: 'post',
    headers: { 'Authorization': `Bearer ${apiKey}` },
    contentType: 'application/json',
    payload: JSON.stringify(payload),
    muteHttpExceptions: true
  };

  const response = UrlFetchApp.fetch(url, options);
  const json = JSON.parse(response.getContentText());

  if (json.error) {
    throw new Error(`AI API Error: ${json.error.message || JSON.stringify(json.error)}`);
  }

  const message = json.choices[0].message;

  if (message.tool_calls && message.tool_calls.length > 0) {
      return {
          type: 'tool_calls',
          calls: message.tool_calls.map(tc => {
              let args = {};
              try { args = JSON.parse(tc.function.arguments); } catch(e) {}
              return {
                  name: tc.function.name,
                  arguments: args
              };
          })
      };
  }

  return { type: 'message', text: message.content || '' };
}

2_providers.provider_notion.gs:
// =============================================================================
// ARTEFACTO: 2_providers/provider_notion.gs
// CAPA: 2 — Providers
// RESPONSABILIDAD: Translator from Notion to Universal Core Protocol.
//         Converts Notion page and database hierarchy into universal atoms.
//         Unique access point for the Notion REST API.
//
// DISCOVERY PROTOCOL:
//   PROVIDER_CONF_NOTION is detected by _scanProviders_().
//
// REFERENCIA API: Notion API v2022-06-28
//   POST /v1/search            → buscar páginas y databases en la raíz
//   GET  /v1/databases/{id}    → metadata de una database (schema)
//   POST /v1/databases/{id}/query → filas de una database (TABULAR_STREAM)
//   GET  /v1/blocks/{id}/children → bloques de una página (ATOM_READ)
//   POST /v1/pages             → crear página (ATOM_CREATE)
//   PATCH /v1/pages/{id}       → actualizar página (ATOM_UPDATE)
//
// AXIOMS:
//   - Classification logic resides here. Frontend receives standardized atoms.
//   - Notion database → class: TABULAR
//   - Notion page     → class: DOCUMENT
//   - _flattenProperties() maps complex Notion structures into flat objects.
//   - Pagination is translated directly to Return Law metadata.
//
// RESTRICCIONES:
//   - NO puede inferir class por nombre de página o heurísticas de contenido.
//   - NO puede persistir estado entre requests (GAS es stateless).
//   - La API Key se lee desde system_config.gs — nunca hardcodeada.
//   - La validación del token es fail-fast: si no hay API Key → ERROR inmediato.
// =============================================================================

/**
 * Configuración de auto-descubrimiento del provider notion.
 * @const {Object}
 */
/**
 * Manifestación del Silo Notion. Sigue el Protocolo ADR-002.
 * @returns {Object} Contrato de configuración.
 */
function CONF_NOTION() {
  return Object.freeze({
    id: 'notion',
    handle: {
      ns: 'com.indra.system.silo',
      alias: 'notion',
      label: 'Notion',
      icon: 'DATABASE'
    },
    class: 'FOLDER',
    version: '1.1 (Synthesis)',
    config_schema: [
      { key: 'NOTION_API_KEY', type: 'password', label: 'API Key de Notion', required: true },
    ],
    capabilities: {
      ATOM_READ: { sync: 'BLOCKING', purge: 'NONE', handler: 'handleNotion' },
      ATOM_CREATE: { sync: 'BLOCKING', purge: 'ALL', handler: 'handleNotion' },
      ATOM_UPDATE: { sync: 'BLOCKING', purge: 'ID', handler: 'handleNotion' },
      ATOM_DELETE: { sync: 'BLOCKING', purge: 'ALL', handler: 'handleNotion' },
      TABULAR_UPDATE: { sync: 'BLOCKING', purge: 'ID', handler: 'handleNotion' }, // AXIOMA DE SINCERIDAD
      SCHEMA_MUTATE: { sync: 'BLOCKING', purge: 'ID', handler: 'handleNotion' },
      TABULAR_STREAM: { sync: 'BLOCKING', purge: 'NONE', handler: 'handleNotion' },
      HIERARCHY_TREE: { sync: 'BLOCKING', purge: 'NONE', handler: 'handleNotion' },
      SEARCH_DEEP: { sync: 'BLOCKING', purge: 'NONE', handler: 'handleNotion' },
      SYSTEM_CONNECTION_TEST: { sync: 'BLOCKING', purge: 'NONE', handler: 'handleNotion' },
      ACCOUNT_RESOLVE: { sync: 'BLOCKING', purge: 'NONE', handler: 'handleNotion' },
      ATOM_DECOMPOSE: { sync: 'BLOCKING', purge: 'NONE', handler: 'handleNotion' },
      MEDIA_UPLOAD: { sync: 'BLOCKING', purge: 'NONE', handler: 'handleNotion' },
      SCHEMA_FIELD_OPTIONS: { sync: 'BLOCKING', purge: 'NONE', handler: 'handleNotion' }
    },
    protocol_meta: {
      HIERARCHY_TREE: { label: 'Conectando con Notion', help: 'Escaneando páginas y bases de datos en la raíz.' },
      TABULAR_STREAM: { label: 'Extrayendo Datos', help: 'Consultando filas y resolviendo relaciones en paralelo.' },
      ATOM_READ: { label: 'Abriendo Página', help: 'Recuperando bloques y contenido de Notion.' },
      ATOM_CREATE: { label: 'Creando en Notion', help: 'Esculpiendo nueva página en el workspace externo.' },
      ATOM_UPDATE: { label: 'Sincronizando Notion', help: 'Actualizando propiedades en la nube.' },
      ATOM_DELETE: { label: 'Archivando en Notion', help: 'Enviando página a la papelera (archivar).' },
      SCHEMA_MUTATE: { label: 'Mutando Estructura', help: 'Alterando columnas de la base de datos externa.' },
      SEARCH_DEEP: { label: 'Búsqueda Profunda', help: 'Consultando todo el workspace de Notion.' },
      SYSTEM_CONNECTION_TEST: { label: 'Probando Enlace', help: 'Verificando validez del Token de Integración.' }
    }
  });
}


// ─── CONSTANTES DE API ────────────────────────────────────────────────────────

const NOTION_BASE_URL_ = 'https://api.notion.com/v1';
const NOTION_API_VER_ = '2022-06-28';

// ─── MANEJADOR PRINCIPAL ──────────────────────────────────────────────────────

/**
 * Punto de entrada del provider notion. Invocado por protocol_router.gs.
 *
 * @param {Object} uqo - Universal Query Object.
 * @returns {{ items: Array, metadata: Object }}
 */
function handleNotion(uqo) {
  const protocol = (uqo.protocol || '').toUpperCase();
  const parts = uqo.provider.split(':');
  const provider = parts[0];
  const accountId = parts[1] || 'default';

  if (provider !== 'notion') {
    const err = createError('SYSTEM_FAILURE', `El handler de Notion recibió un provider inesperado: ${provider}`);
    return { items: [], metadata: { status: 'ERROR', error: err.message, code: err.code } };
  }

  logInfo(`[provider_notion] Dispatching: ${protocol} for account: ${accountId}`, { context_id: uqo.context_id });

  // Validación fail-fast: sin API Key → error visible inmediato.
  const apiKey = _notion_getNotionApiKey(accountId);
  if (!apiKey) {
    const err = createError('CONFIGURATION_ERROR',
      `Notion [${accountId}] no está configurado. Ve a Servicios y añade tu API Key.`
    );
    return { items: [], metadata: { status: 'ERROR', error: err.message, code: err.code } };
  }

  if (protocol === 'HIERARCHY_TREE') return _notion_handleHierarchyTree(uqo, apiKey);
  if (protocol === 'TABULAR_STREAM') return _notion_handleTabularStream(uqo, apiKey);
  if (protocol === 'TABULAR_UPDATE') return _notion_handleTabularUpdate(uqo, apiKey); // POLIMORFISMO TOTAL
  if (protocol === 'ATOM_READ') return _notion_handleAtomRead(uqo, apiKey);
  if (protocol === 'ATOM_CREATE') return _notion_handleAtomCreate(uqo, apiKey);
  if (protocol === 'ATOM_UPDATE') return _notion_handleAtomUpdate(uqo, apiKey);
  if (protocol === 'ATOM_DELETE') return _notion_handleAtomDelete(uqo, apiKey);
  if (protocol === 'SEARCH_DEEP') return _notion_handleSearchDeep(uqo, apiKey);
  if (protocol === 'ACCOUNT_RESOLVE') return _notion_handleAccountResolve(uqo, apiKey);
  if (protocol === 'SCHEMA_MUTATE') return _notion_handleSchemaMutate(uqo, apiKey);
  if (protocol === 'ATOM_DECOMPOSE') return _notion_handleAtomDecompose(uqo, apiKey);
  if (protocol === 'MEDIA_UPLOAD') return _notion_handleMediaUpload(uqo, apiKey);
  if (protocol === 'SCHEMA_FIELD_OPTIONS') return _notion_handleSchemaFieldOptions(uqo, apiKey);

  const err = createError('PROTOCOL_NOT_FOUND',
    `Provider "notion" no soporta el protocolo: "${protocol}".`
  );
  return { items: [], metadata: { status: 'ERROR', error: err.message, code: err.code } };
}

/**
 * SYSTEM_CONNECTION_TEST: Verifica si un token es válido.
 * Puede recibir el `api_key` en `uqo.data` para probar antes de guardar,
 * o usar la ya guardada si no se provee.
 *
 * @private
 */
function _notion_handleConnectionTest(uqo) {
  const testApiKey = (uqo.data && uqo.data.api_key) || _notion_getNotionApiKey(uqo.provider.split(':')[1]);
  if (!testApiKey) {
    return { items: [], metadata: { status: 'ERROR', error: 'No se proveyó API Key para la prueba.' } };
  }
  try {
    _notion_notionRequest('/search', { method: 'POST', payload: { page_size: 1 }, apiKey: testApiKey });
    return { items: [], metadata: { status: 'OK' } };
  } catch (e) {
    return { items: [], metadata: { status: 'ERROR', error: 'Token inválido o sin permisos.' } };
  }
}

/**
 * ACCOUNT_RESOLVE: Descubre la identidad real del workspace de Notion.
 * AXIOMA §1.4: La identidad es un Hecho Verificable.
 * @private
 */
function _notion_handleAccountResolve(uqo, passedApiKey) {
  const apiKey = passedApiKey || (uqo.data && uqo.data.api_key);
  if (!apiKey) return { items: [], metadata: { status: 'ERROR', error: 'API Key requerida para resolución.' } };

  try {
    // En Notion, /v/users/me devuelve el bot y el workspace relacionado
    const identity = _notion_notionRequest('/users/me', { method: 'GET', apiKey });

    // El workspace name viene en bot.owner.workspace_name (Integraciones Internas)
    const label = identity.bot?.owner?.workspace_name
      || identity.name
      || identity.bot?.owner?.user?.name
      || 'Notion Workspace';

    logInfo(`[provider_notion] Identidad resuelta: ${label}`);

    return {
      items: [{
        id: uqo.account_id || 'new',
        handle: {
          ns: 'com.indra.system.account',
          alias: _system_slugify_(label),
          label: label
        },
        class: 'ACCOUNT_IDENTITY',
        protocols: ['ATOM_READ']
      }],
      metadata: { status: 'OK' }
    };

  } catch (e) {
    logError(`[provider_notion] Fallo en ACCOUNT_RESOLVE: ${e.message}`);
    return { items: [], metadata: { status: 'ERROR', error: e.message } };
  }
}

// ─── HANDLERS POR PROTOCOLO ───────────────────────────────────────────────────

/**
 * HIERARCHY_TREE: Lista las páginas y databases en la raíz de Notion.
 * context_id = "ROOT"   → búsqueda global en el workspace de Notion.
 * context_id = pageId   → hijos directos de una página.
 *
 * @private
 */
function _notion_handleHierarchyTree(uqo, apiKey) {
  try {
    let contextId = uqo.context_id || 'ROOT';
    if (contextId === uqo.provider) contextId = 'ROOT';
    const cursor = uqo.query && uqo.query.cursor ? uqo.query.cursor : undefined;
    const depth = uqo.query && uqo.query.depth ? parseInt(uqo.query.depth) : 1;
    const providerId = uqo.provider;

    let results, hasMore, nextCursor;

    // --- NIVEL 1: ESCANEO DE RAÍZ O CONTEXTO ---
    if (contextId === 'ROOT' && !cursor) {
      const dbResponse = _notion_notionRequest('/search', {
        method: 'POST',
        payload: { filter: { value: 'database', property: 'object' }, page_size: 20 },
        apiKey,
      });

      const allResponse = _notion_notionRequest('/search', {
        method: 'POST',
        payload: { page_size: 40 },
        apiKey,
      });

      const seenIds = new Set();
      const combinedResults = [];
      [...(dbResponse.results || []), ...(allResponse.results || [])].forEach(item => {
        if (!seenIds.has(item.id)) {
          seenIds.add(item.id);
          combinedResults.push(item);
        }
      });

      results = combinedResults;
      hasMore = allResponse.has_more || false;
      nextCursor = allResponse.next_cursor || null;

    } else {
      // Búsqueda específica o hijos
      const response = contextId === 'ROOT' 
        ? _notion_notionRequest('/search', { method: 'POST', payload: { page_size: 50, start_cursor: cursor }, apiKey })
        : _notion_notionRequest(`/blocks/${contextId}/children?page_size=50${cursor ? '&start_cursor=' + cursor : ''}`, { method: 'GET', apiKey });
      
      results = response.results || [];
      // Filtrado si es por bloques para solo quedarnos con páginas/DBs
      if (contextId !== 'ROOT') {
        results = results.filter(b => b.type === 'child_page' || b.type === 'child_database');
      }
      hasMore = response.has_more || false;
      nextCursor = response.next_cursor || null;
    }

    let items = results
      .map(item => _notion_notionObjectToAtom(item, providerId))
      .filter(atom => atom !== null);

    // --- NIVEL 2: INFERENCIA PARALELA (EAGER LOADING) ---
    // Si depth > 1, recuperamos los hijos de todas las carpetas/páginas detectadas en UN SOLO GOLPE.
    if (depth > 1 && items.length > 0) {
      const folders = items.filter(i => i.class === 'FOLDER' || i.class === 'DOCUMENT');
      if (folders.length > 0) {
        logInfo(`[provider_notion] Ejecutando Deep Scan en paralelo para ${folders.length} nodos.`);
        
        const requests = folders.map(f => ({
          url: `${NOTION_BASE_URL_}/blocks/${f.id}/children?page_size=20`,
          method: 'GET',
          headers: {
            'Authorization': 'Bearer ' + apiKey,
            'Notion-Version': NOTION_API_VER_,
            'Content-Type': 'application/json',
          },
          muteHttpExceptions: true
        }));

        const responses = UrlFetchApp.fetchAll(requests);
        responses.forEach((resp, idx) => {
          if (resp.getResponseCode() === 200) {
            const childrenData = JSON.parse(resp.getContentText());
            const childAtoms = (childrenData.results || [])
              .filter(b => b.type === 'child_page' || b.type === 'child_database')
              .map(b => _notion_notionObjectToAtom(b, providerId))
              .filter(a => a !== null);
            
            // Inyectamos los hijos directamente en el átomo padre (vía payload)
            // para que el FractalViewer los tenga "Pre-cargados".
            folders[idx].payload = folders[idx].payload || {};
            folders[idx].payload.children = childAtoms;
            logInfo(`   ∟ Hijos inyectados en ${folders[idx].handle.label}: ${childAtoms.length}`);
          }
        });
      }
    }

    const hoodCounts = {
      STRUCTURE: items.filter(i => i.system_hood === 'STRUCTURE').length,
      PHENOTYPE: items.filter(i => i.system_hood === 'PHENOTYPE').length,
      ROUTES: 0
    };

    return {
      items,
      metadata: {
        status: 'OK',
        has_more: hasMore,
        next_cursor: nextCursor,
        total_objects: (contextId === 'ROOT' && !hasMore) ? items.length : undefined,
        sync_status: hasMore ? 'RESONATING' : 'COMPLETE',
        hood_counts: hoodCounts,
        depth_scanned: depth
      },
    };

  } catch (err) {
    logError('[provider_notion] Error en hierarchy_tree.', err);
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }
}

/**
 * TABULAR_STREAM: Lista las filas de una Notion Database.
 * context_id = databaseId de Notion.
 * query.filter, query.sorts → pasados directamente a la API de Notion (opacos).
 *
 * @private
 */
function _notion_handleTabularStream(uqo, apiKey) {
  if (!uqo.context_id) {
    const err = createError('INVALID_INPUT', 'TABULAR_STREAM requiere context_id.');
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }

  try {
    const dbId = uqo.context_id;
    const query = uqo.query || {};
    const providerId = uqo.provider;
    const limit = query.limit || null;

    const dbMeta = _notion_notionRequest(`/databases/${dbId}`, { method: 'GET', apiKey });
    const schema = dbMeta.properties || {};
    const dbName = _notion_extractNotionTitle(dbMeta.title);

    let allRows = [];
    let hasMore = true;
    let nextCursor = query.cursor || undefined;

    // --- AXIOMA DE PERSISTENCIA TOTAL: Paginación Automática ---
    while (hasMore) {
        const pagePayload = { page_size: limit && limit < 100 ? limit : 100 };
        if (nextCursor) pagePayload.start_cursor = nextCursor;
        if (query.filter) pagePayload.filter = query.filter;
        if (query.sorts && query.sorts.length > 0) {
            pagePayload.sorts = _notion_translateSorts(query.sorts);
        }

        const response = _notion_notionRequest(`/databases/${dbId}/query`, {
            method: 'POST',
            payload: pagePayload,
            apiKey,
        });

        const pageResults = response.results || [];
        allRows = allRows.concat(pageResults);
        
        hasMore = response.has_more && (!limit || allRows.length < limit);
        nextCursor = response.next_cursor;

        if (limit && allRows.length >= limit) {
            allRows = allRows.slice(0, limit);
            break;
        }
        
        // Anti-bloqueo preventivo
        if (allRows.length > 10000) {
             logWarn(`[provider_notion] Safety Break: Se han detectado más de 10,000 filas. Deteniendo stream para evitar timeout.`);
             break;
        }
    }

    const rawItems = allRows.map(page => _notion_rowToAtom(page, dbId, dbName, providerId));
    const fields = _notion_schemaToFields(schema);

    logInfo(`[provider_notion] TABULAR_STREAM: DB Metadata Schema Properties: ${Object.keys(schema).join(', ')}`);
    logInfo(`[provider_notion] TABULAR_STREAM: Fields Resultantes: ${fields.length}`);

    // ── RESOLUCIÓN DE RELACIONES ──────────────────────────────────────────────
    // Usa UrlFetchApp.fetchAll() — todos los requests van en paralelo.
    // Costo de tiempo: ~latencia de 1 request, sin importar cuántos IDs haya.
    // El límite protege solo contra bases de datos con miles de relaciones únicas
    // (caso extremo). Para uso normal (50-100 filas) cubre el 100% de los IDs.
    const RELATION_RESOLVE_LIMIT = 100;
    const relationFields = fields.filter(function (c) { return c.type === 'RELATION'; });
    const items = _notion_resolveRelationNames(rawItems, relationFields, apiKey, RELATION_RESOLVE_LIMIT);

    logInfo(`[provider_notion] tabular_stream: ${items.length} filas de "${dbName}"`);

    return {
      items,
      metadata: {
        status: 'OK',
        has_more: hasMore,
        next_cursor: nextCursor,
        schema: { fields },     // DATA_CONTRACTS: schema en metadata
        context: { db_id: dbId, db_name: dbName },
      },
    };

  } catch (err) {
    logError('[provider_notion] Error en tabular_stream.', err);
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }
}

/**
 * TABULAR_UPDATE: Inserta o actualiza filas (páginas) en una Database de Notion.
 * AXIOMA DE POLIMORFISMO: El satélite envía datos planos, el provider los hace complejos.
 * 
 * @private
 */
function _notion_handleTabularUpdate(uqo, apiKey) {
  const dbId = uqo.context_id;
  const actions = uqo.data?.actions || [];
  
  if (!dbId || actions.length === 0) {
    throw createError('INVALID_INPUT', 'TABULAR_UPDATE requiere context_id (dbId) y data.actions.');
  }

  try {
    // 1. Obtener el esquema de la DB para saber cómo traducir tipos
    const dbMeta = _notion_notionRequest(`/databases/${dbId}`, { method: 'GET', apiKey });
    const schema = dbMeta.properties || {};

    // 2. Preparar los requests paralelos
    const fetchRequests = actions.map(action => {
       const type = (action.type || 'CREATE').toUpperCase();
       const properties = _notion_translateToNotionProperties(action.data || {}, schema);
       
       if (type === 'CREATE') {
         return {
           url: `${NOTION_BASE_URL_}/pages`,
           method: 'POST',
           payload: JSON.stringify({ parent: { database_id: dbId }, properties }),
           headers: {
             'Authorization': 'Bearer ' + apiKey,
             'Notion-Version': NOTION_API_VER_,
             'Content-Type': 'application/json'
           },
           muteHttpExceptions: true
         };
       } else if (type === 'UPDATE' && action.id) {
         return {
           url: `${NOTION_BASE_URL_}/pages/${action.id}`,
           method: 'PATCH',
           payload: JSON.stringify({ properties }),
           headers: {
             'Authorization': 'Bearer ' + apiKey,
             'Notion-Version': NOTION_API_VER_,
             'Content-Type': 'application/json'
           },
           muteHttpExceptions: true
         };
       }
       return null;
    }).filter(Boolean);

    if (fetchRequests.length === 0) {
       return { items: [], metadata: { status: 'OK', records_mutated: 0 } };
    }

    // 3. Ejecución Paralela Industrial
    logInfo(`[provider_notion] TABULAR_UPDATE: Lanzando ${fetchRequests.length} mutaciones en paralelo.`);
    const responses = UrlFetchApp.fetchAll(fetchRequests);
    
    let successCount = 0;
    const errors = [];
    const items = [];

    responses.forEach((resp, idx) => {
      const code = resp.getResponseCode();
      if (code >= 200 && code < 300) {
        successCount++;
        const page = JSON.parse(resp.getContentText());
        items.push(_notion_rowToAtom(page, dbId, 'Notion DB', uqo.provider));
      } else {
        errors.push(`Accion ${idx}: HTTP ${code} - ${resp.getContentText().substring(0, 100)}`);
      }
    });

    return {
      items,
      metadata: {
        status: errors.length > 0 && successCount === 0 ? 'ERROR' : 'OK',
        records_mutated: successCount,
        error_details: errors.length > 0 ? errors : undefined,
        ignored_fields: [] // Notion rechaza el request si hay campos extras, no los ignora.
      }
    };

  } catch (err) {
    logError('[provider_notion] Error fatal en TABULAR_UPDATE.', err);
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }
}

/**
 * Traduce un objeto de datos plano a la estructura de propiedades de Notion.
 * AXIOMA §4.5: El provider absorbe la complejidad del silo.
 * @private
 */
function _notion_translateToNotionProperties(data, schema) {
  const notionProps = {};
  
  Object.keys(data).forEach(key => {
    const value = data[key];
    // Buscamos la propiedad en el esquema (case insensitive fallback)
    const propertyMatch = schema[key] || Object.values(schema).find(p => _system_slugify_(p.name || '') === key);
    if (!propertyMatch) return; // Ignorar si no existe en Notion

    const type = propertyMatch.type;
    const propName = propertyMatch.name || key;

    switch (type) {
      case 'title':
        notionProps[propName] = { title: [{ text: { content: String(value) } }] };
        break;
      case 'rich_text':
        notionProps[propName] = { rich_text: [{ text: { content: String(value) } }] };
        break;
      case 'number':
        notionProps[propName] = { number: Number(value) };
        break;
      case 'select':
        notionProps[propName] = { select: { name: String(value) } };
        break;
      case 'multi_select':
        const vals = Array.isArray(value) ? value : [value];
        notionProps[propName] = { multi_select: vals.map(v => ({ name: String(v) })) };
        break;
      case 'date':
        notionProps[propName] = { date: { start: new Date(value).toISOString() } };
        break;
      case 'checkbox':
        notionProps[propName] = { checkbox: Boolean(value) };
        break;
      case 'url':
        notionProps[propName] = { url: String(value) };
        break;
      case 'email':
        notionProps[propName] = { email: String(value) };
        break;
      case 'phone_number':
        notionProps[propName] = { phone_number: String(value) };
        break;
      case 'relation':
        const ids = Array.isArray(value) ? value : [value];
        notionProps[propName] = { relation: ids.map(id => ({ id })) };
        break;
      // Otros tipos (formula, rollup, created_time) son de solo lectura en Notion
    }
  });

  return notionProps;
}

/**
 * ATOM_READ: Obtiene el contenido de un bloque/página o database de Notion.
 * context_id = ID de Notion (página o database).
 *
 * @private
 */
function _notion_handleAtomRead(uqo, apiKey) {
  if (!uqo.context_id) {
    const err = createError('INVALID_INPUT', 'ATOM_READ requiere context_id.');
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }

  const id = uqo.context_id;
  logInfo(`[provider_notion] ATOM_READ: Intentando resolución agnóstica para ${id}`);

  try {
    let rawObj = null;
    let typeFound = null;

    // 1. Intentar como PÁGINA
    try {
      rawObj = _notion_notionRequest(`/pages/${id}`, { method: 'GET', apiKey });
      typeFound = 'page';
    } catch (e1) {
      // 2. Si falla, intentar como DATABASE
      logInfo(`[provider_notion] ATOM_READ: ${id} no es página, probando database...`);
      try {
        rawObj = _notion_notionRequest(`/databases/${id}`, { method: 'GET', apiKey });
        typeFound = 'database';
      } catch (e2) {
        throw createError('NOT_FOUND', `No se encontró el objeto Notion ${id} como página ni como database.`);
      }
    }

    const atom = _notion_notionObjectToAtom(rawObj, uqo.provider);

    // 3. Si es página, enriquecer con bloques (contenido)
    if (typeFound === 'page' && atom) {
      const blocks = _notion_notionRequest(`/blocks/${id}/children?page_size=100`, { method: 'GET', apiKey });
      atom.raw.blocks = blocks.results || [];
    }

    logInfo(`[provider_notion] ATOM_READ: Resuelto como ${typeFound}`);

    return {
      items: atom ? [atom] : [],
      metadata: { status: 'OK', notion_type: typeFound },
    };

  } catch (err) {
    logError(`[provider_notion] Error en ATOM_READ para ${uqo.context_id}: ${err.message}`);
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }
}

/**
 * ATOM_CREATE: Crea una nueva página en Notion.
 * context_id = ID de la página padre (o database ID para crear una fila).
 * data.name  = título de la página (requerido).
 *
 * @private
 */
function _notion_handleAtomCreate(uqo, apiKey) {
  const data = uqo.data || {};
  const label = data.handle?.label || data.name;
  const classType = data.class || 'DOCUMENT';

  if (!label) {
    const err = createError('INVALID_INPUT', 'ATOM_CREATE requiere data.handle.label o data.name.');
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }
  if (!uqo.context_id) {
    const err = createError('INVALID_INPUT', 'ATOM_CREATE requiere context_id.');
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }

  try {
    // ── MODO TABULAR: Crear Database con Propiedades Tipadas (ADR-032)
    if (classType === 'TABULAR') {
      const parentId = uqo.context_id;
      const fields = data.fields || data.payload?.fields || [];
      
      const notionProperties = {
        "Nombre": { "title": {} } // Indra usa 'Nombre' por convención en Notion
      };

      if (Array.isArray(fields)) {
        fields.forEach(f => {
          const name = typeof f === 'object' ? (f.label || f.alias || f.id) : f;
          if (name === 'Nombre' || name === 'Name') return; 
          const type = typeof f === 'object' ? f.type : 'TEXT';
          // Inyectamos los metadatos del campo específico en el uqo temporal para la traducción
          const fieldUqo = { ...uqo, data: { ...uqo.data, ...(typeof f === 'object' ? f : {}) } };
          notionProperties[name] = _notion_translateTypeToNotion(type, fieldUqo);
        });
      }

      const dbPayload = {
        parent: { page_id: parentId },
        title: [ { text: { content: label } } ],
        properties: notionProperties,
        // Soporte para Icono y Portada (Plastilina Visual)
        icon: data.icon ? { type: 'emoji', emoji: data.icon } : undefined,
        cover: data.cover ? { type: 'external', external: { url: data.cover } } : undefined
      };

      const created = _notion_notionRequest('/databases', { method: 'POST', payload: dbPayload, apiKey });
      const atom = _notion_notionObjectToAtom(created, uqo.provider);

      logInfo(`[provider_notion] DATABASE Creada inteligentemente: "${label}" con ${Object.keys(notionProperties).length} props.`);
      return { items: atom ? [atom] : [], metadata: { status: 'OK' } };
    }

    // ── MODO DOCUMENT: Crear Página simple
    const pagePayload = {
      parent: { page_id: uqo.context_id },
      properties: {
        title: { title: [{ text: { content: label } }] },
      },
    };

    const created = _notion_notionRequest('/pages', { method: 'POST', payload: pagePayload, apiKey });
    const atom = _notion_notionObjectToAtom(created, uqo.provider);

    logInfo(`[provider_notion] PÁGINA Creada: "${label}" bajo ${uqo.context_id}`);
    return { items: atom ? [atom] : [], metadata: { status: 'OK' } };

  } catch (err) {
    logError('[provider_notion] Error en atom_create.', err);
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }
}

/**
 * ATOM_UPDATE: Actualiza el título u otras propiedades de una página.
 * context_id = pageId de Notion.
 * data = objeto con los campos a actualizar (flat, el adapter enriquece).
 *
 * @private
 */
function _notion_handleAtomUpdate(uqo, apiKey) {
  if (!uqo.context_id || !uqo.data) {
    const err = createError('INVALID_INPUT', 'ATOM_UPDATE requiere context_id y data.');
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }

  try {
    const properties = {};
    const label = uqo.data.handle?.label || uqo.data.name;
    if (label) {
      properties.title = { title: [{ text: { content: label } }] };
    }

    const updated = _notion_notionRequest(`/pages/${uqo.context_id}`, {
      method: 'PATCH',
      payload: { properties },
      apiKey,
    });

    const atom = _notion_notionObjectToAtom(updated, uqo.provider);
    return { items: atom ? [atom] : [], metadata: { status: 'OK' } };

  } catch (err) {
    logError('[provider_notion] Error en atom_update.', err);
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }
}

/**
 * ATOM_DELETE: Archiva (soft-delete) una página en Notion.
 * Notion no permite borrado permanente via API — solo archivado.
 *
 * @private
 */
function _notion_handleAtomDelete(uqo, apiKey) {
  if (!uqo.context_id) {
    const err = createError('INVALID_INPUT', 'ATOM_DELETE requiere context_id.');
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }

  try {
    _notion_notionRequest(`/pages/${uqo.context_id}`, {
      method: 'PATCH',
      payload: { archived: true },
      apiKey,
    });

    logInfo(`[provider_notion] Página archivada: ${uqo.context_id}`);
    return { items: [], metadata: { status: 'OK' } };

  } catch (err) {
    logError('[provider_notion] Error en atom_delete.', err);
    return { items: [], metadata: { status: 'ERROR', error: err.message } };
  }
}

// ─── CONVERSIÓN A ÁTOMO UNIVERSAL ────────────────────────────────────────────

/**
 * Convierte un objeto de Notion (page o database) a Átomo Universal canónico.
 * Decisión de clasificación:
 *   object === 'database'   → class: TABULAR  (tiene estructura de filas)
 *   object === 'page'       → class: DOCUMENT (contenido narrativo)
 *   block.type === 'child_page'     → class: DOCUMENT
 *   block.type === 'child_database' → class: TABULAR
 *
 * @param {Object} notionObj - Objeto de la API de Notion.
 * @returns {Object|null} Átomo Universal o null si el objeto no es proyectable.
 * @private
 */
function _notion_notionObjectToAtom(notionObj, providerId) {
  if (!notionObj) return null;

  const objectType = notionObj.object; // 'page', 'database', 'block'
  const blockType = notionObj.type;   // 'child_page', 'child_database' (si es bloque)

  let id, name, atomClass;

  if (objectType === 'database') {
    id = notionObj.id;
    name = _notion_extractNotionTitle(notionObj.title) || 'Sin título';
    atomClass = 'TABULAR';

  } else if (objectType === 'page') {
    id = notionObj.id;
    name = _notion_extractPageTitle(notionObj) || 'Sin título';
    atomClass = 'DOCUMENT';

  } else if (objectType === 'block') {
    id = notionObj.id;
    if (blockType === 'child_database') {
      name = notionObj.child_database?.title || 'Database sin título';
      atomClass = 'TABULAR';
    } else if (blockType === 'child_page') {
      name = notionObj.child_page?.title || 'Página sin título';
      atomClass = 'DOCUMENT';
    } else {
      return null; // Bloques que no son páginas/databases no son proyectables en el silo
    }

  } else {
    return null;
  }

  const protocols = atomClass === 'TABULAR'
    ? ['TABULAR_STREAM', 'ATOM_READ', 'ATOM_CREATE', 'ATOM_UPDATE', 'ATOM_DELETE']
    : ['ATOM_READ', 'ATOM_CREATE', 'ATOM_UPDATE', 'ATOM_DELETE'];

  const payload = {};
  if (objectType === 'database' && notionObj.properties) {
    payload.fields = _notion_schemaToFields(notionObj.properties);
  }

  return {
    id,
    handle: {
      ns: `com.notion.${atomClass.toLowerCase()}`,
      alias: _system_slugify_(name) || 'notion_unnamed',
      label: name
    },
    class: atomClass,
    provider: providerId,
    protocols,
    system_hood: atomClass === 'TABULAR' ? 'STRUCTURE' : 'PHENOTYPE',
    payload: payload, 
    raw: {
      notion_type: objectType,
      notion_url: notionObj.url || null,
      created_at: notionObj.created_time || null,
      modified_at: notionObj.last_edited_time || null,
    },
  };
}

/**
 * Convierte una fila (page) de una Notion Database a Átomo Universal.
 * Las propiedades son aplanadas por _flattenProperties_ para que el tabular_view
 * solo vea valores simples, nunca la estructura anidada de Notion.
 *
 * @param {Object} page       - Página de Notion que representa una fila.
 * @param {string} dbId       - ID de la database contenedora.
 * @param {string} dbName     - Nombre de la database para trazabilidad.
 * @returns {Object} Átomo Universal con campos planos.
 * @private
 */
function _notion_rowToAtom(page, dbId, dbName, providerId) {
  const flatProps = _notion_flattenProperties(page.properties || {});
  const title = _notion_extractPageTitle(page) || page.id;

  return {
    ...flatProps,
    id: page.id,
    handle: {
      ns: `com.notion.row.${dbId}`,
      alias: (title || '').toLowerCase().replace(/[^\w\s]/gi, '').replace(/\s+/g, '_'),
      label: title
    },
    class: 'TABULAR',
    provider: providerId,
    protocols: ['ATOM_READ', 'ATOM_UPDATE', 'ATOM_DELETE'],
    raw: {
      db_id: dbId,
      db_name: dbName,
      notion_url: page.url || null,
      modified_at: page.last_edited_time || null,
    },
  };
}

// ─── APLANADOR DE PROPIEDADES DE NOTION ──────────────────────────────────────

/**
 * Aplana las complejas estructuras de propiedades de Notion a objetos simples.
 * { campo: { type: 'rich_text', rich_text: [{ plain_text: 'valor' }] } }
 * → { campo: 'valor' }
 *
 * Copiado y adaptado del NotionAdapter clásico (INDRA_OS/INDRA_CORE)
 * que funcionó correctamente. Solo se adapta el estilo a las restricciones del nuevo modelo.
 *
 * @param {Object} properties - Propiedades de página de Notion (sin aplanar).
 * @returns {Object} Propiedades aplanadas { nombre: valor }.
 * @private
 */
function _notion_flattenProperties(properties) {
  const flat = {};

  for (const key in properties) {
    const prop = properties[key];
    if (!prop || typeof prop !== 'object') {
      flat[key] = prop != null ? String(prop) : null;
      continue;
    }
    const type = prop.type;

    switch (type) {
      case 'title':
        flat[key] = (prop.title && prop.title[0]) ? prop.title[0].plain_text : '';
        break;
      case 'rich_text':
        flat[key] = (prop.rich_text && prop.rich_text[0]) ? prop.rich_text[0].plain_text : '';
        break;
      case 'number':
        // number puede ser null en Notion (celda vacía)
        flat[key] = (prop.number !== null && prop.number !== undefined) ? prop.number : null;
        break;
      case 'select':
        flat[key] = prop.select ? prop.select.name : null;
        break;
      case 'multi_select':
        flat[key] = prop.multi_select ? prop.multi_select.map(function (o) { return o.name; }) : [];
        break;
      case 'date':
        // CORRECCIÓN: retornar solo el string ISO de inicio, no el objeto {start, end}.
        // El frontend espera un string para el renderer 'date'.
        flat[key] = prop.date ? (prop.date.start || null) : null;
        break;
      case 'checkbox':
        flat[key] = Boolean(prop.checkbox);
        break;
      case 'url':
        flat[key] = prop.url || null;
        break;
      case 'email':
        flat[key] = prop.email || null;
        break;
      case 'phone_number':
        flat[key] = prop.phone_number || null;
        break;
      case 'status':
        flat[key] = (prop.status && prop.status.name) ? prop.status.name : null;
        break;
      case 'relation':
        // Array de objetos {id} → array de IDs string
        flat[key] = prop.relation ? prop.relation.map(function (r) { return r.id; }) : [];
        break;
      case 'people':
        // Array de objetos de usuario → array de IDs
        flat[key] = prop.people ? prop.people.map(function (p) { return p.name || p.id; }) : [];
        break;
      case 'files':
        // ADR-023: Canonicalizar archivos/imágenes como INDRA_MEDIA.
        // Las URLs de Notion son temporales (~1 hora). Se incluye expires_at para que el
        // Bridge o Workflow pueda detectarlo y refrescar si es necesario.
        flat[key] = prop.files ? prop.files.map(function (f) {
          const rawUrl = f.file ? f.file.url : (f.external ? f.external.url : null);
          if (!rawUrl) return null;

          const isImage = f.name && /\.(jpg|jpeg|png|gif|webp|svg|avif)$/i.test(f.name);
          const mimeGuess = isImage
            ? ('image/' + (f.name.split('.').pop().toLowerCase().replace('jpg', 'jpeg')))
            : null;

          return {
            type: 'INDRA_MEDIA',
            storage: f.file ? 'notion' : 'url',
            canonical_url: rawUrl,
            file_id: null,          // Notion no tiene File IDs directos para refrescar
            mime_type: mimeGuess,
            expires_at: f.file      // Las URLs internas de Notion expiran
              ? new Date(Date.now() + 55 * 60 * 1000).toISOString()  // ~55 min de margen
              : null,
            alt: f.name || null
          };
        }).filter(Boolean) : [];
        break;
      case 'created_time':
        flat[key] = prop.created_time || null;
        break;
      case 'last_edited_time':
        flat[key] = prop.last_edited_time || null;
        break;
      case 'created_by':
        flat[key] = prop.created_by ? (prop.created_by.name || prop.created_by.id) : null;
        break;
      case 'last_edited_by':
        flat[key] = prop.last_edited_by ? (prop.last_edited_by.name || prop.last_edited_by.id) : null;
        break;
      case 'formula': {
        // CORRECCIÓN: extraer el valor primitivo del subtipo de la formula.
        const f = prop.formula;
        if (!f) { flat[key] = null; break; }
        // f.type puede ser 'string', 'number', 'boolean', 'date'
        const fVal = f[f.type];
        if (f.type === 'date') {
          flat[key] = fVal ? (fVal.start || null) : null;
        } else {
          flat[key] = (fVal !== undefined && fVal !== null) ? fVal : null;
        }
        break;
      }
      case 'rollup': {
        // CORRECCIÓN: extraer el valor primitivo del subtipo del rollup.
        const r = prop.rollup;
        if (!r) { flat[key] = null; break; }
        if (r.type === 'number') {
          flat[key] = (r.number !== null && r.number !== undefined) ? r.number : null;
        } else if (r.type === 'date') {
          flat[key] = r.date ? (r.date.start || null) : null;
        } else if (r.type === 'array') {
          // Rollup array: tomar el primer valor plano si existe
          flat[key] = r.array ? r.array.length : 0;
        } else {
          flat[key] = null;
        }
        break;
      }
      case 'unique_id':
        // ID único de Notion (número autoincremental con prefijo opcional)
        flat[key] = prop.unique_id
          ? (prop.unique_id.prefix ? prop.unique_id.prefix + '-' + prop.unique_id.number : prop.unique_id.number)
          : null;
        break;
      case 'verification':
        // Tipo de verificación de Notion (estado de verificación)
        flat[key] = prop.verification ? (prop.verification.state || null) : null;
        break;
      case 'button':
        // Tipo UI-only de Notion — no tiene valor de dato, es solo un botón de acción.
        // Se omite silenciosamente (sin logWarn — no es un bug, es una propiedad válida sin dato).
        flat[key] = null;
        break;
      default:
        // SEGURIDAD: cualquier tipo desconocido → null explícito.
        // NUNCA retornamos el objeto prop crudo — eso rompe React.
        logWarn('[provider_notion] flattenProperties: tipo no reconocido "' + type + '" en clave "' + key + '". Usando null.');
        flat[key] = null;
    }
  }

  return flat;
}

/**
 * Convierte el schema de propiedades de Notion al formato de campos canónico (ADR-008).
 * Este formato viaja en metadata.schema.fields y es consumido por el Bridge.
 *
 * @param {Object} notionSchema - Objeto properties de una Notion Database.
 * @returns {Array<{ id, label, type }>} Array de campos canónicos.
 * @private
 */
function _notion_schemaToFields(notionSchema) {
  if (!notionSchema) return [];

  return Object.entries(notionSchema).map(function (entry) {
    const key = entry[0];
    const prop = entry[1];
    const t = prop.type;

    // Mapa de tipos Notion → tipos canónicos del sistema (DATA_CONTRACTS §5.x)
    let canonicalType = 'STRING';
    if (t === 'number') canonicalType = 'NUMBER';
    else if (t === 'date' || t === 'created_time' || t === 'last_edited_time') canonicalType = 'DATE';
    else if (t === 'checkbox') canonicalType = 'BOOLEAN';
    else if (t === 'select' || t === 'status') canonicalType = 'SELECT';
    else if (t === 'multi_select') canonicalType = 'MULTI_SELECT';
    else if (t === 'email') canonicalType = 'EMAIL';
    else if (t === 'url') canonicalType = 'URL';
    else if (t === 'files') canonicalType = 'FILE';
    else if (t === 'relation') canonicalType = 'RELATION';
    else if (t === 'formula' || t === 'rollup') canonicalType = 'COMPUTED';
    else if (t === 'people') canonicalType = 'PEOPLE';

    return {
      id: key,
      key: key, // Alias para compatibilidad con selectores de UI
      handle: {
        ns: 'com.notion.schema.field',
        alias: _system_slugify_(key) || 'notion_field',
        label: key
      },
      type: canonicalType,
      // Inducción de Lógica: extraemos la expresión original para el LogicEngine
      formula_expression: t === 'formula' ? (prop.formula?.expression || null) : null,
      options: (prop.select && prop.select.options ? prop.select.options.map(function (o) { return o.name; }) :
        (prop.multi_select && prop.multi_select.options ? prop.multi_select.options.map(function (o) { return o.name; }) : [])),
    };
  });
}

// ─── RESOLUCIÓN DE RELACIONES ─────────────────────────────────────────────────

/**
 * Resuelve los IDs de páginas en columnas de tipo RELATION a nombres legibles.
 * Hace batch-fetch de páginas únicas con un mapa de caché local.
 * Principio Glandular: la inteligencia de enriquecimiento vive en el backend.
 *
 * @param {Array}  items          - Átomos de fila ya aplanados.
 * @param {Array}  relationCols   - Columnas de tipo RELATION del schema.
 * @param {string} apiKey        - API Key de Notion.
 * @param {number} limit         - Máximo de IDs únicos a resolver (rate limit).
 * @returns {Array} Items con IDs de relación reemplazados por nombres.
 * @private
 */
function _notion_resolveRelationNames(items, relationCols, apiKey, limit) {
  if (!relationCols || relationCols.length === 0 || !items || items.length === 0) {
    return items;
  }

  // 1. Recopilar todos los IDs de relación únicos en todos los ítems
  const allRelationIds = {};
  items.forEach(function (item) {
    relationCols.forEach(function (col) {
      const cellValue = item[col.id];
      if (Array.isArray(cellValue)) {
        cellValue.forEach(function (id) {
          if (typeof id === 'string' && id) allRelationIds[id] = true;
        });
      }
    });
  });

  const uniqueIds = Object.keys(allRelationIds);
  if (uniqueIds.length === 0) return items;

  // 2. Limitar para no superar el máximo de UrlFetchApp.fetchAll()
  const idsToResolve = uniqueIds.slice(0, limit);
  if (uniqueIds.length > limit) {
    logWarn('[provider_notion] resolveRelationNames: ' + uniqueIds.length +
      ' IDs de relación. Resolviendo en paralelo los primeros ' + limit + '.');
  }

  // ── BATCH PARALELO CON UrlFetchApp.fetchAll() ──────────────────────────────
  // GAS V8: fetchAll lanza todos los requests simultáneamente.
  // Resultado: ~tiempo del request más lento en lugar de suma de todos.
  // Con 20 relaciones: ~1s paralelo vs ~20s en serie.
  const headers = {
    'Authorization': 'Bearer ' + apiKey,
    'Notion-Version': NOTION_API_VER_,
    'Content-Type': 'application/json',
  };

  const fetchRequests = idsToResolve.map(function (pageId) {
    return {
      url: NOTION_BASE_URL_ + '/pages/' + pageId,
      method: 'GET',
      headers: headers,
      muteHttpExceptions: true,
    };
  });

  logInfo('[provider_notion] resolveRelationNames: lanzando ' + fetchRequests.length + ' requests en paralelo via fetchAll().');

  let responses;
  try {
    responses = UrlFetchApp.fetchAll(fetchRequests);
  } catch (networkError) {
    // Si fetchAll falla en bloque (error de red general), devolver sin enriquecer
    logError('[provider_notion] resolveRelationNames: fetchAll falló — ' + networkError.message);
    return items;
  }

  // 3. Construir caché de nombres desde las respuestas paralelas
  const nameCache = {};
  responses.forEach(function (response, i) {
    const pageId = idsToResolve[i];
    try {
      const statusCode = response.getResponseCode();
      if (statusCode >= 200 && statusCode < 300) {
        const page = JSON.parse(response.getContentText());
        nameCache[pageId] = _notion_extractPageTitle(page) || pageId;
      } else {
        // API devolvió error para este ID específico → usar ID como fallback
        nameCache[pageId] = pageId;
        logWarn('[provider_notion] resolveRelationNames: HTTP ' + statusCode + ' para ID "' + pageId + '".');
      }
    } catch (parseError) {
      nameCache[pageId] = pageId; // fallback seguro
      logWarn('[provider_notion] resolveRelationNames: parse error para ID "' + pageId + '".');
    }
  });

  // 4. Reemplazar IDs por nombres en cada ítem
  return items.map(function (item) {
    const enriched = Object.assign({}, item);
    relationCols.forEach(function (col) {
      const cellValue = enriched[col.id];
      if (Array.isArray(cellValue)) {
        enriched[col.id] = cellValue.map(function (id) {
          return nameCache[id] || id; // Si no se resolvió, mantener el ID
        });
      }
    });
    return enriched;
  });
}

// ─── TRADUCCIÓN DE SORTS UQO → NOTION ────────────────────────────────────────

/**
 * Traduce el array de sorts del formato canónico UQO al formato nativo de Notion.
 * DATA_CONTRACTS §3.1: direction = "ASC" | "DESC"
 * Notion API:          direction = "ascending" | "descending"
 *
 * @param {Array<{field: string, direction: string}>} sorts - Sorts UQO canónicos.
 * @returns {Array<{property: string, direction: string}>} Sorts en formato Notion.
 * @private
 */
function _notion_translateSorts(sorts) {
  if (!Array.isArray(sorts)) return [];
  return sorts.map(function (s) {
    return {
      property: s.field,
      direction: (s.direction === 'ASC') ? 'ascending' : 'descending',
    };
  });
}

// ─── EXTRACCIÓN DE TÍTULOS ────────────────────────────────────────────────────

/**
 * Extrae el título legible de una página de Notion.
 * Las páginas pueden tener el título en diferentes propiedades según
 * si son páginas simples o filas de base de datos.
 *
 * @param {Object} page - Objeto página de Notion.
 * @returns {string} Título extraído o cadena vacía.
 * @private
 */
function _notion_extractPageTitle(page) {
  if (!page || !page.properties) return '';
  // Buscar la propiedad de tipo 'title' (siempre hay exactamente una en Notion)
  for (const key in page.properties) {
    const prop = page.properties[key];
    if (prop.type === 'title' && prop.title && prop.title.length > 0) {
      return prop.title[0].plain_text || '';
    }
  }
  return '';
}

/**
 * Extrae el título de un array de rich_text (usado en databases).
 * @param {Array} titleArray - Array de objetos rich_text de Notion.
 * @returns {string}
 * @private
 */
function _notion_extractNotionTitle(titleArray) {
  if (!titleArray || !titleArray.length) return '';
  return titleArray.map(function (t) { return t.plain_text || ''; }).join('');
}

// ─── CLIENTE HTTP PARA LA API DE NOTION ──────────────────────────────────────

/**
 * Cliente HTTP unificado para toda comunicación con la API de Notion.
 * Centraliza: autenticación, serialización, manejo de errores HTTP,
 * y logging de cada request para diagnóstico en GAS.
 *
 * @param {string} endpoint - Ruta relativa. Ej: '/search', '/databases/abc123/query'.
 * @param {{ method: string, payload?: Object, apiKey: string }} options
 * @returns {Object} Respuesta JSON parseada de la API de Notion.
 * @throws Lanza error estructurado si la API retorna error HTTP o red.
 * @private
 */
function _notion_notionRequest(endpoint, options) {
  const url = NOTION_BASE_URL_ + endpoint;
  const method = (options.method || 'GET').toUpperCase();

  logInfo(`[provider_notion] HTTP ${method} ${endpoint}`);

  const fetchOptions = {
    method: method,
    muteHttpExceptions: true,
    headers: {
      'Authorization': 'Bearer ' + options.apiKey,
      'Notion-Version': NOTION_API_VER_,
      'Content-Type': 'application/json',
    },
  };

  if (options.payload) {
    fetchOptions.payload = JSON.stringify(options.payload);
  }

  let response;
  try {
    response = UrlFetchApp.fetch(url, fetchOptions);
  } catch (networkError) {
    throw createError('NETWORK_ERROR',
      `[provider_notion] Error de red al llamar a Notion: ${networkError.message}`,
      { endpoint }
    );
  }

  const statusCode = response.getResponseCode();
  const responseText = response.getContentText();

  if (statusCode < 200 || statusCode >= 300) {
    let errorMessage = `Notion API error HTTP ${statusCode}`;
    let errorCode = 'NOTION_API_ERROR';
    try {
      const errorBody = JSON.parse(responseText);
      errorMessage = errorBody.message || errorMessage;
      errorCode = errorBody.code || errorCode;
    } catch (e) { /* body no es JSON — usar mensaje genérico */ }

    logError(`[provider_notion] Error ${statusCode} en ${endpoint}: ${errorMessage}`);
    throw createError(errorCode, errorMessage, { statusCode, endpoint });
  }

  try {
    return JSON.parse(responseText);
  } catch (parseError) {
    throw createError('PARSE_ERROR',
      `[provider_notion] Respuesta no JSON de Notion en ${endpoint}.`,
      { endpoint, raw: responseText.substring(0, 200) }
    );
  }
}

// ─── GESTIÓN DE CREDENCIALES ──────────────────────────────────────────────────

/**
 * Lee la Notion API Key desde PropertiesService via system_config.gs.
 * La clave se almacena como 'ACCOUNT_notion_{accountId}_KEY' in PropertiesService.
 *
 * @param {string} accountId - El ID de la cuenta.
 * @returns {string|null} La API Key o null si no está configurada.
 * @private
 */
function _notion_getNotionApiKey(accountId) {
  const rawKey = readProviderApiKey('notion', accountId || 'default');
  if (!rawKey) return null;

  try {
    // AXIOMA DE SOBERANÍA: Intentar parsear como objeto dinámico (Motor v12.0)
    const credentials = JSON.parse(rawKey);
    // Buscamos la llave por el ID definido en el config_schema
    return credentials.NOTION_API_KEY || credentials.api_key || rawKey;
  } catch (e) {
    // FALLBACK: Si no es JSON, es una llave legacy en texto plano
    return rawKey;
  }
}

/**
 * SCHEMA_MUTATE: Sincroniza cambios estructurales (columnas) con la base de datos de Notion.
 * AXIOMA DE RESONANCIA: El provider traduce la libertad de INDRA a la restricción del silo.
 *
 * @param {Object} uqo - Universal Query Object.
 * @param {string} apiKey - Integración Token de Notion.
 * @private
 */
function _notion_handleSchemaMutate(uqo, apiKey) {
  const dbId = uqo.context_id;
  const payload = uqo.data?.payload;
  const fields = payload?.fields;

  if (!dbId || !fields) {
    throw createError('INVALID_INPUT', 'SCHEMA_MUTATE requiere context_id (dbId) y payload.fields.');
  }

  try {
    // 1. Obtener estado actual para detectar qué es nuevo o qué ha cambiado
    const currentDb = _notion_notionRequest(`/databases/${dbId}`, { method: 'GET', apiKey });
    const currentProps = currentDb.properties || {};

    // 2. Traducir INDRA fields a Notion Properties
    const notionProperties = {};

    fields.forEach(field => {
       // El label de INDRA es el nombre de la columna en Notion
       const propertyName = field.label; 
       
       // Si la propiedad no existe en Notion, la preparamos para creación
       if (!currentProps[propertyName]) {
         const fieldUqo = { ...uqo, data: { ...uqo.data, ...field } };
         notionProperties[propertyName] = _notion_translateTypeToNotion(field.type, fieldUqo);
       }
       // En esta fase, no renombramos ni borramos para evitar pérdida de datos accidental.
    });

    if (Object.keys(notionProperties).length === 0) {
      return { 
        items: [], 
        metadata: { 
          status: 'OK', 
          message: 'No se detectaron nuevas columnas para resonar en Notion.' 
        } 
      };
    }

    // 3. Ejecutar Mutación en Notion
    const updated = _notion_notionRequest(`/databases/${dbId}`, {
      method: 'PATCH',
      payload: { properties: notionProperties },
      apiKey
    });

    logInfo(`[provider_notion] SCHEMA_MUTATE exitoso en ${dbId}. Creadas: ${Object.keys(notionProperties).join(', ')}`);

    const atom = _notion_notionObjectToAtom(updated, uqo.provider);
    return { 
      items: atom ? [atom] : [], 
      metadata: { 
        status: 'OK', 
        mutated_properties: Object.keys(notionProperties) 
      } 
    };

  } catch (err) {
    logError(`[provider_notion] Fallo en SCHEMA_MUTATE para ${dbId}: ${err.message}`);
    const msg = err.message || 'Error desconocido en mutación';
    return { items: [], metadata: { status: 'ERROR', error: msg } };
  }
}

/**
 * Traduce tipos canónicos de INDRA a especificaciones de propiedad de Notion API.
 * @param {string} indraType
 * @param {Object} uqo - Para extraer metadatos de relación/rollup
 * @returns {Object} Configuración del tipo para Notion
 * @private
 */
function _notion_translateTypeToNotion(indraType, uqo) {
  const norm = (indraType || '').toUpperCase();
  switch (norm) {
    case 'NUMBER': 
    case 'CURRENCY':
      return { number: { format: 'number' } };
    case 'BOOLEAN': 
    case 'CHECKBOX':
      return { checkbox: {} };
    case 'DATE': 
    case 'DATETIME':
      return { date: {} };
    case 'SELECT':
    case 'RADIO':
    case 'ENUM':
      return { select: {} };
    case 'MULTISELECT':
    case 'CHECKBOX_GROUP':
    case 'ARRAY':
      return { multi_select: {} };
    case 'URL':
      return { url: {} };
    case 'EMAIL':
      return { email: {} };
    case 'PHONE':
      return { phone_number: {} };
    case 'RELATION':
      // Si recibimos 'synced_property_name', creamos una relación Bi-direccional
      if (uqo && uqo.data && uqo.data.synced_property_name) {
        return { 
          relation: { 
            database_id: uqo.data.target_database_id,
            type: 'dual_property',
            dual_property: { synced_property_name: uqo.data.synced_property_name }
          } 
        };
      }
      return { 
        relation: { 
          database_id: uqo && uqo.data && uqo.data.target_database_id,
          type: 'single_property' 
        } 
      };
    case 'SYNCED_BLOCK':
      return { synced_block: { synced_from: uqo.data.synced_from || null } };
    case 'ROLLUP':
      // Requiere metadatos de relación
      return {
        rollup: {
          relation_property_name: uqo && uqo.data && uqo.data.relation_name,
          rollup_property_name: uqo && uqo.data && uqo.data.target_property_name,
          function: uqo && uqo.data && uqo.data.function || 'show_original'
        }
      };
    case 'TEXT':
    case 'LONG_TEXT':
    default:
      return { rich_text: {} };
  }
}

/**
 * ATOM_DECOMPOSE: Descompone una página de Notion en sus bloques constituyentes.
 * AXIOMA §4.1: Todo contenido es una jerarquía de átomos editables.
 *
 * @param {Object} uqo - Universal Query Object.
 * @param {string} apiKey - Token de Notion.
 * @private
 */
function _notion_handleAtomDecompose(uqo, apiKey) {
  const pageId = uqo.context_id;
  if (!pageId) throw createError('INVALID_INPUT', 'ATOM_DECOMPOSE requiere context_id (pageId).');

  try {
    const response = _notion_notionRequest(`/blocks/${pageId}/children?page_size=100`, { method: 'GET', apiKey });
    const blocks = response.results || [];

    const items = blocks.map(block => {
      const type = block.type;
      const content = block[type];
      let label = 'Bloque ' + type;
      
      // Intentar extraer texto legible para el label del átomo
      if (content && content.rich_text && content.rich_text.length > 0) {
        label = content.rich_text[0].plain_text.substring(0, 30) || label;
      } else if (content && content.title && content.title.length > 0) {
        label = content.title[0].plain_text.substring(0, 30) || label;
      }

      return {
        id: block.id,
        handle: {
          ns: `com.notion.block.${type}`,
          alias: _system_slugify_(label),
          label: label
        },
        class: 'BLOCK',
        sub_class: type.toUpperCase(),
        provider: uqo.provider,
        protocols: ['ATOM_READ', 'ATOM_UPDATE', 'ATOM_DELETE'],
        payload: {
          raw_notion_block: block
        },
        system_hood: 'PHENOTYPE'
      };
    });

    return {
      items,
      metadata: {
        status: 'OK',
        total_atoms: items.length,
        parent_id: pageId
      }
    };
  } catch (e) {
    logError(`[provider_notion] Fallo en ATOM_DECOMPOSE: ${e.message}`);
    return { items: [], metadata: { status: 'ERROR', error: e.message } };
  }
}

/**
 * MEDIA_UPLOAD: Inicia el protocolo de carga de archivos Direct-Upload.
 * @private
 */
function _notion_handleMediaUpload(uqo, apiKey) {
  const data = uqo.data || {};
  const filename = data.filename || 'indra_upload.bin';
  
  try {
    // Paso 1 de Notion: Solicitar espacio de carga
    const uploadMeta = _notion_notionRequest('/file_uploads', {
      method: 'POST',
      payload: { filename },
      apiKey
    });

    return {
      items: [{
        id: uploadMeta.id,
        class: 'MEDIA_TICKET',
        upload_url: uploadMeta.upload_url,
        expiry_time: uploadMeta.expiry_time,
        payload: uploadMeta
      }],
      metadata: { status: 'OK' }
    };
  } catch (e) {
    logError(`[provider_notion] Fallo en MEDIA_UPLOAD: ${e.message}`);
    return { items: [], metadata: { status: 'ERROR', error: e.message } };
  }
}

/**
 * SCHEMA_FIELD_OPTIONS: Recupera la estructura de campos (schema) de una Database.
 * AXIOMA §3.2: El sistema debe ver antes de poder mapear.
 * @private
 */
function _notion_handleSchemaFieldOptions(uqo, apiKey) {
  const dbId = uqo.context_id;
  if (!dbId) throw createError('INVALID_INPUT', 'SCHEMA_FIELD_OPTIONS requiere context_id.');

  try {
    const dbMeta = _notion_notionRequest(`/databases/${dbId}`, { method: 'GET', apiKey });
    const fields = _notion_schemaToFields(dbMeta.properties || {});

    return {
      items: fields,
      metadata: { 
        status: 'OK', 
        schema: { fields },
        source_name: _notion_extractNotionTitle(dbMeta.title)
      }
    };
  } catch (e) {
    logError(`[provider_notion] Fallo en SCHEMA_FIELD_OPTIONS: ${e.message}`);
    return { items: [], metadata: { status: 'ERROR', error: e.message } };
  }
}

2_providers.provider_pipeline.gs:
// =============================================================================
// ARTEFACTO: 2_providers/provider_pipeline.gs
// CAPA: 2 — Providers (Virtual / Internal)
// RESPONSABILIDAD: Operador de transformaciones en memoria. No llama a APIs externas.
//         Recibe ítems del Step anterior (via uqo.data.items) y los procesa
//         según el protocolo de transformación solicitado (ADR 004).
//
// AXIOMAS:
//   - Autonomía del Backend: El cómputo pesado y de negocio vive aquí.
//   - Motor V8: Usa Function() dinámico para TRANSFORM_COMPUTE.
//   - Es un tubo determinista: Mismo input + misma query = mismo output.
// =============================================================================

/**
 * Manifestación del provider pipeline.
 * @returns {Object}
 */
function CONF_PIPELINE() {
  return Object.freeze({
    id: 'pipeline',
    handle: {
      ns: 'com.indra.system.logic',
      alias: 'pipeline',
      label: 'Transformador'
    },
    class: 'LOGIC_ENGINE',
    version: '1.0',
    exposure: 'internal', // El usuario no necesita configurar el motor de cómputo
    capabilities: {
      TRANSFORM_FILTER: { handler: 'handlePipeline' },
      TRANSFORM_MAP: { handler: 'handlePipeline' },
      TRANSFORM_COMPUTE: { handler: 'handlePipeline' },
      TRANSFORM_AGGREGATE: { handler: 'handlePipeline' },
      TRANSFORM_SORT: { handler: 'handlePipeline' },
      TRANSFORM_TEMPLATE: { handler: 'handlePipeline' }
    },
    config_schema: [], // No requiere API Keys ni configuración persistente
  });
}

/**
 * Punto de entrada único para el pipeline.
 * El ejecutor de workflows inyecta los ítems en uqo.data.items.
 */
function handlePipeline(uqo) {
  const protocol = (uqo.protocol || '').toUpperCase();
  const items = (uqo.data && uqo.data.items) || [];

  logInfo(`[provider_pipeline] Ejecutando: ${protocol} sobre ${items.length} ítems.`);

  if (protocol === 'TRANSFORM_FILTER') return _pipe_handleFilter(items, uqo.query);
  if (protocol === 'TRANSFORM_MAP') return _pipe_handleMap(items, uqo.query);
  if (protocol === 'TRANSFORM_COMPUTE') return _pipe_handleCompute(items, uqo.query);
  if (protocol === 'TRANSFORM_SORT') return _pipe_handleSort(items, uqo.query);
  if (protocol === 'TRANSFORM_AGGREGATE') return _pipe_handleAggregate(items, uqo.query);
  if (protocol === 'TRANSFORM_TEMPLATE') return _pipe_handleTemplate(items, uqo.query);

  return { items: [], metadata: { status: 'ERROR', error: `Protocolo ${protocol} no implementado.` } };
}

// ─── HANDLERS DE TRANSFORMACIÓN ───────────────────────────────────────────────

/**
 * TRANSFORM_FILTER: Filtra una colección de átomos basado en condiciones.
 * uqo.query.filters = [{ field, operator, value }]
 */
function _pipe_handleFilter(items, query) {
  const filters = query.filters || [];
  if (filters.length === 0) return { items, metadata: { status: 'OK' } };

  const filtered = items.filter(item => {
    return filters.every(f => {
      const val = item[f.field] !== undefined ? item[f.field] : (item.raw && item.raw[f.field]);

      switch (f.operator) {
        case 'EQUALS': return String(val) === String(f.value);
        case 'NOT_EQUALS': return String(val) !== String(f.value);
        case 'CONTAINS': return String(val).toLowerCase().includes(String(f.value).toLowerCase());
        case 'GREATER_THAN': return Number(val) > Number(f.value);
        case 'LESS_THAN': return Number(val) < Number(f.value);
        default: return true;
      }
    });
  });

  return { items: filtered, metadata: { status: 'OK', total_objects: filtered.length } };
}

/**
 * TRANSFORM_MAP: Renombra o selecciona campos de cada átomo.
 * uqo.query.fields = { "original_key": "new_key" }
 */
function _pipe_handleMap(items, query) {
  const fieldMap = query.fields || {};
  const mapKeys = Object.keys(fieldMap);

  const mapped = items.map(item => {
    const newItem = { ...item };
    mapKeys.forEach(oldKey => {
      const newKey = fieldMap[oldKey];
      const val = item[oldKey] !== undefined ? item[oldKey] : (item.raw && item.raw[oldKey]);
      newItem[newKey] = val;
    });
    return newItem;
  });

  return { items: mapped, metadata: { status: 'OK' } };
}

/**
 * TRANSFORM_COMPUTE: Ejecuta una fórmula JavaScript (V8) sobre cada átomo.
 * uqo.query.formula = "a * b"
 * uqo.query.target_field = "total"
 */
function _pipe_handleCompute(items, query) {
  const formula = query.formula;
  const target = query.target_field || 'computed_value';

  if (!formula) return { items, metadata: { status: 'ERROR', error: 'Faltan parámetros: formula' } };

  const computed = items.map(item => {
    try {
      // Inyectar contexto: propiedades del átomo + propiedades del raw
      const context = { ...item, ...(item.raw || {}) };
      const keys = Object.keys(context).filter(k => k !== 'raw'); // evitar recursión circular
      const values = keys.map(k => context[k]);

      // Crear función dinámica en V8
      const fn = new Function(...keys, `try { return (${formula}); } catch(e) { return null; }`);
      const result = fn(...values);

      return { ...item, [target]: result };
    } catch (e) {
      logWarn(`[provider_pipeline] Error evaluando fórmula "${formula}" en ítem ${item.id}: ${e.message}`);
      return { ...item, [target]: null };
    }
  });

  return { items: computed, metadata: { status: 'OK' } };
}

/**
 * TRANSFORM_SORT: Ordena los ítems por uno o varios campos.
 * uqo.query.sort = [{ field, direction: 'ASC'|'DESC' }]
 */
function _pipe_handleSort(items, query) {
  const sortDefs = query.sort || [];
  if (sortDefs.length === 0) return { items, metadata: { status: 'OK' } };

  const sorted = [...items].sort((a, b) => {
    for (const s of sortDefs) {
      const valA = a[s.field] ?? (a.raw && a.raw[s.field]);
      const valB = b[s.field] ?? (b.raw && b.raw[s.field]);

      if (valA === valB) continue;

      const factor = s.direction === 'DESC' ? -1 : 1;
      return valA > valB ? factor : -factor;
    }
    return 0;
  });

  return { items: sorted, metadata: { status: 'OK' } };
}

/**
 * TRANSFORM_AGGREGATE: Agrupa y calcula totales (SUM, COUNT).
 * uqo.query.group_by = "field"
 * uqo.query.operations = [{ field, op: "SUM"|"COUNT"|"AVG", name: "resultado" }]
 */
function _pipe_handleAggregate(items, query) {
  const groupBy = query.group_by;
  const ops = query.operations || [];

  if (!groupBy) return { items, metadata: { status: 'ERROR', error: 'TRANSFORM_AGGREGATE requiere group_by.' } };

  const groups = {};
  items.forEach(item => {
    const key = item[groupBy] ?? (item.raw && item.raw[groupBy]) ?? 'Sin grupo';
    if (!groups[key]) groups[key] = [];
    groups[key].push(item);
  });

  const results = Object.keys(groups).map(groupKey => {
    const groupItems = groups[groupKey];
    const resultItem = {
      id: `agg_${groupKey}`,
      handle: {
        ns: 'com.indra.pipeline.aggregate',
        alias: _system_slugify_(groupKey),
        label: groupKey
      },
      class: 'DATA_ROW',
      [groupBy]: groupKey,
      count: groupItems.length,
      protocols: []
    };

    ops.forEach(opDef => {
      const field = opDef.field;
      const op = opDef.op;
      const name = opDef.name || `${op}_${field}`;

      if (op === 'COUNT') {
        resultItem[name] = groupItems.length;
      } else if (op === 'SUM' || op === 'AVG') {
        const sum = groupItems.reduce((acc, it) => {
          const val = Number(it[field] ?? (it.raw && it.raw[field]) ?? 0);
          return acc + (isNaN(val) ? 0 : val);
        }, 0);
        resultItem[name] = op === 'AVG' ? sum / groupItems.length : sum;
      }
    });

    return resultItem;
  });

  return { items: results, metadata: { status: 'OK', total_objects: results.length } };
}

/**
 * TRANSFORM_TEMPLATE: Llenar un template textual por cada ítem.
 * uqo.query.template = "Hola {{name}}, tu saldo es {{balance}}"
 * uqo.query.target_field = "message"
 */
function _pipe_handleTemplate(items, query) {
  const template = query.template;
  const target = query.target_field || 'rendered_text';

  if (!template) return { items, metadata: { status: 'ERROR', error: 'Falta parámetro template.' } };

  const rendered = items.map(item => {
    let result = template;
    const context = { ...item, ...(item.raw || {}) };

    // Buscar todas las ocurrencias de {{campo}}
    const regex = /\{\{(.+?)\}\}/g;
    result = result.replace(regex, (match, fieldName) => {
      const field = fieldName.trim();
      return context[field] !== undefined ? context[field] : '';
    });

    return { ...item, [target]: result };
  });

  return { items: rendered, metadata: { status: 'OK' } };
}

