/**
 * =============================================================================
 * ARTEFACTO: 2_providers/provider_system_workspace.gs
 * RESPONSABILIDAD: El "Alambrado" de contextos activos (PINS).
 * AXIOMA: GESTIÓN DE REFERENCIAS INTERNAS.
 * =============================================================================
 */

/**
 * SYSTEM_PIN: Ancla un átomo al workspace activo.
 * @private
 */
function _system_handlePin(uqo) {
    const workspaceId = uqo.workspace_id;
    const atom = uqo.data && uqo.data.atom;

    if (!workspaceId) throw createError('INVALID_INPUT', 'SYSTEM_PIN requiere workspace_id.');
    if (!atom || !atom.id || !atom.class || !atom.handle) {
        throw createError('INVALID_INPUT', 'SYSTEM_PIN requiere data.atom completo.');
    }

    try {
        const file = _system_findAtomFile(workspaceId);
        const doc = JSON.parse(file.getBlob().getDataAsString());
        const pins = Array.isArray(doc.pins) ? doc.pins : [];

        const pinPointer = {
            id: atom.id,
            handle: atom.handle,
            class: atom.class,
            provider: atom.provider,
            protocols: atom.protocols || [],
            pinned_at: new Date().toISOString(),
        };

        const existingIdx = pins.findIndex(p => p.id === atom.id && p.provider === atom.provider);
        if (existingIdx >= 0) pins[existingIdx] = pinPointer;
        else pins.push(pinPointer);

        doc.pins = pins;
        doc.updated_at = new Date().toISOString();
        file.setContent(JSON.stringify(doc, null, 2));

        const responsePayload = atom.payload || {};
        if (atom.class === 'DATA_SCHEMA' && !Array.isArray(responsePayload.fields)) {
            responsePayload.fields = [];
        }

        return { items: [{ ...pinPointer, payload: responsePayload }], metadata: { status: 'OK' } };
    } catch (err) {
        return { items: [], metadata: { status: 'ERROR', error: err.message, code: err.code || 'NOT_FOUND' } };
    }
}

/**
 * SYSTEM_UNPIN: Desancla un átomo del workspace activo.
 */
function _system_handleUnpin(uqo) {
    const workspaceId = uqo.workspace_id;
    const data = uqo.data || {};
    if (!workspaceId || !data.atom_id || !data.provider) throw createError('INVALID_INPUT', 'Faltan parámetros en UNPIN.');

    try {
        const file = _system_findAtomFile(workspaceId);
        const doc = JSON.parse(file.getBlob().getDataAsString());
        doc.pins = (doc.pins || []).filter(p => {
          const isMatchId = p.id === data.atom_id;
          
          // Blindaje contra nulos en el proveedor (Axioma de Sinceridad v17.6)
          const pProv = p.provider || '';
          const dProv = data.provider || '';
          
          const isMatchProvider = pProv === dProv || 
                                  (pProv && pProv.startsWith(dProv + ':')) ||
                                  (dProv && dProv.startsWith(pProv + ':'));
                                  
          return !(isMatchId && isMatchProvider);
        });
        doc.updated_at = new Date().toISOString();
        file.setContent(JSON.stringify(doc, null, 2));
        return { items: [], metadata: { status: 'OK' } };
    } catch (err) {
        return { items: [], metadata: { status: 'ERROR', error: err.message } };
    }
}

function _system_handlePinsRead(uqo) {
    const workspaceId = uqo.workspace_id;
    if (!workspaceId) throw createError('INVALID_INPUT', 'PINS_READ requiere workspace_id.');

    try {
        const file = _system_findAtomFile(workspaceId);
        const doc = JSON.parse(file.getBlob().getDataAsString());
        const pins = Array.isArray(doc.pins) ? doc.pins : [];

        let needsWorkspaceSync = false;

        // ─── PORTAL DE SINCERIDAD (v4.39 - Modo Ledger Fast) ─────────
        const pinIds = pins.map(p => p.id);
        const ledgerSnapshot = _ledger_get_bulk_metadata_(pinIds);

        const sincerePins = pins.map(pin => {
            const lMeta = ledgerSnapshot[pin.id];
            
            if (!lMeta) {
                // Si no está en el Ledger, hacemos un último intento físico antes de marcar como huérfano
                try {
                    const f = DriveApp.getFileById(pin.id);
                    if (f.isTrashed()) return { ...pin, _orphan: true };
                } catch(e) { 
                    logWarn(`[homeostasis] Materia muerta detectada: ${pin.id} (${e.message})`);
                    return { ...pin, _orphan: true }; 
                }
            }

            // Atomo existe en Ledger (Materia verificada)
            let enhancedPin = { ...pin };
            
            // Reconciliación Determinista de Identidad (v17.6)
            let physicalLabel = lMeta ? lMeta.label : pin.handle?.label;

            if (pin.handle?.label !== physicalLabel) {
                needsWorkspaceSync = true;
                enhancedPin.handle = { ...pin.handle, label: physicalLabel };
            }

            return { ...enhancedPin, _orphan: false };
        });

        // Axioma de Curación: Si detectamos desincronía o materia muerta (huérfanos), re-escribimos el Workspace
        const orphansFound = sincerePins.some(p => p._orphan);
        
        if (needsWorkspaceSync || orphansFound) {
            // PURGA HOMEOSTÁTICA: Solo conservamos los que NO son huérfanos
            doc.pins = sincerePins
              .filter(p => !p._orphan) // <--- Aquí incineramos la entropía
              .map(({ _orphan, _reconciled, payload, ...p }) => p); 
            
            file.setContent(JSON.stringify(doc, null, 2));
            logInfo(`[homeostasis] Workspace ${workspaceId} purgado y curado. Materia muerta eliminada.`);
        }

        return {
            items: sincerePins,
            metadata: {
                status: 'OK',
                count: sincerePins.length,
                bridges: doc.bridges || [],
                reconciled: needsWorkspaceSync
            }
        };
    } catch (err) {
        logError(`[infrastructure] Fallo en PINS_READ: ${workspaceId}`, err);
        return { items: [], metadata: { status: 'ERROR', error: err.message } };
    }
}

/**
 * Sincroniza identidades referenciadas.
 */
function _system_propagateNameChange(atomId, newName, providerId) {
    try {
        const wsFolder = _system_getOrCreateSubfolder_(WORKSPACES_FOLDER_NAME_);
        const files = wsFolder.getFiles();
        while (files.hasNext()) {
            const file = files.next();
            if (file.getMimeType() !== 'application/json') continue;
            try {
                const content = JSON.parse(file.getBlob().getDataAsString());
                let changed = false;
                (content.pins || []).forEach(pin => {
                    if (pin.id === atomId && (pin.provider === providerId || pin.provider.startsWith(providerId + ':'))) {
                        if (pin.handle) pin.handle.label = newName;
                        changed = true;
                    }
                });
                if (changed) file.setContent(JSON.stringify(content, null, 2));
            } catch (e) { }
        }
    } catch (err) { logError('[workspace] Fallo en propagación.', err); }
}

/**
 * Sincroniza alias referenciados en los pins.
 */
function _system_propagateAliasChange(atomId, newAlias, providerId) {
    try {
        const wsFolder = _system_getOrCreateSubfolder_(WORKSPACES_FOLDER_NAME_);
        const files = wsFolder.getFiles();
        while (files.hasNext()) {
            const file = files.next();
            if (file.getMimeType() !== 'application/json') continue;
            try {
                const content = JSON.parse(file.getBlob().getDataAsString());
                let changed = false;
                (content.pins || []).forEach(pin => {
                    if (pin.id === atomId && (pin.provider === providerId || pin.provider.startsWith(providerId + ':'))) {
                        if (pin.handle) pin.handle.alias = newAlias;
                        changed = true;
                    }
                });
                if (changed) file.setContent(JSON.stringify(content, null, 2));
            } catch (e) { }
        }
    } catch (err) { logError('[workspace] Fallo en propagación de alias.', err); }
}

/**
 * Elimina un pin de todos los workspaces cuando el átomo es destruido.
 */
function _system_propagateDeletion(atomId, providerId) {
    try {
        logInfo(`[homeostasis] Iniciando propagación de borrado para: ${atomId}`);
        const wsFolder = _system_getOrCreateSubfolder_(WORKSPACES_FOLDER_NAME_);
        const files = wsFolder.getFiles();
        while (files.hasNext()) {
            const file = files.next();
            if (file.getMimeType() !== 'application/json') continue;
            try {
                const content = JSON.parse(file.getBlob().getDataAsString());
                const originalCount = (content.pins || []).length;
                
                // AXIOMA DE PURGA SINCERA (v17.7): Si el ID coincide, el átomo ha muerto físicamente.
                content.pins = (content.pins || []).filter(pin => pin.id !== atomId);

                if (content.pins.length !== originalCount) {
                    file.setContent(JSON.stringify(content, null, 2));
                    logInfo(`[homeostasis] Pin eliminado del Workspace: ${file.getName()}`);
                }
            } catch (e) { }
        }
    } catch (err) { logError('[workspace] Fallo en propagación de borrado.', err); }
}

3_services.auth_service.gs:
/**
 * =============================================================================
 * ARTEFACTO: 3_services/auth_service.gs
 * RESPONSABILIDAD: Motor de identidad y autorización micelar.
 * AXIOMA: Soberanía de Sangre + Validación de Satélites + Tickets Públicos.
 * =============================================================================
 */

const AuthService = (function() {

  /**
   * Autoriza un UQO entrante y le inyecta el contexto de identidad efectivo.
   * @param {Object} uqo - El UQO de entrada.
   * @param {Object} contract - El contrato de protocolo resuelto.
   * @returns {Object|null} Contexto de identidad o null si falla.
   */
  function authorize(uqo, contract) {
    const activeEmail = Session.getActiveUser().getEmail() || Session.getEffectiveUser().getEmail();
    let coreOwnerEmail = readCoreOwnerEmail(); 
    
    // AXIOMA v7.1: ANCLAJE AUTOMÁTICO DE SOBERANÍA
    // Si el sistema es huérfano (Estado 0), el primer ejecutor humano se convierte en dueño.
    if (!coreOwnerEmail && activeEmail) {
      console.log(`[auth] ANCLAJE AUTOMÁTICO: Corona de Soberanía otorgada a ${activeEmail}`);
      PropertiesService.getScriptProperties().setProperty('SYS_CORE_OWNER_UID', activeEmail);
      coreOwnerEmail = activeEmail;
    }

    // 1. RECONOCIMIENTO DE SANGRE (Soberanía Directa)
    const isOwner = activeEmail === coreOwnerEmail;
    
    // 2. VALIDACIÓN DE LLAVERO (Satelital / Sesión)
    // AXIOMA DE SINCERIDAD: El token puede viajar en 'satellite_token', 'password' o 'token'.
    // Esto permite la paridad con el TransportLayer del satélite sin duplicar campos.
    const activeToken = uqo.satellite_token || uqo.password || uqo.token;
    let satelliteContext = null;
    
    if (activeToken) {
      satelliteContext = _keychain_validate(activeToken); 
      
      // AXIOMA DE CONSCIENCIA: Si el token está vinculado a un Átomo (clase IDENTITY), 
      // inyectamos el sujeto directamente en el UQO para la lógica de negocio.
      if (satelliteContext && satelliteContext.atom_id) {
        uqo.subject_id = satelliteContext.atom_id;
        uqo.is_user_session = true;
        logInfo(`[auth] Sujeto detectado: ${uqo.subject_id} | Resonando como Usuario.`);
      }
    }

    // 3. VALIDACIÓN DE TICKETS (Público / Compartido)
    let validTicket = null;
    if (uqo.share_ticket) {
      const contextId = uqo.context_id || (uqo.data && uqo.data.context_id);
      validTicket = _share_validateTicket(uqo.share_ticket, contextId); 
    }

    // --- CONSOLIDACIÓN DE AUTORIDAD ---
    let result = null;
    
    if (isOwner) {
      result = { identity_type: 'SOVEREIGN', label: "Sovereign", class: "MASTER", owner_id: coreOwnerEmail, is_master: true };
    } else if (satelliteContext) {
      // --- RESOLUCIÓN SATELLITAL AXIOMÁTICA (v13.2) ---
      const resolution = IdentityProvider.getSatelliteResolution(satelliteContext.atom_id);
      
      result = { 
        identity_type: 'SATELLITE', 
        label: satelliteContext.name || "Satellite Agent", 
        class: resolution?.class || satelliteContext.class, 
        owner_id: coreOwnerEmail, 
        is_master: (resolution?.class === 'MASTER' || satelliteContext.class === 'MASTER'),
        scopes: resolution?.scopes || satelliteContext.scopes || [],
        atom_id: satelliteContext.atom_id 
      };
    } else if (validTicket) {
      result = { identity_type: 'GUEST', label: "Guest", class: 'GUEST', owner_id: validTicket.core_id, is_master: false, is_public: true };
    } else {
      result = { identity_type: 'UNIDENTIFIED', owner_id: 'anonymous@indra-os.com' };
    }

    // AXIOMA ADR-052: El actor debe estar en la lista blanca del contrato
    if (!ProtocolRegistry.isActorAuthorized(contract, result.identity_type)) {
      console.warn(`[auth] Actor '${result.identity_type}' NO AUTORIZADO para protocolo '${uqo.protocol}'.`);
      return null;
    }

    return result;
  }

  return {
    authorize: authorize,
    
    /**
     * SYSTEM_IDENTITY_SYNC: El gran intercambiador de identidades.
     * Recibe una validación externa (Google OAuth) y devuelve un token de sesión Indra.
     */
    syncIdentity: function(uqo) {
      const data = uqo.data || {};
      const idToken = data.id_token;
      
      if (!idToken) throw createError('INVALID_INPUT', 'Se requiere id_token para la sincronización.');

      // --- AXIOMA DE SINCERIDAD EXTERNA ---
      // En una implementación real, aquí validaríamos el token contra los servidores de Google.
      // Por ahora, simulamos la extracción del email para el flujo de desarrollo.
      // TODO: Implementar validación JWT real.
      let email;
      try {
        // Simulación: asumimos que el token es el email en este sandbox (Solo para pruebas iniciales)
        // En producción, esto debe ser: const email = GoogleTokenVerifier.verify(idToken);
        email = idToken.includes('@') ? idToken : "user@example.com"; 
      } catch(e) {
        throw createError('AUTH_FAILED', 'Token externo inválido o expirado.');
      }

      logInfo(`[auth:sync] Intentando emparejar sujeto: ${email}`);

      // 1. Buscar el átomo IDENTITY vía Ledger (Con Búsqueda Profunda Integrada v18.0)
      const userAtom = ledger_find_atom_deep('IDENTITY', { email: email }, uqo);

      if (!userAtom) {
        logWarn(`[auth:sync] Sujeto ${email} no encontrado en la malla. Abortando.`);
        return { 
          metadata: { status: 'NOT_AUTHORIZED', error: 'El usuario no está registrado en este Workspace.' }, 
          items: [] 
        };
      }

      // 2. Emitir ticket de sesión de larga duración con Hidratación de Rango (v18.0)
      const userRole = userAtom.payload?.role || 'GUEST';
      const sessionToken = keychain_issue_session(userAtom.id, {
        name: `Sesión de ${userAtom.handle?.label || email}`,
        scopes: ['USER_ACCESS', userRole]
      });

      logSuccess(`[auth:sync] ¡Soberanía Delegada! Sesión emitida para ${email} con rango ${userRole}`);

      const userName = userAtom.payload?.name || userAtom.handle?.label || email;

      return {
        items: [{
          token: sessionToken,
          profile: {
            id: userAtom.id,
            name: userName,
            email: email,
            role: userRole
          }
        }],
        metadata: { status: 'OK' }
      };
    },

    /**
     * SYSTEM_SESSION_REVOKE: Protocolo de destrucción de sesión.
     */
    revokeSession: function(uqo) {
      const token = uqo.satellite_token || uqo.password || uqo.token;
      const success = keychain_revoke_session(token);
      
      return {
        items: [],
        metadata: { 
          status: success ? 'OK' : 'NOT_FOUND',
          message: success ? 'Sesión revocada físicamente.' : 'No se encontró una sesión activa para revocar.'
        }
      };
    }
  };

})();

3_services.installation_service.gs:
/**
 * =============================================================================
 * ARTEFACTO: 3_services/installation_service.gs
 * CAPA: 3 — Services (Gestión de Nacimiento)
 * RESPONSABILIDAD: Orquestación del ciclo de vida de instalación.
 * AXIOMA: Soberanía de Identidad en el primer aliento.
 * =============================================================================
 */

const InstallationService = (function() {

  /**
   * Punto de entrada para protocolos de bajo nivel de consciencia (0 y 1).
   */
  function handle(uqo) {
    const protocol = uqo.protocol;

    // AXIOMA: Las funciones internas del InstallationService ahora coinciden con el protocolo.
    // Intentamos resolución dinámica local o global.
    const handler = _resolveInstallationHandler_(protocol);
    if (handler) {
      return handler(uqo);
    }

    throw new Error(`[installation_service] Protocolo '${protocol}' no soportado en esta capa.`);
  }

  /**
   * Resuelve el handler para protocolos de instalación.
   * @private
   */
  function _resolveInstallationHandler_(protocol) {
    const scope = globalThis || this;
    
    // 1. Buscar en scope global (Auto-Discovery)
    if (typeof scope[protocol] === 'function') return scope[protocol];
    
    // 2. Buscar alias internos (Mapeo de legado)
    const aliases = {
      'SYSTEM_MANIFEST':          () => SYSTEM_MANIFEST(),
      'SYSTEM_INSTALL_HANDSHAKE': (p) => SYSTEM_INSTALL_HANDSHAKE(p),
      'SYSTEM_CONFIG_WRITE':      (p) => SYSTEM_CONFIG_WRITE(p)
    };
    
    return aliases[protocol] || null;
  }

  /**
   * Handshake de Ignición: Anclaje de identidad del dueño.
   * @private
   */
  function SYSTEM_INSTALL_HANDSHAKE(uqo) {
    const currentState = SystemStateManager.getState();
    const activeEmail = Session.getActiveUser().getEmail() || Session.getEffectiveUser().getEmail();

    // LEY DE SOBERANÍA: Si el Core es huerfano, el primer contacto humano es el dueño.
    if (currentState === SYSTEM_STATE.UNINITIALIZED && activeEmail) {
      PropertiesService.getScriptProperties().setProperty('SYS_CORE_OWNER_UID', activeEmail);
      console.log(`[ignition] SOBERANÍA ANCLADA: ${activeEmail}. Indra tiene dueño.`);
    }

    return {
      metadata: {
        status: 'OK',
        message: 'INDRA_IDENTITY_LOCKED',
        system_state: SystemStateManager.getLabel(SystemStateManager.getState()),
        identity_anchor: activeEmail
      }
    };
  }

  /**
   * Ignición de Soberanía: Ejecución de las tareas de activación.
   * @private
   */
  function SYSTEM_CONFIG_WRITE_IGNITION(uqo) {
    console.log('[ignition] Iniciando ignición de soberanía...');

    try {
      // 1. Configurar credenciales (Diferenciando casos)
      if (uqo.data && uqo.data.satellite_key) {
        bootstrapWithSatelliteKey(uqo.data.satellite_key, uqo.data.email);
      } else if (uqo.password) {
        bootstrapPassword(uqo.password);
      } else {
        throw new Error('No se detectaron credenciales válidas (password/satellite_key).');
      }

      // 2. Cristalizar el núcleo (Renaissance) si no existe
      if (!readMasterLedgerId()) {
        SystemOrchestrator.triggerRenaissance();
      }

      return {
        metadata: {
          status: 'ACTIVE',
          message: 'CORE_IGNITED',
          detail: 'Indra ha despertado plenamente.'
        }
      };
    } catch (e) {
      console.error('[ignition] FALLO CRÍTICO:', e.message);
      return {
        metadata: {
          status: 'ERROR',
          error: `Fallo en el protocolo de ignición: ${e.message}`
        }
      };
    }
  }

  return { 
    handle,
    SYSTEM_INSTALL_HANDSHAKE 
  };

})();

3_services.keychain_service.gs:
/**
 * =============================================================================
 * ARTEFACTO: 3_services/keychain_service.gs
 * CAPA: 3 — Service Layer (Servicios de Orquestación)
 * RESPONSABILIDAD: Gestión del Ledger de Identidades (Llavero) y Tokens de Satélite.
 * ADR-041: Implementación del Motor de Soberanía vía Tokens Maestros (OMEGA).
 * =============================================================================
 */

const KEYCHAIN_STORAGE_KEY_ = 'INDRA_KEYCHAIN_LEDGER';
const DEFAULT_SATELLITE_TOKEN_ = 'indra_satellite_omega';

/**
 * Valida si un token existe y está activo.
 * Retorna el contexto del satélite si es válido, o null si no.
 * Es invocado por el api_gateway en cada petición entrante.
 */
function _keychain_validate(token) {
    if (!token) return null;
    const ledger = _keychain_getLedger_();
    const entry = ledger[token];
    
    if (entry && entry.status === 'ACTIVE') {
        // --- AXIOMA DE CADUCIDAD (v17.8) ---
        // Si el token tiene fecha de expiración, validamos que siga vigente.
        if (entry.expires_at && new Date(entry.expires_at) < new Date()) {
            logWarn(`[keychain] Token expirado detectado: ${token}. Invalidando identidad.`);
            entry.status = 'EXPIRED';
            _keychain_saveLedger_(ledger);
            return null;
        }
        return entry; // Retornamos el perfil completo (clase MASTER, scopes, etc.)
    }
    
    return null;
}

/**
 * SYSTEM_KEYCHAIN_GENERATE: Protocolo para emitir nuevas llaves (Soberanía Fractal).
 */
function SYSTEM_KEYCHAIN_GENERATE(uqo) {
    const data = uqo.data || {};
    const name = data.name || "Nuevo Satélite";
    
    // 1. Validar Identidad del Emisor (Padre)
    const parentToken = uqo.satellite_token || null;
    const parentContext = parentToken ? _keychain_validate(parentToken) : null;
    
    // Si el emisor no es MASTER y no tiene permiso de delegar, abortamos
    if (parentContext && parentContext.can_delegate === false) {
        throw createError('SECURITY_VIOLATION', 'Este token no tiene autoridad para delegar soberanía.');
    }

    // 2. Axioma de Herencia: Limitar Scopes al alcance del padre
    let finalScopes = data.scope_id ? [data.scope_id] : ["ALL"];
    let isMaster = !data.scope_id && (!parentContext || parentContext.class === 'MASTER');

    if (parentContext && parentContext.class !== 'MASTER') {
        // Un hijo solo puede tener scopes que el padre ya poseía
        if (data.scope_id && !parentContext.scopes.includes(data.scope_id)) {
            throw createError('SCOPE_VIOLATION', 'No puedes delegar acceso a un Workspace que tú no controlas.');
        }
        // Si el usuario no especificó scope, hereda los del padre
        if (!data.scope_id) finalScopes = parentContext.scopes;
        isMaster = false; // Un hijo de un SCOPED nunca puede ser MASTER
    }

    const newToken = 'indra_' + _system_slugify_(name) + '_' + Math.random().toString(36).substring(2, 11);
    const ledger = _keychain_getLedger_();
    
    ledger[newToken] = {
        name: name,
        status: "ACTIVE",
        class: isMaster ? "MASTER" : "SCOPED",
        parent_id: parentToken, // Vínculo de Sangre
        can_delegate: data.can_delegate !== undefined ? data.can_delegate : true,
        created_at: new Date().toISOString(),
        scopes: finalScopes,
        scope_label: data.scope_label || (isMaster ? "Acceso Universal" : "Acceso Heredado")
    };
    
    _keychain_saveLedger_(ledger);
    logInfo(`[keychain] Nueva llave jerárquica generada: ${name} (Hijo de ${parentToken || 'RAIZ'})`);
    
    return { 
        items: [{ token: newToken, label: name }], 
        metadata: { status: 'OK', message: 'Llave jerárquica generada con éxito.' } 
    };
}

/**
 * SYSTEM_KEYCHAIN_REVOKE: Protocolo para invalidar una llave y TODA su descendencia.
 */
/**
 * SYSTEM_KEYCHAIN_REVOKE: Comando de Nivel 1 (Protocol Router)
 * Recibe la intención y valida el permiso de ejecución.
 */
function SYSTEM_KEYCHAIN_REVOKE(uqo) {
  const token = uqo.context_id || uqo.data?.token;
  if (!token) throw createError('INVALID_INPUT', 'Se requiere el token para revocar.');
  
  logWarn(`[keychain] ☢️ COMANDO DE PURGADO RECIBIDO PARA: ${token}`);
  
  // Iniciamos la transacción 2PC (Two-Phase Commit)
  const masterLedger = ledger_keychain_read_all();
  _keychain_execute_purge_(token, masterLedger);
  
  return { metadata: { status: 'OK', message: 'Identidad y descendencia purgadas bajo protocolo 2PC.' } };
}

/**
 * PROTOCOLO DE DOS FASES (2PC) - Ejecutor Interno
 * 1. Fase Física: Purgado de recursos (Drive).
 * 2. Fase Lógica: Purgado de Ledger.
 */
function _keychain_execute_purge_(targetId, ledger) {
  const entry = ledger[targetId];
  if (!entry) return;

  // 1. RECURSIÓN: Purgar descendencia primero (Cascada)
  Object.keys(ledger).forEach(key => {
    if (ledger[key].parent_id === targetId) {
      _keychain_execute_purge_(key, ledger);
    }
  });

  // 2. FASE FÍSICA: Purgado Territorial
  const territorialScopes = (entry.scopes || []).filter(s => 
    ['DEPLOY_TARGET', 'WORKSPACE_ROOT', 'DATA_VAULT'].includes(s.type)
  );
  
  territorialScopes.forEach(scope => {
    if (scope.value) {
      try {
        logInfo(`[keychain] Liberando espacio físico: ${scope.type} -> ${scope.value}`);
        DriveApp.getFolderById(scope.value).setTrashed(true);
      } catch (e) {
        logWarn(`[keychain] Fallo en purga física (No-bloqueante): ${e.message}`);
      }
    }
  });

  // 3. FASE LÓGICA: Borrado en Ledger
  ledger_keychain_delete(targetId);
}

/**
 * SYSTEM_KEYCHAIN_AUDIT: Inspección de todas las llaves activas en el sistema.
 */
function SYSTEM_KEYCHAIN_AUDIT() {
    const ledger = _keychain_getLedger_();
    // AXIOMA v7.7: La auditoría solo reconoce la vida (ACTIVE). 
    // Los muertos no votan ni se listan.
    const items = Object.keys(ledger)
        .filter(token => ledger[token].status === 'ACTIVE')
        .map(token => ({
            id: token,
            ...ledger[token]
        }));
    return { items, metadata: { status: 'OK', total: items.length } };
}

/**
 * SYSTEM_KEYCHAIN_SCHEMA: Retorna el contrato de datos del Llavero.
 * AXIOMA: La UI no inventa, el Core dicta.
 */
function SYSTEM_KEYCHAIN_SCHEMA() {
    return {
        items: [{
            fields: [
                { id: 'name', label: 'NOMBRE_DE_IDENTIDAD', placeholder: 'Ej: Agente Operativo Alpha', required: true },
                { id: 'class', label: 'CLASE_DE_IDENTIDAD', options: ['MASTER', 'SCOPED'], default: 'SCOPED' },
                { id: 'scopes', label: 'ALCANCE_DE_ACCESO', placeholder: 'ALL o WorkspaceID' }
            ],
            metadata: {
                ledger_version: 'v7.9',
                sincerity_standard: 'ADR-041'
            }
        }],
        metadata: { status: 'OK', total: 1 }
    };
}

/**
 * Procedimiento de Exorcismo: Limpia las ScriptProperties que causan interferencia.
 */
function system_purge_legacy_karma() {
    const keysToPurge = [
        "SYS_CORE_OWNER_UID",
        "SYS_MOUNT_DRIVE_ROOT_ID",
        "SYS_MOUNT_ROOT_ID",
        "SYS_IS_BOOTSTRAPPED",
        "SYS_ROOT_FOLDER_ID"
    ];
    const props = PropertiesService.getScriptProperties();
    keysToPurge.forEach(k => {
        props.deleteProperty(k);
        logInfo(`[exorcism] Karma purgado: ${k}`);
    });
    return { status: 'CLEAN' };
}

// ─── MOTOR INTERNO (PERSISTENCIA) ───────────────────────────────────────────

function _keychain_getLedger_() {
    // 1. Intentar leer desde el Ledger (Nuevo Estándar)
    const ledger = ledger_keychain_read_all();
    
    // 2. Si el Ledger tiene datos, es la Verdad Central
    if (Object.keys(ledger).length > 0) return ledger;

    // ─── PROCESO DE MIGRACIÓN LEGACY (v4.40 Renaissance) ───
    const rawLegacy = PropertiesService.getScriptProperties().getProperty(KEYCHAIN_STORAGE_KEY_);
    if (rawLegacy) {
        logWarn("[keychain] Detectado Llavero Legacy. Iniciando migración al Master Ledger...");
        try {
            const legacyData = JSON.parse(rawLegacy);
            Object.keys(legacyData).forEach(token => {
                ledger_keychain_sync(token, legacyData[token]);
            });
            // Una vez migrado, purgamos el legacy para liberar los 9KB
            PropertiesService.getScriptProperties().deleteProperty(KEYCHAIN_STORAGE_KEY_);
            logSuccess("[keychain] Migración completada. Espacio de PropertiesService liberado.");
            return legacyData;
        } catch (e) {
            logError("[keychain] Fallo en migración legacy.", e);
        }
    }

    // 3. Si no hay nada, bootstrap inicial
    return _keychain_bootstrap_();
}

function _keychain_saveLedger_(ledger) {
    // Ya no guardamos todo el objeto en una sola propiedad (Adiós límite de 9KB)
    // Sincronizamos entrada por entrada (Peristaltismo)
    Object.keys(ledger).forEach(token => {
        ledger_keychain_sync(token, ledger[token]);
    });
}

/**
 * Protocolo de Bootstrap: Genera la llave indra_satellite_omega si el llavero está vacío.
 */
function _keychain_bootstrap_() {
    const initial = {};
    initial[DEFAULT_SATELLITE_TOKEN_] = {
        name: "Sistema Monolítico (Bootstrap)",
        status: "ACTIVE",
        class: "MASTER", 
        created_at: new Date().toISOString(),
        scopes: ["ALL"]
    };
    _keychain_saveLedger_(initial);
    logWarn("[keychain] Bootstrap de Llavero ejecutado con éxito.");
    return initial;
}

/**
 * SYSTEM_SATELLITE_INITIALIZE: Cristalización de un nuevo agente (v13.0)
 */
function SYSTEM_SATELLITE_INITIALIZE(uqo) {
    const data = uqo.data || {};
    const satelliteName = data.name || "Nuevo Satélite";
    const discoverySecret = data.discovery_secret;
    
    // 1. Validar el Secreto de Descubrimiento (Mecanismo de Confianza)
    // Usamos el token por defecto como secreto inicial si no se configura otro
    const masterSecret = PropertiesService.getScriptProperties().getProperty('SYS_DISCOVERY_SECRET') || DEFAULT_SATELLITE_TOKEN_;
    if (discoverySecret !== masterSecret) {
        throw createError('SECURITY_VIOLATION', 'Secreto de descubrimiento no válido.');
    }

    // 2. GÉNESIS ATÓMICA: Crear el átomo SATELLITE
    const genesisRes = infra_protocol_create('SATELLITE', satelliteName, {
        provider: 'system',
        data: {
            handle: { ns: `com.indra.agent.${_system_slugify_(satelliteName)}` },
            payload: {
                class: data.is_master ? 'MASTER' : 'SCOPED',
                scopes: data.scopes || ['WORKSPACE_READ'],
                device_info: data.device_info || {}
            }
        }
    });

    if (genesisRes.metadata.status !== 'OK') throw new Error(`Fallo en génesis de satélite: ${genesisRes.metadata.error}`);
    const satAtom = genesisRes.items[0];

    // 3. VINCULACIÓN EN LLAVERO: Generar token vinculado al átomo
    const newToken = 'sat_' + Math.random().toString(36).substring(2, 15) + '_' + Date.now().toString(36);
    const ledger = _keychain_getLedger_();
    
    ledger[newToken] = {
        name: satelliteName,
        status: "ACTIVE",
        class: satAtom.payload.class,
        atom_id: satAtom.id, // Vínculo Atómico Sagrado
        created_at: new Date().toISOString()
    };
    
    _keychain_saveLedger_(ledger);
    logSuccess(`[keychain] Satélite cristalizado y vinculado: ${satelliteName} -> ${satAtom.id}`);

    return { 
        items: [{ 
            token: newToken, 
            atom_id: satAtom.id,
            label: satelliteName,
            config: { core_version: CORE_VERSION } 
        }], 
        metadata: { status: 'OK', message: 'Cristalización completada.' } 
    };
}

/**
 * Emite un token de sesión vinculado a un Átomo de Identidad (Sujeto).
 * @param {string} atomId - El ID del átomo IDENTITY.
 * @param {Object} options - { name, scopes, duration_days }
 */
function keychain_issue_session(atomId, options = {}) {
    const durationDays = options.duration_days || 30; // Axioma de Larga Duración (UX Industrial)
    const expiresAt = new Date();
    expiresAt.setDate(expiresAt.getDate() + durationDays);
    
    // Generación de Hash de Sesión
    const token = 'sess_' + Math.random().toString(36).substring(2, 15) + '_' + Date.now().toString(36);
    const ledger = _keychain_getLedger_();
    
    ledger[token] = {
        name: options.name || "Sesión de Usuario",
        status: "ACTIVE",
        class: "SESSION",
        atom_id: atomId,
        created_at: new Date().toISOString(),
        expires_at: expiresAt.toISOString(),
        scopes: options.scopes || ["USER_ACCESS"]
    };
    
    _keychain_saveLedger_(ledger);
    logSuccess(`[keychain] Sesión L2 emitida para ${atomId}. Caducidad: ${durationDays} días.`);
    
    return token;
}

/**
 * Invalida quirúrgicamente un token de sesión.
 * @param {string} token - El token a revocar.
 */
function keychain_revoke_session(token) {
    if (!token) return false;
    const ledger = _keychain_getLedger_();
    if (ledger[token]) {
        ledger[token].status = 'REVOKED';
        ledger[token].revoked_at = new Date().toISOString();
        _keychain_saveLedger_(ledger);
        logWarn(`[keychain] Sesión L2 revocada físicamente: ${token}`);
        return true;
    }
    return false;
}

3_services.monitoring_service.gs:
// =============================================================================
// ARTEFACTO: 3_services/monitoring_service.gs
// CAPA: 3 — Services (Infraestructura de Soporte)
// RESPONSABILIDAD: El túnel de conciencia hacia el Cliente. Captura todos los eventos
//         del servidor durante una ejecución y los "flushea" en el campo
//         `metadata.logs` del response HTTP para que el cliente los muestre
//         en consola en tiempo real. En Hito 1: solo buffer en memoria.
//
// AXIOMAS:
//   - En Hito 1: NO persiste nada. Cero Sheets, cero Drive, cero email.
//   - El buffer de logs es LOCAL a cada instancia de llamada GAS.
//   - `flushLogs()` DEBE ser llamado exactamente una vez al final de cada petición.
//   - Depende de `error_handler.gs` para estructurar eventos de nivel ERROR.
//
// RESTRICCIONES:
//   - NO puede escribir en Drive ni en Sheets en esta fase.
//   - NO puede hacer llamadas de red externas.
//   - `flushLogs()` vacía el buffer. Llamarlo dos veces en la misma ejecución
//     retorna un array vacío en la segunda llamada. Es por diseño.
// =============================================================================

/**
 * Niveles de log por severidad, en orden ascendente.
 * @const {Object.<string, number>}
 */
const LOG_LEVELS = Object.freeze({
  DEBUG:   0,
  INFO:    1,
  WARN:    2,
  ERROR:   3,
  SILENT:  99, // Deshabilita todos los logs
});

/**
 * Nivel mínimo de log que se añade al buffer.
 * Cambiar a 'INFO' para producción, 'DEBUG' para desarrollo.
 * @const {string}
 */
const ACTIVE_LOG_LEVEL = 'DEBUG';

// Buffer en memoria de la ejecución actual.
// GAS es stateless: este array vive solo durante una ejecución de doPost.
let _logBuffer_ = [];

/**
 * Función interna que añade una entrada al buffer si supera el nivel mínimo.
 * @param {string} level   - Nivel del log ('DEBUG', 'INFO', 'WARN', 'ERROR').
 * @param {string} message - Mensaje del evento.
 * @param {*} [context]    - Datos de contexto adicionales (opcional).
 * @private
 */
function _log_(level, message, context) {
  if (LOG_LEVELS[level] < LOG_LEVELS[ACTIVE_LOG_LEVEL]) return;

  const entry = {
    level:     level,
    message:   String(message),
    timestamp: new Date().toISOString(),
  };

  // Serialización segura del contexto (evita referencias circulares)
  if (context !== undefined && context !== null) {
    try {
      entry.context = JSON.parse(JSON.stringify(context));
    } catch (e) {
      entry.context = '[monitoring_service: contexto no serializable]';
    }
  }

  _logBuffer_.push(entry);

  // También imprime en los logs nativos de GAS (visible en el editor GAS)
  console.log(`[${level}] ${message}`);
}

// ─── API PÚBLICA ─────────────────────────────────────────────────────────────

/**
 * Registra un evento de nivel DEBUG (solo visible en modo desarrollo).
 * @param {string} message - Mensaje del evento.
 * @param {*} [context]    - Datos de contexto adicionales.
 */
function logDebug(message, context) {
  _log_('DEBUG', message, context);
}

/**
 * Registra un evento informativo normal del sistema.
 * @param {string} message - Mensaje del evento.
 * @param {*} [context]    - Datos de contexto adicionales.
 */
function logInfo(message, context) {
  _log_('INFO', message, context);
}

/**
 * Registra una advertencia: el sistema continúa pero algo es anómalo.
 * @param {string} message - Mensaje de la advertencia.
 * @param {*} [context]    - Datos de contexto adicionales.
 */
function logWarn(message, context) {
  _log_('WARN', message, context);
}

/**
 * Registra un error: el sistema no pudo completar la operación.
 * @param {string} message    - Mensaje del error.
 * @param {Object} [errorObj] - Objeto de error creado por `error_handler.gs`.
 */
function logError(message, errorObj) {
  _log_('ERROR', message, errorObj || null);
}

/**
 * Retorna el buffer de logs acumulado y lo vacía (flush).
 * Debe ser llamado exactamente UNA VEZ al final de cada petición HTTP,
 * inmediatamente antes de construir el response JSON final.
 *
 * @returns {Array<Object>} Array de entradas de log del ciclo de ejecución actual.
 */
function flushLogs() {
  const snapshot = _logBuffer_.slice(); // Copia defensiva
  _logBuffer_ = [];                      // Vaciar buffer
  return snapshot;
}

/**
 * Retorna el número de entradas en el buffer actual sin vaciarlo.
 * Útil para tests y diagnóstico.
 * @returns {number}
 */
function getBufferSize() {
  return _logBuffer_.length;
}

3_services.nexus_service.gs:
/**
 * =============================================================================
 * ARTEFACTO: 3_services/nexus_service.gs
 * RESPONSABILIDAD: Orquestación de confianza entre nodos Indra (P2P).
 * AXIOMA: Soberanía Multinodal. Handshake de Confianza.
 * =============================================================================
 */

const NexusService = (function() {

  /**
   * INICIA UN HANDSHAKE (Axioma de Reconocimiento entre Pares).
   * Genera un puente de confianza asimétrico. El nodo iniciador queda en estado PENDING_OUTGOING.
   * 
   * @axiom SOBERANÍA: Un nodo solo se conecta si el dueño firma la intención.
   * @param {string} remoteCoreUrl - Endpoint SOAP/REST del Indra remoto.
   * @param {string} alias - Alias local para mapeo espacial (Mounting).
   */
  function initiateHandshake(remoteCoreUrl, alias) {
    logInfo(`[nexus] Iniciando Handshake con nodo remoto: ${alias} (${remoteCoreUrl})`);
    
    // 1. Crear identidad local para el apretón de manos
    const handoverId = Utilities.getUuid();
    
    // AXIOMA: Usar el Router para asegurar persistencia en el Mount ROOT
    const response = route({
      provider: 'system',
      protocol: 'ATOM_CREATE',
      data: {
        class: 'BRIDGE',
        handle: { ns: 'indra.system.bridge', alias: alias, label: `Conexión con ${alias}` },
        payload: {
          remote_url: remoteCoreUrl,
          status: 'PENDING_OUTGOING',
          handover_id: handoverId,
          created_at: new Date().toISOString()
        }
      }
    });

    return {
      metadata: { status: 'OK', message: 'Handshake iniciado. Esperando respuesta del nodo remoto.' },
      items: response.items || []
    };
  }

  /**
   * ACEPTA UN HANDSHAKE (Axioma de Consonancia).
   * Eleva un puente pendiente a estado ACTIVE. Crea una relación de reciprocidad.
   * 
   * @param {Object} uqo - El UQO con el handover_id original.
   */
  function acceptHandshake(uqo) {
    const remoteData = uqo.data;
    if (!remoteData.remote_url || !remoteData.handover_id) {
       throw new Error('nexus_service: Datos de handshake incompletos.');
    }
 
    const response = route({
      provider: 'system',
      protocol: 'ATOM_CREATE',
      data: {
        class: 'BRIDGE',
        handle: { ns: 'indra.system.bridge', alias: remoteData.alias || 'remote_node', label: `Nodo Remoto Autorizado` },
        payload: {
          remote_url: remoteData.remote_url,
          status: 'ACTIVE',
          handover_id: remoteData.handover_id,
          connected_at: new Date().toISOString()
        }
      }
    });
    
    return { metadata: { status: 'OK', message: 'Handshake aceptado. Nodo vinculado.', bridge_id: response.items?.[0]?.id } };
  }

  /**
   * Ejecuta un UQO en un nodo remoto si existe un puente activo.
   * @param {string} bridgeAlias - Alias del nodo remoto.
   * @param {Object} uqo - El UQO a ejecutar remotamente.
   */
  function remoteExecute(bridgeAlias, uqo) {
    // CORRECCIÓN: Usar list_by_class para encontrar el puente por alias
    const activeBridges = ledger_list_by_class('BRIDGE');
    const bridge = activeBridges.find(b => b.handle?.alias === bridgeAlias);
    
    if (!bridge) throw new Error(`nexus_service: No existe un puente configurado para "${bridgeAlias}".`);
    if (bridge.payload?.status !== 'ACTIVE') throw new Error(`nexus_service: El puente "${bridgeAlias}" no está activo.`);

    // 2. Firmar y enviar al remoto (Implementación futura con Fetch)
    logInfo(`[nexus] Redirigiendo UQO a nodo remoto: ${bridge.payload.remote_url}`);
    
    // Aquí se usaría urlFetchApp para enviar el UQO con el token del bridge
    return { metadata: { status: 'PENDING_REMOTE', detail: 'Redirección multinodal en proceso.' } };
  }

  return {
    initiateHandshake: initiateHandshake,
    acceptHandshake: acceptHandshake,
    remoteExecute: remoteExecute
  };

})();

3_services.peristaltic_service.gs:
/**
 * =============================================================================
 * ARTEFACTO: 3_services/peristaltic_service.gs
 * RESPONSABILIDAD: Implementación del Protocolo de Ingesta Peristáltica (ADR-036).
 * Mantiene el estado de subidas fragmentadas y ensambla binarios en Drive.
 * =============================================================================
 */

const PERISTALTIC_TEMP_FOLDER_ = '_indra_ingest_temp';

/**
 * INIT: Registra el inicio de una subida masiva.
 * Crea la sesión en el CacheService.
 */
function peristaltic_service_init(payload) {
  const { uploader, contact, files_manifest, session_id } = payload.data;
  const sessionId = session_id || `sess_${Date.now()}`;

  // Guardamos metadata de la sesión (Válida por 24h)
  const sessionMeta = {
    uploader,
    contact,
    start_at: new Date().toISOString(),
    files: files_manifest.map(f => ({ ...f, status: 'PENDING' }))
  };

  CacheService.getScriptCache().put(`ingest_sess_${sessionId}`, JSON.stringify(sessionMeta), 21600); // 6h

  logInfo(`[peristaltic] Sesión iniciada: ${sessionId}`, { uploader });
  return { items: [{ id: sessionId }], metadata: { status: 'OK' } };
}

/**
 * CHUNK: Recibe un fragmento b64 y lo anexa a un archivo temporal.
 */
function peristaltic_service_chunk(payload) {
  const { session_id, file_name, chunk_index, total_chunks, data_b64, md5 } = payload.data;

  // AXIOMA: Para evitar los límites de CacheService (100KB), usamos archivos temporales en Drive.
  const tempFolder = _peristaltic_getTempFolder();
  const tempFileName = `chunk_${session_id}_${file_name}_${String(chunk_index).padStart(4, '0')}`;

  // Guardamos el chunk como un archivo atómico e independiente
  const chunkBytes = Utilities.base64Decode(data_b64);
  const chunkBlob = Utilities.newBlob(chunkBytes, payload.data.mime_type || 'application/octet-stream');
  tempFolder.createFile(chunkBlob).setName(tempFileName);

  logDebug(`[peristaltic] Fragmento ${chunk_index + 1}/${total_chunks} guardado físicamente: ${tempFileName}`);

  return { metadata: { status: 'OK', chunk_received: chunk_index } };
}

/**
 * FINALIZE: Mueve el archivo temporal a su ubicación final y limpia.
 */
function peristaltic_service_finalize(payload) {
  const { session_id, file_name, target_folder_id, mime_type } = payload.data;
  const tempFolder = _peristaltic_getTempFolder();

  // Búsqueda de todos los fragmentos de este archivo en la sesión
  const chunkPrefix = `chunk_${session_id}_${file_name}_`;
  const files = tempFolder.getFiles();
  const chunks = [];

  while (files.hasNext()) {
    const f = files.next();
    if (f.getName().startsWith(chunkPrefix)) chunks.push(f);
  }

  if (chunks.length === 0) {
    throw createError('NOT_FOUND', `No se encontraron fragmentos para finalizar: ${file_name}`);
  }

  // AXIOMA DE ORDENACIÓN: Reensamblar en secuencia estricta
  chunks.sort((a, b) => a.getName().localeCompare(b.getName()));

  const combinedBytes = [];
  chunks.forEach(chunkFile => {
    combinedBytes.push(...chunkFile.getBlob().getBytes());
  });

  const targetFolder = target_folder_id === 'root' ? DriveApp.getRootFolder() : DriveApp.getFolderById(target_folder_id);
  const finalFile = targetFolder.createFile(Utilities.newBlob(combinedBytes, mime_type || 'application/octet-stream', file_name));

  // LIMPIEZA QUIRÚRGICA: Borrar fragmentos
  chunks.forEach(chunkFile => chunkFile.setTrashed(true));

  logInfo(`[peristaltic] Ensamblado completado: ${file_name} (${chunks.length} fragmentos)`);
  return { items: [{ id: finalFile.getId(), url: finalFile.getUrl() }], metadata: { status: 'OK' } };
}

/**
 * Obtiene o crea la carpeta de tránsito.
 */
function _peristaltic_getTempFolder() {
  const homeRoot = _system_ensureHomeRoot();
  const folders = homeRoot.getFoldersByName(PERISTALTIC_TEMP_FOLDER_);
  if (folders.hasNext()) return folders.next();
  return homeRoot.createFolder(PERISTALTIC_TEMP_FOLDER_);
}

// ─── GESTIÓN DE SESIONES DE TRANSFERENCIA (INDUSTRIAL) ─────────────────────────

/**
 * Crea un Ticket de Ingesta Persistente.
 * Se guarda como un Átomo de clase SYSTEM_TICKET para auditoría y resiliencia.
 */
function _peristaltic_createPersistentTicket(uqo) {
    const data = uqo.data || {};
    const ticketId = `ticket_${Date.now()}_${Math.random().toString(36).substring(7)}`;

    const ticketAtom = {
        id: ticketId,
        class: 'SYSTEM_TICKET',
        handle: {
            ns: 'com.indra.system.peristalsis',
            alias: ticketId,
            label: `Ingesta: ${data.source_provider || 'unknown'} -> ${data.target_provider || 'unknown'}`
        },
        payload: {
            status: 'INITIALIZING',
            progress: 0,
            cursor: 0,
            total_expected: data.total_expected || 0,
            chunk_size: data.chunk_size || 100,
            source: data.source || {},
            target: data.target || {},
            history: [{ timestamp: new Date().toISOString(), event: 'LOG_GENESIS' }]
        }
    };

    // Persistimos físicamente en el Ledger de Sistema
    const createRes = route({
        provider: 'system',
        protocol: 'ATOM_CREATE',
        data: ticketAtom
    });

    return createRes.items?.[0] || ticketAtom;
}

/**
 * INDUCTION_PULSE: Ejecuta un micro-salto de ingesta.
 * Es el corazón rítmico del sistema industrial.
 */
function _peristaltic_handlePulse(uqo) {
    const ticketId = uqo.data?.ticket_id;
    if (!ticketId) throw createError('INVALID_INPUT', 'Se requiere ticket_id para el pulso.');

    // 1. HIDRATACIÓN DEL ESTADO
    const readRes = route({ provider: 'system', protocol: 'ATOM_READ', context_id: ticketId });
    const ticket = readRes.items?.[0];
    if (!ticket) throw createError('NOT_FOUND', 'Ticket de ingesta no encontrado o expirado.');

    if (ticket.payload.status === 'COMPLETED') return { items: [ticket], metadata: { status: 'OK', msg: 'Ya completado.' } };

    const { cursor, chunk_size, source, target } = ticket.payload;

    try {
        // 2. EXTRACCIÓN (Source)
        const sourceRes = route({
            provider: source.provider,
            protocol: 'TABULAR_STREAM',
            context_id: source.id,
            query: { 
                cursor: ticket.payload.next_source_cursor || null,
                limit: chunk_size 
            }
        });

        const items = sourceRes.items || [];
        if (items.length === 0) {
            ticket.payload.status = 'COMPLETED';
            ticket.payload.progress = 1;
        } else {
            // 3. CRISTALIZACIÓN (Target)
            const syncRes = route({
                provider: 'automation',
                protocol: 'INDUSTRIAL_SYNC',
                data: {
                    target_provider: target.provider,
                    silo_id: target.id,
                    sat_payload: { items },
                    source_provider: source.provider,
                    source_id: source.id
                }
            });

            // 4. ACTUALIZACIÓN DE CURSOR
            ticket.payload.cursor += items.length;
            ticket.payload.next_source_cursor = sourceRes.metadata?.next_cursor;
            ticket.payload.status = sourceRes.metadata?.has_more ? 'IN_PROGRESS' : 'COMPLETED';

            if (ticket.payload.total_expected > 0) {
                ticket.payload.progress = Math.min(0.99, ticket.payload.cursor / ticket.payload.total_expected);
            }
        }

        if (ticket.payload.status === 'COMPLETED') ticket.payload.progress = 1;

        // 5. PERSISTENCIA DEL AVANCE
        route({
            provider: 'system',
            protocol: 'ATOM_PATCH',
            context_id: ticketId,
            data: { payload: ticket.payload }
        });

        return { 
            items: [ticket], 
            metadata: { 
                status: 'OK', 
                progress: ticket.payload.progress,
                pulse_count: items.length 
            } 
        };

    } catch (e) {
        ticket.payload.status = 'ERROR';
        ticket.payload.last_error = e.message;
        route({ provider: 'system', protocol: 'ATOM_PATCH', context_id: ticketId, data: { payload: ticket.payload } });
        throw e;
    }
}

3_services.pulse_service.gs:
/**
 * =============================================================================
 * ARTEFACTO: 3_services/pulse_service.gs
 * RESPONSABILIDAD: Motor lógico de la Red de Pulsos. 
 * DHARMA (ADR-018):
 *   - Auto-Ignición (The Boomerang): El Core se invoca a sí mismo.
 *   - Liberación Inmediata: Respondemos al cliente antes de ejecutar.
 *   - Soberanía Micelar: Validamos identidad del dueño del pulso (ADR-019).
 * CORE_VERSION = "4.50.0-OMNI-SOVEREIGN"; // FASE: Renacimiento Completado.
 * =============================================================================
 */

/**
 * Encola una intención (UQO) para su ejecución asíncrona.
 * @param {Object} uqo - El UQO con la intención original.
 * @param {Object} [options] - scheduling, trigger_source, etc.
 * @returns {string} ID del pulso generado.
 */
function pulse_service_enqueue(uqo, options = {}) {
  const pulseId = Utilities.getUuid();
  const now = new Date().toISOString();

  // AXIOMA DE SOBERANÍA: El pulso hereda la identidad del dueño actual (ADR-019)
  const ownerEmail = readCoreOwnerEmail(); // → system_config.gs

  const pulseData = {
    pulse_id: pulseId,
    timestamp: now,
    scheduled_at: options.scheduled_at || now,
    owner_id: ownerEmail,
    trigger_source: options.trigger_source || 'MANUAL',
    protocol: uqo.protocol,
    provider: uqo.provider,
    status: 'PENDING',
    uqo_payload: uqo,
    trace_id: uqo.trace_id || Utilities.getUuid()
  };

  // Guardar físicamente en el Ledger
  pulse_ledger_append(pulseData); // → pulse_ledger.gs

  // Lanzar ignición asíncrona (Boomerang)
  // No esperamos el resultado para liberar al cliente de inmediato.
  pulse_service_ignite(pulseId);

  return pulseId;
}

/**
 * Disparador de ignición (El Boomerang).
 * Llama al Core vía HTTP con el header de ignición.
 * @param {string} pulseId - El ID del pulso a encender.
 */
function pulse_service_ignite(pulseId) {
  try {
    let selfUrl = null;
    try {
      selfUrl = ScriptApp.getService().getUrl();
    } catch (e) {
      logWarn('[pulse_service] No se pudo obtener URL del script (falta permiso script.webapp.deploy).');
    }

    if (!selfUrl) {
      logWarn('[pulse_service] Boomerang omitido por falta de identidad URL.');
      return;
    }

    const igniteHeader = { 'X-Indra-Ignite': 'true', 'X-Indra-Pulse-ID': pulseId };

    // Ignición asíncrona (fetch sin esperar)
    UrlFetchApp.fetch(selfUrl, {
      method: 'post',
      headers: igniteHeader,
      payload: JSON.stringify({ protocol: 'PULSE_WAKEUP', pulse_id: pulseId }),
      muteHttpExceptions: true
    });

    pulse_ledger_updateStatus(pulseId, 'IGNITED');
    logInfo(`[pulse_service] Ignición enviada para pulso: ${pulseId}`);
  } catch (err) {
    logError('[pulse_service] Fallo en la ignición del Boomerang.', err);
  }
}

/**
 * Procesa el siguiente pulso disponible en la cola.
 * Invocado por el Boomerang (Gateway) o el Maintenance Trigger.
 */
function pulse_service_process_next() {
  const pending = pulse_ledger_getPending(); // → pulse_ledger.gs
  if (!pending || pending.length === 0) {
    logInfo('[pulse_service] Sin pulsos pendientes en la cola.');
    return null;
  }

  const pulse = pending[0];
  const pulseId = pulse.pulse_id;

  logInfo(`[pulse_service] Procesando pulso: ${pulseId} (${pulse.owner_id})`);
  pulse_ledger_updateStatus(pulseId, 'EXECUTING');

  try {
    // AXIOMA DE SINCERIDAD: Ejecutamos a través del router original
    // para que se cumplan todas las validaciones de contrato y burst control.
    const result = route(pulse.uqo_payload); // → protocol_router.gs

    const status = result.metadata?.status === 'ERROR' ? 'FAILED' : 'COMPLETED';
    const summary = result.metadata?.execution || result.metadata || {};

    pulse_ledger_updateStatus(pulseId, status, { result_summary: summary });
    logInfo(`[pulse_service] Pulso ${pulseId} finalizado como: ${status}`);

    return result;
  } catch (err) {
    logError(`[pulse_service] Error crítico al ejecutar pulso ${pulseId}`, err);
    pulse_ledger_updateStatus(pulseId, 'FAILED', { result_summary: { error: err.message } });
    return null;
  }
}

/**
 * Trigger de Mantenimiento (Resurrección de Pulsos).
 * Debe configurarse para ejecutarse cada día (no cada minuto).
 * OPTIMIZACIÓN: Solo ejecuta si hay workflows con triggers activos.
 */
function pulse_service_maintenance_trigger() {
  logInfo('[pulse_service] Ejecutando ronda de mantenimiento de pulsos...');

  // Validación: Si no hay triggers de workflow activos, no purgar innecesariamente
  let hasWorkflowTriggers = false;
  try {
    const triggers = ScriptApp.getProjectTriggers();
    hasWorkflowTriggers = triggers.some(t => t.getHandlerFunction() === 'pulse_service_maintenance_trigger');
  } catch (err) {
    logWarn(`[pulse_service] No se pudo verificar triggers: ${err.message}`);
    // Si no hay permisos, asumimos que no hay triggers configurados para este script
  }

  if (!hasWorkflowTriggers) {
    logInfo('[pulse_service] Sin triggers de workflow activos o sin permisos. Mantenimiento omitido.');
    return;
  }

  // 1. Salud del Ledger: Purgar tareas terminadas/fallidas antiguas (Axioma de Autocuración)
  pulse_ledger_purge(); // → pulse_ledger.gs

  // 2. Ejecutar siguiente pendiente
  pulse_service_process_next();

  // 3. LATIDO DE INTEGRIDAD SOBERANA (v4.50)
  pulse_service_integrity_heartbeat();
}

/**
 * Patrulla de Integridad: Reconcilia Ledger vs Realidad Física.
 */
function pulse_service_integrity_heartbeat() {
  logInfo('[pulse_service] Iniciando Patrulla de Integridad...');
  const ledgerId = MountManager.getMount('ROOT');
  if (!ledgerId) return;

  try {
    const atoms = _ledger_get_bulk_metadata_(['WORKSPACE', 'DATA_SCHEMA', 'BRIDGE']);
    atoms.forEach(atom => {
       try {
         // Verificar existencia física
         const file = DriveApp.getFileById(atom.drive_id);

         // Reconciliación de Naming: Si el usuario renombró en Drive, el Ledger se adapta.
         const physicalName = file.getName();
         if (physicalName !== atom.label) {
           logInfo(`[integrity] Reconciliando etiqueta: ${atom.label} -> ${physicalName}`);
           // Actualizar Ledger (vía system_provider)
         }
       } catch (e) {
         logWarn(`[integrity] Átomo huérfano detectado: ${atom.label} (${atom.drive_id}). Marcando para revisión.`);
         // Aquí podríamos marcar en el Ledger como STATUS: 'ORPHAN'
       }
    });

    // 4. Salubridad de Procesos (Task Monitor)
    // Limpiar procesos 'ACTIVE' que no han pulsado en más de 2 horas.
    logInfo('[pulse_service] Patrulla de Integridad finalizada con éxito.');
  } catch (err) {
    logError('[pulse_service] Fallo en la patrulla de integridad.', err);
  }
}

3_services.resonance_registry.gs:
/**
 * =============================================================================
 * ARTEFACTO: 3_services/resonance_registry.gs
 * RESPONSABILIDAD: Mapa de Capacidades y Rasgos Soberanos.
 * AXIOMA: Las clases son etiquetas; los rasgos son leyes.
 * =============================================================================
 */

// --- CATÁLOGO DE RASGOS (TRAITS) ---
const TRAIT = Object.freeze({
  PHYSICAL_RESONANCE: 'PHYSICAL_RESONANCE', // El átomo tiene presencia en el mundo físico
  IDENTITY_ANCHOR:    'IDENTITY_ANCHOR',    // El nombre físico manda sobre el lógico
  LOGICAL_SYNC:       'LOGICAL_SYNC',       // Propagación en cascada a otros átomos (Pins)
  PERISTALTIC:        'PERISTALTIC'         // Soporta flujos industriales de datos
});

// --- ANATOMÍA FÍSICA (ANCHORS) ---
// Define dónde se manifiesta físicamente cada átomo.
const ANCHOR_TYPE = Object.freeze({
  DNA_FILE:   'DNA_FILE',   // El archivo .json de metadatos (atom.id)
  CONTAINER:  'CONTAINER',  // La carpeta que contiene la materia (payload.cell_folder_id)
  TABULAR:    'TABULAR',    // Un archivo de hoja de cálculo vinculado
  LEDGER_ROW: 'LEDGER_ROW'  // La entrada en el Ledger Maestro
});

/**
 * MAPA MAESTRO DE CAPACIDADES Y ANATOMÍA
 * Define la estructura vital de cada clase de átomo.
 */
const RESONANCE_MAP = Object.freeze({
  'WORKSPACE': {
    traits: [TRAIT.PHYSICAL_RESONANCE, TRAIT.IDENTITY_ANCHOR, TRAIT.LOGICAL_SYNC],
    anchors: [ANCHOR_TYPE.DNA_FILE, ANCHOR_TYPE.CONTAINER, ANCHOR_TYPE.LEDGER_ROW]
  },
  'DATA_SCHEMA': {
    traits: [TRAIT.PHYSICAL_RESONANCE, TRAIT.LOGICAL_SYNC],
    anchors: [ANCHOR_TYPE.DNA_FILE, ANCHOR_TYPE.LEDGER_ROW]
  },
  'DOCUMENT': {
    traits: [TRAIT.PHYSICAL_RESONANCE],
    anchors: [ANCHOR_TYPE.DNA_FILE, ANCHOR_TYPE.LEDGER_ROW]
  },
  'WORKFLOW': {
    traits: [TRAIT.PHYSICAL_RESONANCE, TRAIT.LOGICAL_SYNC],
    anchors: [ANCHOR_TYPE.DNA_FILE, ANCHOR_TYPE.LEDGER_ROW]
  },
  'BRIDGE': {
    traits: [TRAIT.IDENTITY_ANCHOR],
    anchors: [ANCHOR_TYPE.DNA_FILE, ANCHOR_TYPE.LEDGER_ROW]
  },
  'SATELLITE': {
    traits: [TRAIT.IDENTITY_ANCHOR],
    anchors: [ANCHOR_TYPE.DNA_FILE, ANCHOR_TYPE.LEDGER_ROW]
  }
});

/**
 * Resuelve los rasgos de una clase específica.
 */
function resonance_registry_get_traits(atomClass) {
  return RESONANCE_MAP[atomClass]?.traits || [];
}

/**
 * Resuelve los anclajes físicos de una clase específica (Anatomía).
 * @returns {string[]} Lista de tipos de anclaje (DNA_FILE, CONTAINER, etc.)
 */
function resonance_registry_get_anchors(atomClass) {
  return RESONANCE_MAP[atomClass]?.anchors || [];
}

/**
 * Verifica si una clase tiene un rasgo específico.
 */
function resonance_registry_has_trait(atomClass, trait) {
  const traits = resonance_registry_get_traits(atomClass);
  return traits.includes(trait);
}

